-- Poems batch 213
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('0dca782c-d742-48c9-8a51-397b7e57ffec','緣識  其四五','宋太宗','宋','宋诗','song-poetry','','[]','心如明鑑照纖微，大道之中沒是非。',32,'全唐诗/poet.song.2000.json','["心如明鑑照纖微，大道之中沒是非。", "拂拭塵埃高挂閣，天邊日月有光輝。"]'),
('85cb9a05-2dd4-4b9c-8976-96fe43625d06','緣識  其四六','宋太宗','宋','宋诗','song-poetry','','[]','道經念誦信無爲，清靜玄言好自持。',32,'全唐诗/poet.song.2000.json','["道經念誦信無爲，清靜玄言好自持。", "苦行精修心不倦，嚥津往往過齋時。"]'),
('ae19adc4-6cde-4555-8d39-d00e469cb06d','緣識  其四七','宋太宗','宋','宋诗','song-poetry','','[]','承平無事上元節，絲竹歌聲更互發。',80,'全唐诗/poet.song.2000.json','["承平無事上元節，絲竹歌聲更互發。", "自從雨後最晴明，不似往年今歲別。", "死來無意在遨遊，常愧三光明皎潔。", "千門萬戶樂喧喧，就中年少無蹔歇。", "天街紅燄布羣星，晃煬人間闘明月。"]'),
('b8dcdfde-55a0-4241-b75f-f466adcea8be','緣識  其四八','宋太宗','宋','宋诗','song-poetry','','[]','上元時節皆相慕，皇都城裏萬家燈。',64,'全唐诗/poet.song.2000.json','["上元時節皆相慕，皇都城裏萬家燈。", "笙歌有處共誇稱，架肩疊足幾許層。", "輕塵霧斂月明中，車騎雲軿五夜風。", "意氣盡隨年少得，九衢填咽樂聲同。"]'),
('8d2002eb-753e-493c-ad8a-567236527f78','緣識  其四九','宋太宗','宋','宋诗','song-poetry','','[]','木人莫把石牛騎，海變桑田故不知。',32,'全唐诗/poet.song.2000.json','["木人莫把石牛騎，海變桑田故不知。", "耕地種禾終是妄，真空相偶更無疑。"]'),
('0cc47b15-6a21-4651-b240-44c244b9e2df','緣識  其五○','宋太宗','宋','宋诗','song-poetry','','[]','逢春酒一杯，百卉向陽開。',36,'全唐诗/poet.song.2000.json','["逢春酒一杯，百卉向陽開。", "梨花看似梅，光揚迎日彩。", "嫩柳引清風，黄鳥聲吹臺。"]'),
('1458ae04-a52f-45ff-b770-7bdf3c61d64c','緣識  其五一','宋太宗','宋','宋诗','song-poetry','','[]','嶧陽之山，傳名曰桐，六律相沒五音中。',130,'全唐诗/poet.song.2000.json','["嶧陽之山，傳名曰桐，六律相沒五音中。", "七軫弦調皆是意，審詳悞則亦如空。", "清秋寂靜華堂深，聽之令我思沈吟。", "幽蘭裏韻冬夜永，且合大道古人心。", "舜製南風治蒼生，方知堯化廣聰明。", "初彈將了移聲去，悲風秋思翻更互。", "鳥啼別鶴何凄凉，秪聞斷續手揮忙。", "慢引來催急風雨，寒泉妙滴散馨香。"]'),
('9b11a653-cc6d-48a5-81b7-bf637f1e8413','緣識  其五二','宋太宗','宋','宋诗','song-poetry','','[]','識性低凡故不知，宣傳好事却爲非。',32,'全唐诗/poet.song.2000.json','["識性低凡故不知，宣傳好事却爲非。", "可憐此輩居人世，逆惡求真善不依。"]'),
('092673e6-aede-45d9-aee2-61301886b5d7','緣識  其五三','宋太宗','宋','宋诗','song-poetry','','[]','蓬萊別有洞中天，摇曳祥雲五色鮮。',32,'全唐诗/poet.song.2000.json','["蓬萊別有洞中天，摇曳祥雲五色鮮。", "不是凡人常到處，精修要實在心專。"]'),
('dd37c461-96b7-4972-a115-38ad6e7f9192','緣識  其五四','宋太宗','宋','宋诗','song-poetry','','[]','中秋八月祥風遍，慢上東輪雲遊轉。',96,'全唐诗/poet.song.2000.json','["中秋八月祥風遍，慢上東輪雲遊轉。", "清境將開照玉京，一時宮闕爲銀殿。", "夜靜寒光半欹樓，空入簾帷白如練。", "景致融怡露添寒，薄茶佳客隨情翫。", "無問高下盡一般，爽氣周天如雪霰。", "千家萬家仰天維，漏永更深方罷看。"]'),
('8cc2839b-867e-462c-acf8-fd919ac024bc','緣識  其五五','宋太宗','宋','宋诗','song-poetry','','[]','黄芽藥就成金丹，理與參同契一般。',32,'全唐诗/poet.song.2000.json','["黄芽藥就成金丹，理與參同契一般。", "切是先求功行力，紅塵內見識應難。"]'),
('ca104cbf-64ac-499c-992f-ac65ec0c1c4c','緣識  其五六','宋太宗','宋','宋诗','song-poetry','','[]','玄元一氣不相監，清靜如存意馬銜。',32,'全唐诗/poet.song.2000.json','["玄元一氣不相監，清靜如存意馬銜。", "大隠居鄽迷小道，絕巔頂上白雲巖。"]'),
('455fbd6f-f0ae-44e9-9d0b-b0e9865c012e','緣識  其五七','宋太宗','宋','宋诗','song-poetry','','[]','牡丹花，深紅淺，忍把金刀枝上剪。',96,'全唐诗/poet.song.2000.json','["牡丹花，深紅淺，忍把金刀枝上剪。", "侵晨含露萬苞香，見者無非情展轉。", "繁華影裏皆柔弱，密葉交加開閃爍。", "朱欄別是一般春，蛺蝶悠颺閑自樂。", "麗天和日景遲遲，思量往事不堪追。", "風送園中來又去，豁然興感競移時。"]'),
('c01f7fcb-da10-4c77-8798-bce4ed02f0f2','緣識  其五八','宋太宗','宋','宋诗','song-poetry','','[]','妙手彈琴無向束，知之修鍊五音足。',338,'全唐诗/poet.song.2000.json','["妙手彈琴無向束，知之修鍊五音足。", "先辨浮沈有指歸，弦頭制度相催促。", "右手抑揚禁淫邪，左手徘徊堪瞻矚。", "法於天，象於地，伏羲所造與心契。", "先明理世見其真，六律含徽聲嘹唳。", "從茲化被先賢慕，激濁揚清消喜怒。", "太素仁風去住間，元和之氣皆徧布。", "飛鳳在天不可測，大小龍吟不費力。", "響應聽時有自然，舉措安詳能雅飾。", "南風思政民俗化，順從平等無高下。", "淳朴相傳今復興，逍遥道德後宗亞。", "指要直掌須反善，拊安排齊似剪取。", "聲來往，玄更玄，振兼文武情展轉。", "古與今來千萬弄，幾人通達能妙用。", "廣陵散好足仙蹤，胡笳十八堪鄭重。", "堪鄭重，何清切，依憑伎倆能撥剌。", "輕挑重打善間鉤，連蠲掄下輕微抹。", "伯牙彈時如何美，汪汪洋洋似流水。", "類例研究得剛柔，壞陵秋思無比擬。", "敘志神和慢調⿰車爾，修身治性藏幽隠。", "蒼龍鶴舞白雉飛，防奢止欲皆相準。"]'),
('9fcde22f-64c9-467d-accf-c27f29cbffb9','緣識  其五九','宋太宗','宋','宋诗','song-poetry','','[]','拊弄聲相引，兼能辨五音。',48,'全唐诗/poet.song.2000.json','["拊弄聲相引，兼能辨五音。", "沈思調品切，句度更加吟。", "緊慢弦中得，凝情指法深。", "精英閑雅澹，停歇世途心。"]'),
('34bed921-1da9-41c9-9c4b-d750efc6b9b5','緣識  其六○','宋太宗','宋','宋诗','song-poetry','','[]','全無體段弟一弱，十指乖張時更錯。',175,'全唐诗/poet.song.2000.json','["全無體段弟一弱，十指乖張時更錯。", "五音不辨信手彈，薄會人前言自樂。", "弦不調，手不洗，更兼指下無道理。", "吟爲失度故不知，把手空摇說宮徵。", "合彈慢處却彈急，愚蒙堪笑情兀兀。", "修持嚴潔甚難哉，岡知瀟灑心中出。", "容易撫之何草草，顛來倒去直至老。", "又耻人教却生嗔，虛度時光猶言好。", "不聰人豈解，指法故然無。", "拙見閑聲律，終朝自娛。", "塵埃琴不飾，日月歲蕭疏。", "慢共知音說，能彈好破除。"]'),
('9ac622c4-db33-4e2a-b674-91052fe87c87','迴文偈四首  其一','宋太宗','宋','宋诗','song-poetry','','[]','上缺深意大誰教，指因緣善歸。',14,'全唐诗/poet.song.2000.json','["上缺深意大誰教，指因緣善歸。"]'),
('a898ce5a-3376-465b-ba5c-a6a75084a5ed','迴文偈四首  其二','宋太宗','宋','宋诗','song-poetry','','[]','會解垂要理，真詮羨非深。',24,'全唐诗/poet.song.2000.json','["會解垂要理，真詮羨非深。", "意大誰教指，因緣善歸心。"]'),
('e3075c10-0b8c-40ec-92be-f81b59edcf11','迴文偈四首  其三','宋太宗','宋','宋诗','song-poetry','','[]','解垂要理真，詮羨非深意。',24,'全唐诗/poet.song.2000.json','["解垂要理真，詮羨非深意。", "大誰教指因，緣善歸心會。"]'),
('8a6e8f72-ddb3-4650-9d4c-9a5d604e1a78','迴文偈四首  其四','宋太宗','宋','宋诗','song-poetry','','[]','重要理真詮。',6,'全唐诗/poet.song.2000.json','["重要理真詮。"]'),
('e55daac8-d0ec-488c-8aef-e789336ca279','好字倒迴文','宋太宗','宋','宋诗','song-poetry','','[]','好與煩性生，好聽。',9,'全唐诗/poet.song.2000.json','["好與煩性生，好聽。"]'),
('bf46922d-010c-4357-8067-a09ad657e47d','述字迴文偈七首  其一','宋太宗','宋','宋诗','song-poetry','','[]','上缺留希佛背生。',8,'全唐诗/poet.song.2000.json','["上缺留希佛背生。"]'),
('36609e8e-6259-4ebc-a17a-ac9704fab61e','述字迴文偈七首  其二','宋太宗','宋','宋诗','song-poetry','','[]','求比舊前憂，依述最亨知。',24,'全唐诗/poet.song.2000.json','["求比舊前憂，依述最亨知。", "休以祐然留，希佛背生推。"]'),
('97c4f515-3dd6-4ebc-96ab-2f5b2f384749','述字迴文偈七首  其三','宋太宗','宋','宋诗','song-poetry','','[]','比舊前憂依，述最亨知休。',24,'全唐诗/poet.song.2000.json','["比舊前憂依，述最亨知休。", "以祐然留希，紳背生推求。"]'),
('558edabd-4629-4da3-8f9a-83ee1ae54f58','述字迴文偈七首  其四','宋太宗','宋','宋诗','song-poetry','','[]','舊前憂依述，最亨知休以。',24,'全唐诗/poet.song.2000.json','["舊前憂依述，最亨知休以。", "祐然留希佛，背生推求比。"]'),
('0c4b9eaa-6d75-4dd1-878d-40d0e56ccc99','述字迴文偈七首  其五','宋太宗','宋','宋诗','song-poetry','','[]','前憂依述最，亨知休以祐。',24,'全唐诗/poet.song.2000.json','["前憂依述最，亨知休以祐。", "然留希佛背，生推求比舊。"]'),
('08da7a8d-89fe-4699-9916-15ce792c7b89','述字迴文偈七首  其六','宋太宗','宋','宋诗','song-poetry','','[]','憂依述最亨，知休以祐然。',24,'全唐诗/poet.song.2000.json','["憂依述最亨，知休以祐然。", "留希佛背生，推求比舊前。"]'),
('93d04d5f-2404-4e84-a047-343304ac669a','述字迴文偈七首  其七','宋太宗','宋','宋诗','song-poetry','','[]','依述最亨知，休以祐然留。',24,'全唐诗/poet.song.2000.json','["依述最亨知，休以祐然留。", "希佛背生推，求比舊前憂。"]'),
('d764c9a1-416a-41d3-b5ed-b0b04426bfbe','述字倒迴文三首  其一','宋太宗','宋','宋诗','song-poetry','','[]','述依憂前舊，比求推生背。',18,'全唐诗/poet.song.2000.json','["述依憂前舊，比求推生背。", "以休知亨最。"]'),
('dffe5446-4286-4ebc-9e75-8c1842fc721c','述字倒迴文三首  其二','宋太宗','宋','宋诗','song-poetry','','[]','依憂前舊比，求推生背佛。',24,'全唐诗/poet.song.2000.json','["依憂前舊比，求推生背佛。", "希留然祐以，休知亨最述。"]'),
('069d210f-81f2-4c95-9c3c-448f1835048f','述字倒迴文三首  其三','宋太宗','宋','宋诗','song-poetry','','[]','憂前舊比求，推生背佛希。',24,'全唐诗/poet.song.2000.json','["憂前舊比求，推生背佛希。", "留然祐以休，知亨最述依。"]'),
('0855bd80-ca95-4ce6-9b39-a59ed645ddba','迴文偈二首  其一','宋太宗','宋','宋诗','song-poetry','','[]','教訓大寬深，古羨協真齊。',24,'全唐诗/poet.song.2000.json','["教訓大寬深，古羨協真齊。", "要運解觀心，苦善業因迷。"]'),
('6f288886-68f0-46f3-a4c8-a46d452fd341','好字拘就觀字正迴文','宋太宗','宋','宋诗','song-poetry','','[]','道寬開訓新，生生業□□。',12,'全唐诗/poet.song.2000.json','["道寬開訓新，生生業□□。"]'),
('d430d871-3ba6-4d07-9071-76afe2d925fd','太平興國七年季冬大雪賜學士','宋太宗','宋','宋诗','song-poetry','','[]','輕輕相亞凝如酥，宮樹花裝萬萬株。',32,'全唐诗/poet.song.2000.json','["輕輕相亞凝如酥，宮樹花裝萬萬株。", "今賜酒卿時一盞，玉堂閑話道情無。"]'),
('65fa09ca-9907-4b12-8c0c-43f32b09e6c8','試趙昌國','宋太宗','宋','宋诗','song-poetry','','[]','秋風雪月天，花竹鶴雲烟。',24,'全唐诗/poet.song.2000.json','["秋風雪月天，花竹鶴雲烟。", "詩酒春池雨，山僧道柳泉。"]'),
('9da06990-bc01-4f9c-b5f8-a45d749c44c6','賜陳摶  其一','宋太宗','宋','宋诗','song-poetry','','[]','蒼生往世弊凋殘，今我如同赤子看。',32,'全唐诗/poet.song.2000.json','["蒼生往世弊凋殘，今我如同赤子看。", "大闡無爲三教盛，承平方說四夷寬。"]'),
('5d6a8aeb-7429-48ef-a223-12f462764354','賜陳摶  其二','宋太宗','宋','宋诗','song-poetry','','[]','餐霞成鶴骨，餌藥駐童顔。',24,'全唐诗/poet.song.2000.json','["餐霞成鶴骨，餌藥駐童顔。", "靜想神仙事，忙中道路閑。"]'),
('cc9b26c9-6f6d-4c42-b348-5c93449d3b96','賜陳摶  其三','宋太宗','宋','宋诗','song-poetry','','[]','曾向前朝出白雲，後來消息杳無聞。',32,'全唐诗/poet.song.2000.json','["曾向前朝出白雲，後來消息杳無聞。", "如今若肯隨徵召，總把三峰乞與君。"]'),
('dd8703ac-c844-46de-92dd-007539c496e8','賜蘇易簡  其一','宋太宗','宋','宋诗','song-poetry','','[]','翰林承旨貴，清凈玉堂中。',48,'全唐诗/poet.song.2000.json','["翰林承旨貴，清凈玉堂中。", "應用咸依式，深嚴比更崇。", "歸家思值日，入內集英風。", "儒措門生盛，高明大化雄。"]'),
('6e6f3ca4-ae84-40a4-a22f-bd8a23678756','賜蘇易簡  其二','宋太宗','宋','宋诗','song-poetry','','[]','運偶昌時遠更深，果然穀在我中心。',64,'全唐诗/poet.song.2000.json','["運偶昌時遠更深，果然穀在我中心。", "從風臣偃光朝野，此日清華見翰林。", "舉措樂時周禮法，思賢教古善規箴。", "少年學士文明世，一守賢毫數萬尋。"]'),
('653bd8ca-6422-43b7-b940-7fad36193e9e','佛牙讚','宋太宗','宋','宋诗','song-poetry','','[]','功成積劫印文端，不是南冊得恐難。',64,'全唐诗/poet.song.2000.json','["功成積劫印文端，不是南冊得恐難。", "眼睹數重金色潤，手擎一片玉光寒。", "鍊時百火精神透，藏處千年瑩采完。", "定果熏修真祕密，正心莫作等閑看。"]'),
('29f10183-ea59-4165-a362-582ed6aceccd','送趙普','宋太宗','宋','宋诗','song-poetry','','[]','忠勤王室展宏謨，政事朝堂頼秉扶。',32,'全唐诗/poet.song.2000.json','["忠勤王室展宏謨，政事朝堂頼秉扶。", "解職暫酬卿所志，休教一念遠皇都。"]'),
('ff2b62bd-7e54-4948-a3fa-601b72ba120e','句  其一','宋太宗','宋','宋诗','song-poetry','','[]','欲餌金鈎深未到，磻溪須問釣魚人。',16,'全唐诗/poet.song.2000.json','["欲餌金鈎深未到，磻溪須問釣魚人。"]'),
('151eb4e2-a2a5-4a05-865a-d093994ba54c','句  其二','宋太宗','宋','宋诗','song-poetry','','[]','薄德終慚舉，通才例上居。',12,'全唐诗/poet.song.2000.json','["薄德終慚舉，通才例上居。"]'),
('5c2827ff-a244-4708-929b-494ab8ec1206','句  其三','宋太宗','宋','宋诗','song-poetry','','[]','時向玉堂尋舊迹，八花磚上日空長。',16,'全唐诗/poet.song.2000.json','["時向玉堂尋舊迹，八花磚上日空長。"]'),
('b67974d6-03dc-41d7-8491-3dc4fc2e7a4c','句  其四','宋太宗','宋','宋诗','song-poetry','','[]','鑾輿臨紫塞，朔野凍雲飛。',12,'全唐诗/poet.song.2000.json','["鑾輿臨紫塞，朔野凍雲飛。"]'),
('1efb2711-0554-43ae-bfd9-603b7e4bbf0b','句  其五','宋太宗','宋','宋诗','song-poetry','','[]','好事盡輸純與直，謾勞頰舌湧如泉。',16,'全唐诗/poet.song.2000.json','["好事盡輸純與直，謾勞頰舌湧如泉。"]'),
('8d5304f9-93f9-43e7-b219-ca0ea67430a5','句  其六','宋太宗','宋','宋诗','song-poetry','','[]','奉使南遊多好景。',8,'全唐诗/poet.song.2000.json','["奉使南遊多好景。"]'),
('ce56a124-f14a-485d-942e-24c95ada26d1','句  其七','宋太宗','宋','宋诗','song-poetry','','[]','君臣千載遇。',6,'全唐诗/poet.song.2000.json','["君臣千載遇。"]'),
('fa2960a1-9f82-424d-b988-8ef087a33ca2','句  其八','宋太宗','宋','宋诗','song-poetry','','[]','二三千客裏成事，七十四人中少年。',16,'全唐诗/poet.song.2000.json','["二三千客裏成事，七十四人中少年。"]'),
('d0e7ad10-4a14-49db-b1d9-e60e71b26d15','句  其九','宋太宗','宋','宋诗','song-poetry','','[]','珍重老臣純不已，我慚寡昧繼三皇。',16,'全唐诗/poet.song.2000.json','["珍重老臣純不已，我慚寡昧繼三皇。"]'),
('3260d835-347a-4197-a1b6-d5281a07e3c1','句  其一○','宋太宗','宋','宋诗','song-poetry','','[]','一箭未施戎馬遁，六軍空恨陳雲高。',28,'全唐诗/poet.song.2000.json','["一箭未施戎馬遁，六軍空恨陳雲高。", "鑾輿曠紫塞，朔野陣雲飛。"]'),
('19e2ea9a-c51e-4ff4-903c-3c4500868666','上方','陳省華','宋','宋诗','song-poetry','','[]','四望平川獨一峰，峰前瀟灑是蓮宮。',64,'全唐诗/poet.song.2000.json','["四望平川獨一峰，峰前瀟灑是蓮宮。", "松聲竹韻千年冷，水色山光萬古同。", "客到每憐樓閣異，僧言因得鬼神功。", "懸民遥喜行春至，鼓腹閑歌夕照中。"]'),
('ee251206-22de-440c-a681-c0534d64f866','非風幡動仁者心動頌','釋本先','宋','宋诗','song-poetry','','[]','非風幡動唯心動，自古相傳直至今。',32,'全唐诗/poet.song.2000.json','["非風幡動唯心動，自古相傳直至今。", "今後水雲人欲曉，祖師直是好知音。"]'),
('ee32f7ea-3226-4d46-a97f-90fb3a51a000','見色便見心頌','釋本先','宋','宋诗','song-poetry','','[]','若是見色便見心，人來問著方難答。',32,'全唐诗/poet.song.2000.json','["若是見色便見心，人來問著方難答。", "更求道理說多般，孤負平生三事衲。"]'),
('cad67be2-91b5-40d6-b1a9-1f36a6700241','明自己頌','釋本先','宋','宋诗','song-poetry','','[]','曠大劫來祇如是，如是同天亦同地。',32,'全唐诗/poet.song.2000.json','["曠大劫來祇如是，如是同天亦同地。", "同地同天作麽形，作麽形兮無不是。"]'),
('1ed5b4ca-4314-4564-ad1e-7384b9408b01','薔薇詩一首十八韻呈東海侍郎徐鉉','李從善','宋','宋诗','song-poetry','','[]','綠影覆幽池，芳菲四月時。',216,'全唐诗/poet.song.2000.json','["綠影覆幽池，芳菲四月時。", "管弦朝夕興，組繡百千枝。", "盛引牆看徧，高煩架屢移。", "露輕濡綵筆，蜂誤拂吟髭。", "日照玲瓏幔，風摇翡翠帷。", "早紅飄蘚地，狂蔓挂蛛絲。", "嫩刺牽衣細，新條窣草垂。", "晚香難暫捨，嬌態自相窺。", "深淺分前後，榮華互盛衰。", "尊前留客久，月下欲歸遲。", "何處繁臨砌，誰家密映籬。", "絳羅房燦爛，碧玉葉參差。", "分得殷勤種，開來遠近知。", "晶熒歌袖袂，柔弱舞腰支。", "膏麝誰將比，庭萱自合嗤。", "勻妝低水鑑，泣淚滴烟𩅰。", "畫擬憑梁廣，名宜亞楚姬。", "寄君十八韻，思拙媿新奇。"]'),
('79d42b2a-fc63-491c-9b44-fd95ac64fc96','寄贈終南英公上人','臧丙','宋','宋诗','song-poetry','','[]','是箇人言好性靈，鎬京碑記念千廳。',64,'全唐诗/poet.song.2000.json','["是箇人言好性靈，鎬京碑記念千廳。", "五言出格爲詩匠，百盞長杯應酒星。", "曾把篆求身上紫，幾將金買面前青。", "多聞國士相尋訪，莫把松門畫夜扃。"]'),
('6540569e-6d8b-40b1-90a6-7da5cbb307c6','閒居','林緒','宋','宋诗','song-poetry','','[]','宿草江邊閣，臨流發嘯歌。',48,'全唐诗/poet.song.2000.json','["宿草江邊閣，臨流發嘯歌。", "所觀得病少，豈在蓄書多。", "生子能無貴，居身不可過。", "苟圖銷旦夕，青鬢長如何。"]'),
('5fe61b31-939d-492a-8a26-bdb6d07858f3','送僧歸天甯萬年禪院','安德裕','宋','宋诗','song-poetry','','[]','跡自青門遠，田衣賁在躬。',48,'全唐诗/poet.song.2000.json','["跡自青門遠，田衣賁在躬。", "舊房千嶠外，歸棹五湖東。", "地力薑畦沃，年支芋盎充。", "從支乃榮道，一與祖心同。"]'),
('9fe8c5f0-10be-45a2-ad3a-2bac56987158','詩一首','馬文斌','宋','宋诗','song-poetry','','[]','希奇寶象獸中王，猛毅雄心世不當。',64,'全唐诗/poet.song.2000.json','["希奇寶象獸中王，猛毅雄心世不當。", "四足端然如玉柱，雙牙利劍若金鋩。", "立觀峭峻成山岳，動必摇形見者慌。", "但以聲名告醜類，從今何敢作災殃。"]'),
('28146722-8976-4e6f-94d4-22045c4d8e59','花雨比下秦中','田錫','宋','宋诗','song-poetry','','[]','雨裏飛花片片紅，雨微花亂轉溟濛。',64,'全唐诗/poet.song.2000.json','["雨裏飛花片片紅，雨微花亂轉溟濛。", "川原何處連天草，簾幕無人半日風。", "寂寞劉楨新病後，淒迷莊舄苦吟中。", "可堪更是黄昏景，燕冷鶑寒恨想同。"]'),
('e9a8e0cd-9512-47bf-b3fe-351fa066c584','寄蒲城宋白小著','田錫','宋','宋诗','song-poetry','','[]','春日閑銷一局棋，春愁還得數篇詩。',64,'全唐诗/poet.song.2000.json','["春日閑銷一局棋，春愁還得數篇詩。", "高吟大醉何人問，英略雄圖久已知。", "破産雖無容足所，丈夫豈合以家爲。", "時來富貴終須有，懶學梁鴻賦五噫。"]'),
('d5ff4ba9-302c-4b87-b9b5-7469992d5a18','離懷','田錫','宋','宋诗','song-poetry','','[]','離懷如醉復如癡，脈脈無言不展眉。',64,'全唐诗/poet.song.2000.json','["離懷如醉復如癡，脈脈無言不展眉。", "秋草空牽幽意在，征軒疑有斷魂隨。", "殘星更漏門開處，斜月簾櫳酒醒時。", "此恨誰能解消遣，因題紅葉偶成詩。"]'),
('d5f87aed-b05d-48b3-8063-dff3bc7dffb0','自勉','田錫','宋','宋诗','song-poetry','','[]','飄泊年年頗恨身，梁園未到滯咸秦。',64,'全唐诗/poet.song.2000.json','["飄泊年年頗恨身，梁園未到滯咸秦。", "上樓獨爲青山立，攬鑑初驚白髮新。", "北叟何曾悲失馬，宣尼猶自問迷津。", "功名分有終須得，莫强憂愁耗爾神。"]'),
('d57669d8-5b9c-4781-868e-ed92462cd344','夏日即事','田錫','宋','宋诗','song-poetry','','[]','王師猶未下全吳，何日封章賀獻俘。',64,'全唐诗/poet.song.2000.json','["王師猶未下全吳，何日封章賀獻俘。", "正是鬰蒸生瘴瘧，可堪不潦滿江湖。", "威宣鐵軸千艘盛，執撼金陵一壘孤。", "羈客無能爲籌略，閑消白日覆棋圖。"]'),
('18ca8c3b-82da-4178-aaf1-e28c75547406','春雨','田錫','宋','宋诗','song-poetry','','[]','天寒雲彩變春輝，霢霂來如曉霧飛。',64,'全唐诗/poet.song.2000.json','["天寒雲彩變春輝，霢霂來如曉霧飛。", "著物先饒芳草濕，盈空旋翳碧山微。", "鶑村樹密吹應徧，鴛瓦簷高滴尚稀。", "丞相追班方入賀，沙隄柳色正依依。"]'),
('2c79712e-3e98-411d-bd95-88780b1cb97b','樽前吟呈宋白小著','田錫','宋','宋诗','song-poetry','','[]','三年多謝主人翁，盃酒相寬禮數豐。',64,'全唐诗/poet.song.2000.json','["三年多謝主人翁，盃酒相寬禮數豐。", "唯惜時光如走馬，懶詢天道似張弓。", "秋深街巷槐花雨，夜靜廳堂葦箔風。", "盡是無憀腸斷處，都將分付醉鄉中。"]'),
('7b1adef5-f5ce-4900-83af-778c1d3db230','代牡丹酬答','田錫','宋','宋诗','song-poetry','','[]','舒元輿是賦家流，我有餘研不盡收。',64,'全唐诗/poet.song.2000.json','["舒元輿是賦家流，我有餘研不盡收。", "今日謝君貽好句，恨無雙珮略相酬。", "神仙見謫情雖薄，風雨相輕恨未休。", "爲報悅人須以禮，不同蘇小耐慚羞。"]'),
('d344637c-2340-458e-a644-1e50ca108886','多情','田錫','宋','宋诗','song-poetry','','[]','多情如病苦難醫，頭緒多於折藕絲。',64,'全唐诗/poet.song.2000.json','["多情如病苦難醫，頭緒多於折藕絲。", "送客落花行馬處，望鄉殘月倚樓時。", "憶來幾入春深夢，感極翻成酒後悲。", "大抵爲君言不盡，彩牋閑詠合歡詩。"]'),
('6f05cc63-be4d-4242-b3b4-927eea58686d','寄韓丕進士','田錫','宋','宋诗','song-poetry','','[]','嵩室亂峰三十六，嵩陽今復住何峰。',64,'全唐诗/poet.song.2000.json','["嵩室亂峰三十六，嵩陽今復住何峰。", "已因詩好聲名出，却爲情高仕進慵。", "白鳥白雲秋色樹，水南水北月明鐘。", "逍遥自得閑吟興，誰識夫君是卧龍。"]'),
('d699ae8a-f518-4b39-b7ee-7f1ef4345e15','覽韓渥鄭谷詩因呈太素','田錫','宋','宋诗','song-poetry','','[]','風騷夐古少知音，本色詩人百種心。',64,'全唐诗/poet.song.2000.json','["風騷夐古少知音，本色詩人百種心。", "順熟合依元白體，清新堪擬鄭韓吟。", "搜來健比孤生竹，得處精於百鍊金。", "唯我與君相唱和，天機自見不勞尋。"]'),
('d59a3cc6-d862-409b-b689-9de2edd2d125','渭北即事書呈太素','田錫','宋','宋诗','song-poetry','','[]','渭北居來似塞垣，三逢堯曆度寒暄。',64,'全唐诗/poet.song.2000.json','["渭北居來似塞垣，三逢堯曆度寒暄。", "家貧老幼思歸國，性僻交朋少及門。", "天暖憶遊沙苑寺，雪中會過洛河村。", "流年又是重陽節，賞菊論詩酒一樽。"]'),
('136ba58f-b311-49f8-9f0f-fbf001dd10e0','醉題紅葉','田錫','宋','宋诗','song-poetry','','[]','拾筆閑題紅葉時，醉容相向亦相宜。',64,'全唐诗/poet.song.2000.json','["拾筆閑題紅葉時，醉容相向亦相宜。", "塞垣風勁應吹盡，江國霜微想半衰。", "嫌聽滿階鳴夜雨，曾看臨水映疏籬。", "春光不許長如此，旋放寒梅嫩柳枝。"]'),
('1a0156ff-8999-43e9-9dcd-e1bdc43cde85','寄題象耳寺','田錫','宋','宋诗','song-poetry','','[]','二十年前會憶游，彭亡渡口泊孤舟。',64,'全唐诗/poet.song.2000.json','["二十年前會憶游，彭亡渡口泊孤舟。", "一程林下登山路，百尺谿邊汲水樓。", "磬韻似煙和燭裊，松聲如雨入窗流。", "別來往事都成夢，誰寄篇章問惠休。"]'),
('9445cad8-b760-4864-b674-e280ebe37389','促織','田錫','宋','宋诗','song-poetry','','[]','西風嫋嫋欲昏黄，草木蕭蕭綠翅凉。',64,'全唐诗/poet.song.2000.json','["西風嫋嫋欲昏黄，草木蕭蕭綠翅凉。", "闇傍遠燈催絡緯，獨經遥夜伴啼螿。", "露濡蟲綱絲潛斷，月照澄江練有光。", "幾處疏砧紅葉寺，誰憐弄杼不成章。"]'),
('bcef92ba-d2ec-4c52-90fa-76ec83b14e91','憶梅花','田錫','宋','宋诗','song-poetry','','[]','三年不見遠江梅，長到梅時把酒盃。',64,'全唐诗/poet.song.2000.json','["三年不見遠江梅，長到梅時把酒盃。", "似共故人千里別，空思近臘數枝開。", "心隨曉月經鄉渚，夢與春雲傍釣臺。", "金蕊瓊花風雪景，憑誰圖畫入關來。"]'),
('507394fe-2b12-458d-8db4-f66c34906953','和太素春書','田錫','宋','宋诗','song-poetry','','[]','風幡輕細翠悠颺，樓閣輕寒水滿塘。',64,'全唐诗/poet.song.2000.json','["風幡輕細翠悠颺，樓閣輕寒水滿塘。", "柳絮微煙吟思足，梨花淡月睡魂香。", "江山似畫憐湘浦，魚笋嘗新憶華腸。", "早是春陰憶無頼，可堪中酒惡情陽。"]'),
('b4e3ab4d-fe90-452a-9745-514e11dd57e6','和太素早春書事憶遊京國','田錫','宋','宋诗','song-poetry','','[]','新年吟詠喜經旬，金粟山邊渭水濱。',64,'全唐诗/poet.song.2000.json','["新年吟詠喜經旬，金粟山邊渭水濱。", "微雪尚妨天氣暖，衰林先讓鳥聲春。", "牽情但恨梅花謝，醒酒空思桂蠹辛。", "深感相將遊汴水，夢中楊柳已迷人。"]'),
('8b663f2f-1aea-4445-bb88-08c3eedc26c8','覽太素新編','田錫','宋','宋诗','song-poetry','','[]','蜀國香牋似彩霞，裝成近集入京華。',64,'全唐诗/poet.song.2000.json','["蜀國香牋似彩霞，裝成近集入京華。", "千篇詩好精靈器，百軸文雄俠少誇。", "繁富積皇新職貢，妍明春帝曉鶑花。", "彤庭何處安排好，李謫仙才稱草麻。"]'),
('8ec305ed-2839-457f-b0a3-083c93fc6776','吟情','田錫','宋','宋诗','song-poetry','','[]','風月心腸別有情，靈臺珠玉氣常清。',64,'全唐诗/poet.song.2000.json','["風月心腸別有情，靈臺珠玉氣常清。", "微吟暗觸天機駭，雅道因隨物象生。", "春是主人饒蕩逸，酒爲歡伯伴縱橫。", "莫嫌宮體多淫艷，到底詩狂罪亦輕。"]'),
('d6e579cc-8f73-4299-94cf-37c24910f1b4','和朱玄進士對雪','田錫','宋','宋诗','song-poetry','','[]','風迴玉宇拂窗欄，欲晚層城科峭寒。',64,'全唐诗/poet.song.2000.json','["風迴玉宇拂窗欄，欲晚層城科峭寒。", "含月有光吟不盡，著煙無迹畫方難。", "江春南國兼梅落，塞臘西山向竹殘。", "何處多情偏入賞，狂隨舞袖遶盃盤。"]'),
('4b4eb986-1e7f-4bb1-8495-010443ce9d36','冬夕書事','田錫','宋','宋诗','song-poetry','','[]','堪嗤棲屑客長安，風雪加添近臘寒。',64,'全唐诗/poet.song.2000.json','["堪嗤棲屑客長安，風雪加添近臘寒。", "江筆呵來書字淡，孤燈挑盡向窗殘。", "十年苦思詩千首，一夕迴腸事萬端。", "家住天涯歸未得，嶺梅江蓼自辛酸。"]'),
('f79f1584-45f9-46e9-aa88-21aa8d1983e1','對酒','田錫','宋','宋诗','song-poetry','','[]','去年秋值罷文闈，今歲無憀自陝歸。',64,'全唐诗/poet.song.2000.json','["去年秋值罷文闈，今歲無憀自陝歸。", "雪月好吟還唱和，風雲未至且依違。", "江南梅早多紅蔕，渭北山寒少翠微。", "猶頼一樽消遣恨，不堪棖觸躁時機。"]'),
('f6e0b7e9-13a9-4a04-9b2e-f1f7d5fdabd3','暮冬閿鄉遇蕭霸赴任','田錫','宋','宋诗','song-poetry','','[]','嶺外路遥君赴任，陝西年盡我歸家。',64,'全唐诗/poet.song.2000.json','["嶺外路遥君赴任，陝西年盡我歸家。", "長亭際會情無限，一夕分飛恨又賒。", "夜話無燈松火繼，曉行乘月亂山斜。", "七千里驛誰相伴，雪裏寒梅正放花。"]'),
('17171d8c-1e84-4495-9069-205ca35f6fe7','殘冬書事呈宋太玄','田錫','宋','宋诗','song-poetry','','[]','歸來何物可消憂，縣寺蕭條懶强游。',64,'全唐诗/poet.song.2000.json','["歸來何物可消憂，縣寺蕭條懶强游。", "酒價未償重貰取，雪詩休厭且交酬。", "兼憐春近如迎客，莫惜年殘似急流。", "天子承祧重文物，花時早約入皇州。"]'),
('cc201c66-b8c3-4733-bebb-20e881127b91','寄梁周翰補闕徽之宋白二拾遺','田錫','宋','宋诗','song-poetry','','[]','飄零蹤跡尚堪悲，唯向三賢最受知。',64,'全唐诗/poet.song.2000.json','["飄零蹤跡尚堪悲，唯向三賢最受知。", "少俊有名輸賈誼，宦遊多難比張儀。", "詩中老格何人愛，酒後佯狂識者嗤。", "北省郎官應見誚，明時猶尚進身遲。"]'),
('c15b3b8d-68d3-47b2-8d9d-f84232f27b74','寄宋準學士','田錫','宋','宋诗','song-poetry','','[]','鸞輿西幸郊天日，洛水橋南乍識君。',64,'全唐诗/poet.song.2000.json','["鸞輿西幸郊天日，洛水橋南乍識君。", "投分塤箎無異曲，定交蘭菊有餘芬。", "別來信阻年將盡，望去臺高日又曛。", "堪恨支離何所似，波中萍葉嶺頭雲。"]'),
('5e9c770d-27f0-44a2-974c-f75296fb112e','和宋太玄臘日','田錫','宋','宋诗','song-poetry','','[]','逢臘欣酬吟詠才，已知春色向人來。',64,'全唐诗/poet.song.2000.json','["逢臘欣酬吟詠才，已知春色向人來。", "口脂潤逐銀罌賜，百藥香隨鈿合開。", "梁苑辭臣堪賦雪，壽陽公主好妝梅。", "更憐罷獵歸侵夜，重對歌筵紅燭臺。"]'),
('a0828b3b-60df-438d-b24c-1277edf1e35e','三月二十八日書懷','田錫','宋','宋诗','song-poetry','','[]','惜春將盡自徘徊，巷館殘陽戶半開。',64,'全唐诗/poet.song.2000.json','["惜春將盡自徘徊，巷館殘陽戶半開。", "芳樹更無鶑舌語，故巢空有燕歸來。", "音書杜絕家千里，愁憤消磨酒一盃。", "地狹長沙何所適，行謠方憶摘楊梅。"]'),
('6af9eee1-e3ff-4e6e-94e4-4aab54b2b239','渭北春盡日作因思蜀洛舊遊寄太素','田錫','宋','宋诗','song-poetry','','[]','九十日春知枉度，樽前無頼獨咨嗟。',64,'全唐诗/poet.song.2000.json','["九十日春知枉度，樽前無頼獨咨嗟。", "空城北走諸陵道，古苑南連百里沙。", "翠憶玉津官舍竹，繁思金馬故城花。", "去年言與君遊洛，況味爭如不在家。"]'),
('0a80d39a-1319-48d6-b97b-950e6e7d41c0','即事','田錫','宋','宋诗','song-poetry','','[]','殘花飛盡留芳草，縈寞孤懷話未能。',64,'全唐诗/poet.song.2000.json','["殘花飛盡留芳草，縈寞孤懷話未能。", "天氣暄寒猶未定，春衫脫著自無憑。", "荔枝結子思南越，湖水宜茶憶竟陵。", "看是清和時又過，林亭何處度炎蒸。"]'),
('fa425f6d-eec2-4404-a546-91d280df74e8','晚望因寄宋太素','田錫','宋','宋诗','song-poetry','','[]','春深水榭絮紛紛，支策臨高日欲曛。',64,'全唐诗/poet.song.2000.json','["春深水榭絮紛紛，支策臨高日欲曛。", "故國已迷巴徼路，斷腸空似嶺頭雲。", "燕飛芳草隨天遠，鶑囀殘花隔竹聞。", "物景感人情不盡，因成吟詠寄於君。"]'),
('eeb57571-e336-4863-bcd4-7b4a20a8213f','幽居','田錫','宋','宋诗','song-poetry','','[]','寂寂閑居客至稀，靜中滋味意何歸。',64,'全唐诗/poet.song.2000.json','["寂寂閑居客至稀，靜中滋味意何歸。", "因探易象知深旨，自喜吟高得化機。", "桑露乍寒蠶欲老，草煙纔暖蝶交飛。", "樊川物景終南翠，遂性空思杜紫微。"]'),
('a2edcd61-af20-49e0-996b-86fb5dc049d0','府解後有詔旨權停貢舉因成長句寄太素兼簡韓丕茂才','田錫','宋','宋诗','song-poetry','','[]','一名倜儻動皇州，寄應王門作解頭。',64,'全唐诗/poet.song.2000.json','["一名倜儻動皇州，寄應王門作解頭。", "將領風騷推李杜，較量英勇讓曹劉。", "春闈有詔俄中輟，秋賦隨時亦暫休。", "金殿制科思取應，遠飛章句問喜謀。"]'),
('4a91ce06-1e69-4da8-a7dd-acba9358f1ed','御試二儀合德詩','田錫','宋','宋诗','song-poetry','','[]','聖主承祧兌澤深，乾坤玄化合堯心。',96,'全唐诗/poet.song.2000.json','["聖主承祧兌澤深，乾坤玄化合堯心。", "黄輿比厚旋生植，白日齊明遠照臨。", "周普至仁符積載，霶流睿渥若春霖。", "游鱗在藻方諧性，獷俗乘桴自獻琛。", "和悅感人生瑞靄，穆清流詠在薰琴。", "小臣幸與觀光試，敢效祈招頌德音。"]'),
('4872dd88-ccbe-4efb-be58-f17334e3fbf6','寄陳處士','田錫','宋','宋诗','song-poetry','','[]','簿書軍吏日相隨，心在諠譁旨趣卑。',64,'全唐诗/poet.song.2000.json','["簿書軍吏日相隨，心在諠譁旨趣卑。", "明月夜吟無意緒，白雲秋約笑羈縻。", "宛陵古寺經遊少，疊嶂名樓眺望遲。", "堪重高人陳處士，不來尋訪已多時。"]'),
('a484714c-ec20-401e-9516-093addad2c6f','登郡樓望嚴陵釣臺','田錫','宋','宋诗','song-poetry','','[]','谿上嚴陵古釣臺，倚樓凝望自徘徊。',64,'全唐诗/poet.song.2000.json','["谿上嚴陵古釣臺，倚樓凝望自徘徊。", "先生能保孤高節，英主嘗師王霸才。", "日暮白雲迷草莽，岸平春水浸莓苔。", "登臨不盡微吟興，花落東風首重迴。"]'),
('60c74b1c-d62f-4c17-b2ab-39554a21ba1c','寄陳處士','田錫','宋','宋诗','song-poetry','','[]','柳闇江亭春正深，黄鶑百囀有餘音。',64,'全唐诗/poet.song.2000.json','["柳闇江亭春正深，黄鶑百囀有餘音。", "自慚分判頒條政，誰信常懷易俗心。", "吟次落花浮硯水，靜中飛絮滿簾陰。", "及瓜即是歸丹闕，莫惜時來一訪尋。"]'),
('31f3f865-1a04-4553-b21b-640e170577e5','登疊嶂樓','田錫','宋','宋诗','song-poetry','','[]','郡在江湖煙樹間，謝公遺踵好躋攀。',64,'全唐诗/poet.song.2000.json','["郡在江湖煙樹間，謝公遺踵好躋攀。", "詩中勝景堪吟嘯，池上清風足往還。", "疑思但憐雲映水，迴頭不覺日銜山。", "登臨屢起歸歟興，看是槐花滿故關。"]'),
('8da2d245-23af-4df2-a91e-4e4bf4982390','和安儀鳳','田錫','宋','宋诗','song-poetry','','[]','水國迎凉暑氣消，思清吟嘯語雄豪。',64,'全唐诗/poet.song.2000.json','["水國迎凉暑氣消，思清吟嘯語雄豪。", "遠如海樹黄雲曉，健比秋風白浪高。", "酬答愧無明月珮，縱橫爭及解牛刀。", "和詩送別昭亭路，何似金鑾奪錦袍。"]'),
('2f7e488a-833e-4521-b93f-25bf8911122a','送安儀鳳','田錫','宋','宋诗','song-poetry','','[]','宣城相送思依依，正是紅蓮菡萏時。',64,'全唐诗/poet.song.2000.json','["宣城相送思依依，正是紅蓮菡萏時。", "行色迎秋清似畫，別情因景化爲詩。", "人離湖水南邊岸，蟬聽槐花北向枝。", "天子文明是何地，丹霄岐路莫生疑。"]'),
('30f45f65-0f1d-4ac8-bf55-46431757dc51','寄攀郎中','田錫','宋','宋诗','song-poetry','','[]','近遣司賓小吏時，寄書兼寄十篇詩。',64,'全唐诗/poet.song.2000.json','["近遣司賓小吏時，寄書兼寄十篇詩。", "自慚不是陽春曲，誰敢徼求作者知。", "疊嶂晚登空遠望，昭停別後倍相思。", "夜來還有微吟興，風動新荷月滿池。"]'),
('6c515793-a4e3-4bec-aae8-d64aa2c88e3a','謝晏公','田錫','宋','宋诗','song-poetry','','[]','吟成大雅百篇詩，首首清新鑒者誰。',64,'全唐诗/poet.song.2000.json','["吟成大雅百篇詩，首首清新鑒者誰。", "草卷密封先見贈，藥欄斜倚看多時。", "意如虎窟難中得，字比雲峰險處奇。", "珍重十僧聲價外，江南屈指即吾師。"]'),
('57bc8831-76c2-4b99-9d66-ee7543b81f1b','早秋言懷','田錫','宋','宋诗','song-poetry','','[]','清秋江國有餘暄，謝朓遺風稱雅言。',64,'全唐诗/poet.song.2000.json','["清秋江國有餘暄，謝朓遺風稱雅言。", "簾下水亭人吏靜，窗分笑閣簿書繁。", "坐來幽蝶雙飛過，吟次高梧一葉翻。", "自笑無能蒞公事，將何才術了君恩。"]'),
('97b72daf-9b3a-4265-acc5-91dc33468867','寄江南諸相知','田錫','宋','宋诗','song-poetry','','[]','詩成奏入冕旒前，小諫官資驟轉遷。',64,'全唐诗/poet.song.2000.json','["詩成奏入冕旒前，小諫官資驟轉遷。", "带職喜爲仙館吏，立班常近御爐烟。", "清華拜命知深忝，謇諤非才愧昔賢。", "多謝宣城舊知己，寄來新句滿花牋。"]'),
('288f1be6-a329-4101-a406-4ccea5006190','乾明節祝聖壽  其一','田錫','宋','宋诗','song-poetry','','[]','百辟歡呼降誕辰，金樽獻酒願千春。',63,'全唐诗/poet.song.2000.json','["百辟歡呼降誕辰，金樽獻酒願千春。", "延年不假丹砂效，亨壽全由聖德新。", "古物進來兼藥鼎，畫圖呈處有仙人。", "君恩若賞歌詩意，應念甘侍從臣。"]'),
('99927370-1179-4bd3-9012-0a370d44bb94','乾明節祝聖壽  其二','田錫','宋','宋诗','song-poetry','','[]','生日稱觴自六宮，香焚甲觀畫堂中。',64,'全唐诗/poet.song.2000.json','["生日稱觴自六宮，香焚甲觀畫堂中。", "太平曆數歸英主，上壽年齡屬聖躬。", "玉樹有花因瑞雪，鈞天呈曲在虛空。", "三公進賀禎祥事，先奏河清達帝聰。"]'),
('b530ea09-ae5d-48c6-9e14-b8e23878c908','乾明節祝聖壽  其三','田錫','宋','宋诗','song-poetry','','[]','吾皇享福自無涯，百辟稱觴禮數加。',64,'全唐诗/poet.song.2000.json','["吾皇享福自無涯，百辟稱觴禮數加。", "韶樂揭天如上界，鑪香映日似輕霞。", "空中紫氣圓成蓋，海上蟠桃暖放花。", "感應聖人千萬壽，神仙日月屬官家。"]'),
('f3d363e9-71db-4890-aefe-f63f2c0dcb89','乾明節祝聖壽  其四','田錫','宋','宋诗','song-poetry','','[]','皇朝令節號乾明，萬國嘻嘻若大庭。',64,'全唐诗/poet.song.2000.json','["皇朝令節號乾明，萬國嘻嘻若大庭。", "多士進詩隨禹貢，千官獻酒祝堯齡。", "天香曉降聞仙樂，南海秋來見壽星。", "黎庶更思瞻盛禮，待封日觀禪雲亭。"]'),
('8fce7eb1-0280-41c8-8d01-e5044a25c720','乾明節祝聖壽  其五','田錫','宋','宋诗','song-poetry','','[]','鸞盃進酒近天顔，拜舞風清響珮環。',64,'全唐诗/poet.song.2000.json','["鸞盃進酒近天顔，拜舞風清響珮環。", "瑞日正高重御宴，摵鞭纔定再催班。", "霓旌絳節仙家樂，金闕銀臺海上山。", "綺陌曉來迴望處，建章樓閣紫雲間。"]'),
('9f36a101-9165-4da5-b88e-b3003ac43720','乾明節祝聖壽  其六','田錫','宋','宋诗','song-poetry','','[]','聖節祥煙藹御鑪，殿庭嚴肅響山呼。',64,'全唐诗/poet.song.2000.json','["聖節祥煙藹御鑪，殿庭嚴肅響山呼。", "赭袍日照來天上，玉佩風清侍座隅。", "古字數行仙藥訣，鮫綃十幅壽星圖。", "遠方拜表來朝貢，兼賀虹流電繞樞。"]'),
('883e67ab-a7eb-4cbf-bd0b-bf66c67a3fc1','乾明節祝聖壽  其七','田錫','宋','宋诗','song-poetry','','[]','漢家臺榭與天通，甲觀蒼蒼紫氣中。',64,'全唐诗/poet.song.2000.json','["漢家臺榭與天通，甲觀蒼蒼紫氣中。", "佳節夜來宣受賀，壽盃朝進祝延洪。", "管絃嘈囋驚花發，同日晴和向雪融。", "宴次宮鸚忽飛過，隨呼萬歲語玲瓏。"]'),
('e04aa3fa-19d4-4e00-9d0a-0297c9620de9','乾明節祝聖壽  其八','田錫','宋','宋诗','song-poetry','','[]','君王降誕繼陶唐，每至嘉辰睹異祥。',64,'全唐诗/poet.song.2000.json','["君王降誕繼陶唐，每至嘉辰睹異祥。", "宮樹曉來生瑞露，金門夜半有天香。", "皇親朝覲隨章奏，中使頒宣散道場。", "萬國人臣皆悅樂，巍巍聖德自無疆。"]'),
('50df557f-1063-4f2b-af94-f3c99a245176','乾明節祝聖壽  其九','田錫','宋','宋诗','song-poetry','','[]','慶誕長生寶殿中，非煙五色覆諸宮。',64,'全唐诗/poet.song.2000.json','["慶誕長生寶殿中，非煙五色覆諸宮。", "酒爲天祿資君壽，曲奏霓裳樂帝聰。", "悲翠簾前雲氣紫，珊瑚枝上雪花紅。", "太平天子聞稱賀，先喜年年過歲豐。"]'),
('d4e26530-7d9b-45af-b0e4-e0fb5b211d4d','乾明節祝聖壽  其一○','田錫','宋','宋诗','song-poetry','','[]','聖節思歸會帝京，得隨班列祝文明。',64,'全唐诗/poet.song.2000.json','["聖節思歸會帝京，得隨班列祝文明。", "河清見底爲嘉瑞，海水無波表太平。", "月夜忽聞仙樂奏，宮中時有彩雲生。", "詩成拜表同封進，願繼詞臣雅韻聲。"]'),
('f8f3308f-d377-4e52-b3e5-e5cb4fe8101f','乾明節祝聖壽  其一一','田錫','宋','宋诗','song-poetry','','[]','日上扶桑第一枝，東方樓閣曙光時。',64,'全唐诗/poet.song.2000.json','["日上扶桑第一枝，東方樓閣曙光時。", "萬邦將啟乾明宴，兩制應宣御製詩。", "樂感羽毛皆率舞，神和福祿自來宜。", "諫垣班列天顔近，暫乞歸朝侍玉墀。"]'),
('9e2c8578-ba14-4ea0-bdd0-9d04a2bd2958','乾明節祝聖壽  其一二','田錫','宋','宋诗','song-poetry','','[]','河朔雖云近帝鄉，時逢慶誕祝君王。',64,'全唐诗/poet.song.2000.json','["河朔雖云近帝鄉，時逢慶誕祝君王。", "身心常在三清路，曉夕先裝一炷香。", "聖壽如山隨地久，恩光似日與天長。", "策臣所貴無他物，唯獻新譸十九章。"]'),
('d395bfc3-18ff-401f-8795-da4df8257de2','相州郡樓贈高祕丞','田錫','宋','宋诗','song-poetry','','[]','年來歸興憶皇州，頻向花時倚郡樓。',64,'全唐诗/poet.song.2000.json','["年來歸興憶皇州，頻向花時倚郡樓。", "南陌春光芳樹遠，西郊山色晚雲浮。", "國家無事邊陲靜，風俗還淳禮讓修。", "吟得新詩謝知己，將何才術稱分憂。"]'),
('4ce9afc6-046b-47dd-afff-fa1eeb1eba3c','贈楊臨察','田錫','宋','宋诗','song-poetry','','[]','昔日長安際會時，客情鄉思兩依依。',64,'全唐诗/poet.song.2000.json','["昔日長安際會時，客情鄉思兩依依。", "金門次第俱升達，雲路高低各奮飛。", "御史班資知任重，諫官章綬愧才微。", "今來共理藩宣事，自古相逢似此稀。"]'),
('7ad37b13-abcf-4b86-8f9b-2e1e680e1b5f','郡樓書懷','田錫','宋','宋诗','song-poetry','','[]','館殿嘗爲侍從臣，出分憂寄牧黎民。',64,'全唐诗/poet.song.2000.json','["館殿嘗爲侍從臣，出分憂寄牧黎民。", "時平事簡多公暇，樓迥風清欲暮春。", "樹杪壺關千嶂疊，天邊漳水綠波新。", "帝鄉永日憑欄望，心羨浮雲向紫宸。"]'),
('1489758a-b868-4785-ad1f-7869e6fb395a','池上','田錫','宋','宋诗','song-poetry','','[]','溝堰新分野水來，池邊日夕自徘徊。',64,'全唐诗/poet.song.2000.json','["溝堰新分野水來，池邊日夕自徘徊。", "餘花飛盡空芳樹，落絮繁多滿綠苔。", "輦下歸心春館殿，天邊凝睇晚樓臺。", "郡齋欲立題詩石，御史丞郎各有才。"]'),
('92b31d20-93ea-4b14-b45c-0978e0a39b4d','暮雨','田錫','宋','宋诗','song-poetry','','[]','春天寒慘欲昏黄，數點霏霏忽繞廊。',64,'全唐诗/poet.song.2000.json','["春天寒慘欲昏黄，數點霏霏忽繞廊。", "城漏暗催相共滴，花塵輕濕乍聞香。", "風生水際來將密，雨打簾文灑處光。", "獨向郡齋心自喜，豐年宜賀侍飛章。"]'),
('838b640b-a379-4f12-b2d6-599516897bcb','中夜聞泉','田錫','宋','宋诗','song-poetry','','[]','昨日西山野外通，聲如秋雨带松風。',64,'全唐诗/poet.song.2000.json','["昨日西山野外通，聲如秋雨带松風。", "誰憐鄴下重城夜，却似江南廨署中。", "燭燼垂花飄硯席，月華凝雪映簾櫳。", "此時新得潺湲聽，吟詠狂思學謝公。"]'),
('d2b30695-3f25-4c54-8db3-9939223595c8','言懷','田錫','宋','宋诗','song-poetry','','[]','遠山蒼翠滿西樓，亶甲遺風古相州。',64,'全唐诗/poet.song.2000.json','["遠山蒼翠滿西樓，亶甲遺風古相州。", "春晚落花經雨盡，夜來寒水繞堂流。", "詔條靜理無才術，衮職思歸侍冕旒。", "吟寄良交若爲意，安眠不得似諸侯。"]'),
('43e87ce6-098d-4c49-8ee3-2421b491f24d','呈楊侍郎','田錫','宋','宋诗','song-poetry','','[]','權分憂寄理漳濱，惠化何及相民。',63,'全唐诗/poet.song.2000.json','["權分憂寄理漳濱，惠化何及相民。", "條奏事宜思復古，興修風教望還淳。", "靜當細雨初封印，吟對餘花自送春。", "清蚊好陪池上酌，故人情分最相親。"]'),
('bf1a09e7-7934-4696-b2bd-95b6c7fb8c2e','除夜','田錫','宋','宋诗','song-poetry','','[]','紅燭除花酒滿巵，繞廓風細動簾帷。',64,'全唐诗/poet.song.2000.json','["紅燭除花酒滿巵，繞廓風細動簾帷。", "已從半夜分春漏，即是平明受歲時。", "或省轉官因大慶，元正立仗憶丹墀。", "吟思何日承宣召，却得金門和御詩。"]'),
('85bb7f72-772f-4261-af4b-ab9f28f2db01','元日','田錫','宋','宋诗','song-poetry','','[]','去年元會立班時，簪紱光輝與禮儀。',64,'全唐诗/poet.song.2000.json','["去年元會立班時，簪紱光輝與禮儀。", "今日洺川逢歲旦，延留賓客樂昌期。", "朝雲暖潤輕陰散，晚日融明瑞景遲。", "遥念皇州春色早，宮花欲發萬年枝。"]'),
('e9e26540-85c1-4e94-a6c4-a778ecfbfbf6','漳川即事寄韓丕拾遺','田錫','宋','宋诗','song-poetry','','[]','漳濱柳色弄微黄，春日情懷詠載陽。',64,'全唐诗/poet.song.2000.json','["漳濱柳色弄微黄，春日情懷詠載陽。", "自念安邊無上策，如何補衮與周行。", "身如迴雁來河朔，心似浮雲在帝鄉。", "吟寄昌黎韓小諫，嘉謨應有好封章。"]'),
('208a65e6-d480-47f3-8b51-bcbd34907cab','紅樹','田錫','宋','宋诗','song-poetry','','[]','秋來嘉樹色堪攀，紅葉沒谿復映山。',64,'全唐诗/poet.song.2000.json','["秋來嘉樹色堪攀，紅葉沒谿復映山。", "半露寺樓深崦裏，密籠漁舍夕陽間。", "吟看摇落堆金井，醉賞扶疏對玉顔。", "水國却疑春野秀，似花幽鳥正關關。"]'),
('26e2b7f5-337a-4b14-a08e-2927f7b4a524','聖節有懷','田錫','宋','宋诗','song-poetry','','[]','南山晴靄御爐烟，迴望長安白日邊。',64,'全唐诗/poet.song.2000.json','["南山晴靄御爐烟，迴望長安白日邊。", "率衆謝恩呼萬歲，思歸侍宴已三年。", "翠微鐘磬行香寺，紅葉樓臺祝壽筵。", "吟想皇州晚來景，雲間宮闕夕陽天。"]'),
('3815cc7c-8f2f-42d4-9d0b-1dd5dfae32ed','秋聲有懷寄副翰宋白舍人','田錫','宋','宋诗','song-poetry','','[]','秋聲蕭瑟北山椒，頼有琴樽遣寂寥。',64,'全唐诗/poet.song.2000.json','["秋聲蕭瑟北山椒，頼有琴樽遣寂寥。", "書幌靜憐斜月鑒，窗燈寒带落花挑。", "久辭知己來江國，少寄音書過海潮。", "因想玉堂今夜直，建章宮漏正迢迢。"]'),
('90273ad4-d8a4-4fae-aefd-cbf0333729f8','釣臺懷古','田錫','宋','宋诗','song-poetry','','[]','閑讀銘詞掃綠苔，溪邊永日自徘徊。',64,'全唐诗/poet.song.2000.json','["閑讀銘詞掃綠苔，溪邊永日自徘徊。", "白雲遺迹今親到，青史高名不可陪。", "千古煙霞爲己有，一竿風月避誰來。", "松巔老鶴應相識，時唳和風下釣臺。"]'),
('6ac46f98-7df6-4f72-852f-d7b2f7e9f03c','郡齋書事','田錫','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','江天短景莫相催，三度逢花折早梅。',64,'全唐诗/poet.song.2000.json','["江天短景莫相催，三度逢花折早梅。", "仙棹遠歸思李郭，廬山高會憶宗雷。", "林端忽見孤雲出，池上欣聞好客來。", "昨夜月明霜更苦，卷簾黄葉滿青苔。"]'),
('c1904360-1120-4aee-b2f8-49788e6b26d6','暇日偶題','田錫','宋','宋诗','song-poetry','','[]','年來吟鬢已星星，鳥石谿邊葉又零。',64,'全唐诗/poet.song.2000.json','["年來吟鬢已星星，鳥石谿邊葉又零。", "簾下孤燈刪草奏，窗間疊嶂讀茶經。", "瘴鄉怕襲山嵐毒，野艇嫌衝水霧腥。", "天末豈記歸去意，白雲掩映數峰青。"]'),
('64925edf-d9a7-4581-b831-051bb3bbe9e5','桐江即事','田錫','宋','宋诗','song-poetry','','[]','滄州深隠未言歸，三載桐江解印遲。',64,'全唐诗/poet.song.2000.json','["滄州深隠未言歸，三載桐江解印遲。", "官職清華非不達，性靈疏拙欲何爲。", "閑移夫子青山廟，擬立嚴陵釣渚碑。", "兼喜谿雲每相狎，時來窗戶伴吟詩。"]'),
('cc950cc2-8650-4227-8cfb-601ad71104e1','水霖','田錫','宋','宋诗','song-poetry','','[]','菊花潦倒雨冥冥，秋菌參差上壁生。',64,'全唐诗/poet.song.2000.json','["菊花潦倒雨冥冥，秋菌參差上壁生。", "臺榭可堪閑眺望，池籠不快野心情。", "猿啼山館寒無夢，燈背風簾滴到明。", "却爲農家妨歛穫，叢祠精舍擬祈晴。"]'),
('c71c93ac-745f-46c6-8c1c-401d19d85631','和溫仲舒殘春遣懷','田錫','宋','宋诗','song-poetry','','[]','丹闕年來奏賀頻，金輿侍從望東巡。',64,'全唐诗/poet.song.2000.json','["丹闕年來奏賀頻，金輿侍從望東巡。", "越王江上重迴首，嚴子臺邊再送春。", "水國山川怡道性，花時琴酒悅吟神。", "煙霞肯欲留君往，宰相方謀用故人。"]'),
('9794bdee-879d-46f6-96d0-2b88a187fe02','郡中遣意寄友人','田錫','宋','宋诗','song-poetry','','[]','谿雲澹澹浪悠悠，十二州中最小州。',64,'全唐诗/poet.song.2000.json','["谿雲澹澹浪悠悠，十二州中最小州。", "花落喜過流水寺，月明懶下看潮樓。", "藥欄梅潤秋重換，棋局松陰夜不收。", "吟寄故人如借問，釣魚磯在海西頭。"]'),
('0d813672-03db-4f48-8c4d-f4e3fe8a4305','桐江詠','田錫','宋','宋诗','song-poetry','','[]','桐谿湛湛見游鱗，摇落楓林繞水濱。',64,'全唐诗/poet.song.2000.json','["桐谿湛湛見游鱗，摇落楓林繞水濱。", "秋色數行沙上雁，殘陽一簇渡頭人。", "藍鮮斤生過深澗，雪吼寒潮人富春。", "俱是謝公吟詠地，伊余何以繼芳塵。"]'),
('5a1de026-5681-4d12-a4e2-8eab3b1cbd66','偶題因懷張王二諫議','田錫','宋','宋诗','song-poetry','','[]','理郡三年政未聞，孤城僻在浙江濆。',64,'全唐诗/poet.song.2000.json','["理郡三年政未聞，孤城僻在浙江濆。", "金門路遠書難寄，水國吟餘日又曛。", "半夜啼猿千里客，數峰殘雪一谿雲。", "詩中贏得爲官況，不讓樊川杜使君。"]'),
('40ad7f4d-eb45-4f20-beb9-581d6cda2ddc','七里灘','田錫','宋','宋诗','song-poetry','','[]','清泚寒流走白沙，釣臺蒼翠遠嵯峨。',64,'全唐诗/poet.song.2000.json','["清泚寒流走白沙，釣臺蒼翠遠嵯峨。", "隔谿人語穿芳樹，旁岸魚跳落淺莎。", "幾處上源堪涉渡，有時野艇併來過。", "秋聲不盡吟詩意，七里潺湲奈爾何。"]'),
('2626f8c4-4ce6-4d48-93b7-4d23717d381d','和溫仲舒寄贈','田錫','宋','宋诗','song-poetry','','[]','桐江秋水錦鱗肥，閑釣煙波是見機。',64,'全唐诗/poet.song.2000.json','["桐江秋水錦鱗肥，閑釣煙波是見機。", "野步共遊芳草徑，吟情對啟白雲扉。", "醉來拾筆題紅葉，睡覺憑欄望翠微。", "官滿替人如未到，蒹葭玉樹且相依。"]'),
('f339268c-e2c4-4fd3-8d42-f0f161e3913f','和溫仲舒感懷','田錫','宋','宋诗','song-poetry','','[]','郡齋松蓋翠斜欹，客至鳴琴汎酒巵。',64,'全唐诗/poet.song.2000.json','["郡齋松蓋翠斜欹，客至鳴琴汎酒巵。", "江上正當摇落景，天涯空惜太平時。", "尋殘幽谷春難到，蘭茂深林衆豈知。", "上國三千王百里，楊梅熟日是歸期。"]'),
('bd9312dc-1823-4e3f-a141-b7933fb34795','倚樓','田錫','宋','宋诗','song-poetry','','[]','西樓吟倚若爲情，情似浮雲處處生。',64,'全唐诗/poet.song.2000.json','["西樓吟倚若爲情，情似浮雲處處生。", "翠疊亂山千里闊，紅翻晴葉一川明。", "散分野色漁村小，斜襯秋光雁陣橫。", "迴望帝鄉歸未得，蘆花如雪繞江城。"]'),
('bd2f0e9c-fafc-43f7-947d-8a42ff76e19f','秋懷','田錫','宋','宋诗','song-poetry','','[]','蒹葭深處古嚴州，吟向潺湲爲送秋。',64,'全唐诗/poet.song.2000.json','["蒹葭深處古嚴州，吟向潺湲爲送秋。", "雲映疏鐘紅葉寺，浪摇孤角翠微樓。", "土茅路遠催先貢，霜稻天晴趁早收。", "零落黄花正西笑，應憐印綬尚淹留。"]'),
('8d99d5c5-1d52-4150-8bbb-08e0fa29caaa','題天竺寺','田錫','宋','宋诗','song-poetry','','[]','三月楊花撲馬飛，聯鑣來欵白雲扉。',64,'全唐诗/poet.song.2000.json','["三月楊花撲馬飛，聯鑣來欵白雲扉。", "湖邊鐘磬含清籟，樹杪樓臺靄翠微。", "野景留人狂欲住，春光啼鳥勸思歸。", "萋萋芳草重迴首，十里松門照落暉。"]'),
('34e89917-f332-4162-a467-1b154db1d926','茱萸堰泊','田錫','宋','宋诗','song-poetry','','[]','茱萸堰下泊行舟，初落帆檣暮雨收。',64,'全唐诗/poet.song.2000.json','["茱萸堰下泊行舟，初落帆檣暮雨收。", "寒水漾煙輕似縠，微雲籠月澹如秋。", "登封自惜天涯去，盛事空思國史修。", "達曙不眠燈耿耿，寺鐘遥聽在西樓。"]'),
('02698ee5-d5d9-4470-bf06-2f98b010fdd1','讀翰林集','田錫','宋','宋诗','song-poetry','','[]','太白謫仙人，換酒鷫鸘裘。',96,'全唐诗/poet.song.2000.json','["太白謫仙人，換酒鷫鸘裘。", "扁舟弄雲海，聲動南諸侯。", "諸侯盡郊迎，葆吹羅道周。", "哆目若餓虎，逸翰飛靈虬。", "落日青山亭，浮雲黄鶴樓。", "浩浩歌謠興，滔滔江漢流。", "下交魏王屋，長揖韓荆州。", "千載有英氣，蘭君安可儔。"]'),
('9e3ad38b-db8d-4346-99ec-3443ba659e30','寄宋白拾遺','田錫','宋','宋诗','song-poetry','','[]','醉中別大梁，西歸胃水陽。',216,'全唐诗/poet.song.2000.json','["醉中別大梁，西歸胃水陽。", "飄然何所似，浮雲辭帝鄉。", "歸來驚歲晏，悵然增浩歎。", "景短倏云暝，夜寒難至旦。", "指酒雪花飛，早梅思南枝。", "碧落周星紀，青陽換歲時。", "雙魚忽得書，云已三公駭奇士。", "嚴吳玉霄仍近密，小諫官職清，大才文翰逸。", "獻納有嘉謀，英豪伸壯圖。", "萬乘是知己，外華籍。", "金骨俄輕舉，侍從臣，元白才名子。", "揮毫爛彩霞，逸性飛湍水。", "不日縯絲綸，鼇宮承帝旨。", "伊余重交結，白日貫精誠。", "黄金一諾重，鴻毛萬事輕。", "微塵彈作冠，清泉滌吾纓。", "思佩朝天籙，相將昇太清。"]'),
('386fbc94-7ad6-48b1-9d29-9902824173af','塞上曲','田錫','宋','宋诗','song-poetry','','["\u5199\u666f", "\u79cb\u5929", "\u8fb9\u585e"]','秋氣生朔陲，塞草猶離離。',84,'全唐诗/poet.song.2000.json','["秋氣生朔陲，塞草猶離離。", "大漠西風急，黄榆凉葉飛。", "襜襤罷南牧，林胡畏漢威。", "藁街將入貢，代馬就新羈。", "浮雲護玉關，斜日在金微。", "蕭縈邊聲靜，太平烽影稀。", "素臣稱有道，守在於四夷。"]'),
('ed29c798-c874-4932-9621-3bc2341fab28','塞下曲','田錫','宋','宋诗','song-poetry','','[]','黄河瀉白浪，到海一萬里。',120,'全唐诗/poet.song.2000.json','["黄河瀉白浪，到海一萬里。", "榆關風土惡，夜來霜入水。", "河源凍徹底，冰面平如砥。", "邊將好邀功，夜率鏖兵起。", "馬度疾於風，車馳不濡軌。", "盡破匈奴營，別築漢家壘。", "擴土過陰山，窮荒爲北鄙。", "天威震朔漠，戎心畏廉李。", "所以龍馬駒，長貢明天子。", "邊夫苟非才，怨亦從茲始。"]'),
('7953ee54-7f14-4235-9c93-b6a17ce49cb8','結交篇','田錫','宋','宋诗','song-poetry','','[]','爲簪莫用玉，玉脆長憂折。',85,'全唐诗/poet.song.2000.json','["爲簪莫用玉，玉脆長憂折。", "連環須以金，金堅永無缺。", "陳餘尚倜儻，張耳重交結。", "事勢俄參商，干戈自屠滅。", "意斷如與會離，情忘若弦絕。", "始志何綢繆，終讎何勇决。", "我願然諾心，不得輕相悅。"]'),
('646ce935-1a8e-42fa-854c-2aab6a39314a','投杼詞','田錫','宋','宋诗','song-poetry','','[]','孝爲百行本，至性由天資。',144,'全唐诗/poet.song.2000.json','["孝爲百行本，至性由天資。", "曾參善事母，母氏賢且慈。", "馨膳以饋進，承意唯歡怡。", "高堂既自樂，纖室閑鳴機。", "飛語忽來告，明識潛深思。", "蓋念事吾孝，安得殺人爲。", "亟聞寧不信，投杼遂生疑。", "用知君臣際，反以交朋推。", "道德難結固，恩情有合離。", "毀譽苟不入，讒間無以施。", "景慕魏文侯，滿篋留謗詞。", "樂羊在山中，委遇終不衰。"]'),
('2f6336df-a155-4df9-9235-c4f23d6e979a','擬古  其一','田錫','宋','宋诗','song-poetry','','[]','棠谿出精金，百鍊無餘滓。',108,'全唐诗/poet.song.2000.json','["棠谿出精金，百鍊無餘滓。", "鑄得芙蓉劍，靈輝若秋水。", "陸可斷兕犀，陰亦驚神鬼。", "照物雙影寒，中霄靈氣紫。", "有時風雨至，欲作龍蛇起。", "海酒與陵肉，寶燭延奇士。", "酣飲取傳觀，英圖各相視。", "吐氣成虹蜺，將平不平事。", "大笑荆軻輩，卒如兒女子。"]'),
('bf456cea-7170-48cf-be09-f6c516bb4086','擬古  其二','田錫','宋','宋诗','song-poetry','','[]','中山魏公子，志意邈難儔。',72,'全唐诗/poet.song.2000.json','["中山魏公子，志意邈難儔。", "朝吸沆瀣精，遠與冥鴻遊。", "風高江浪惡，雲黄海樹秋。", "青山對獨酌，明月在孤舟。", "心常懸象魏，迹若參公侯。", "縱橫致君術，思一伸良籌。"]'),
('b135641b-0ada-4561-bdd0-068fa4cf0fd3','擬古  其三','田錫','宋','宋诗','song-poetry','','[]','遊子中夜心，功名忽嗟暮。',48,'全唐诗/poet.song.2000.json','["遊子中夜心，功名忽嗟暮。", "黑貂空上書，甘泉方獻賦。", "白日驚壯齒，青雲有英顧。", "收采苟不時，珊瑚亦生蠹。"]'),
('2ba1f001-9f30-4fde-828a-e679ce5131a7','擬古  其四','田錫','宋','宋诗','song-poetry','','[]','漢鼎鴻毛輕，諸侯爭弄兵。',72,'全唐诗/poet.song.2000.json','["漢鼎鴻毛輕，諸侯爭弄兵。", "吳魏已先定，玄德思功名。", "據鞍髀肉消，感激淚沾纓。", "南陽有奇士，三顧精誠傾。", "龍變得風雨，指麾霸王成。", "日月若長在，永永懸英聲。"]'),
('858083ca-c108-4bb2-8556-772635fa5629','擬古  其五','田錫','宋','宋诗','song-poetry','','[]','碧落登真訣，太霄蕊簡書。',48,'全唐诗/poet.song.2000.json','["碧落登真訣，太霄蕊簡書。", "安得松喬子，仙階一授余。", "載攬彩虹綏，去登紫雲車。", "飄然遠氛俗，志逸如龍攄。"]'),
('4aacabc3-ccc2-4a6f-90bc-7b2b0be7b91f','擬古  其六','田錫','宋','宋诗','song-poetry','','[]','曲逆漢功臣，少年嘗窘厄。',96,'全唐诗/poet.song.2000.json','["曲逆漢功臣，少年嘗窘厄。", "巷館雖席門，軒車盡嘉客。", "事魏言不從，說楚謀無獲。", "來歸隆準公，罄伸圖霸策。", "絳灌競生妬，讒非相見迫。", "封金欲拂衣，將舉鸞皇翮。", "豁達英主心，信遇終無隔。", "小節不掩名，勳庸自輝赫。"]'),
('df5e5dc8-1853-401d-9f66-9e35c49cf8f1','擬古  其七','田錫','宋','宋诗','song-poetry','','[]','禰衡鸚鵡詞，揮翰無停綴。',60,'全唐诗/poet.song.2000.json','["禰衡鸚鵡詞，揮翰無停綴。", "狂甚於接輿，才不容當世。", "身居桴鼓下，心在雲天際。", "黄祖悁忿來，殞之如虎噬。", "淺水游巨魚，宜失縱橫勢。"]'),
('2d0a72e2-5149-4620-b7cf-d9492f80d4c7','擬古  其八','田錫','宋','宋诗','song-poetry','','[]','玉樹拭不滅，柳带柔堪結。',48,'全唐诗/poet.song.2000.json','["玉樹拭不滅，柳带柔堪結。", "惠然貞歸心，皎若天山雪。", "羅幕生春風，珠簾鑒秋月。", "滄波燕又歸，尺書胡斷絕。"]'),
('91a61668-4084-474d-a25e-c0faaa0841a6','擬古  其九','田錫','宋','宋诗','song-poetry','','[]','萱花不須折，安足忘君憂。',48,'全唐诗/poet.song.2000.json','["萱花不須折，安足忘君憂。", "青銅莫頻攬，適令驚鬢秋。", "謝安壯未仕，定遠晚封侯。", "功名俱磊落，時來豈自由。"]'),
('6ae3ea72-2601-4093-ac79-987074c49da5','擬古  其一○','田錫','宋','宋诗','song-poetry','','[]','直言如霜刃，卒發傷人意。',72,'全唐诗/poet.song.2000.json','["直言如霜刃，卒發傷人意。", "痛貫丹誠中，無與金瘡理。", "緘恨若瘢痕，終身難棄置。", "伺隙果報時，遂陷無情地。", "雖悔安可追，弗反同奔駟。", "君子慎樞機，言之豈容易。"]'),
('02645501-b7b9-4d37-a02b-ea6b6d666a99','擬古  其一一','田錫','宋','宋诗','song-poetry','','[]','楚畹種芳蘭，發生逢早春。',84,'全唐诗/poet.song.2000.json','["楚畹種芳蘭，發生逢早春。", "萌芽初蕺蕺，枝葉俄莘莘。", "幽叢秋既老，芳氣冬爾薰。", "馨香當還風，晻藹來襲人。", "百草莫相妬，從之爲爾鄰。", "深林莫蓋藏，芬然亦自伸。", "朝采暮采來，虹綬瓊瑶人。"]'),
('b589f4df-3584-4988-ba56-2093f018ef85','擬古  其一二','田錫','宋','宋诗','song-poetry','','[]','天風吹雨來，黄土爲柔埴。',48,'全唐诗/poet.song.2000.json','["天風吹雨來，黄土爲柔埴。", "一經女媧手，蹶然含性識。", "悲哉商子孫，不能述祖德。", "愚樸變澆漓，化之尤費力。"]'),
('7a8c3661-a1d4-4cca-8131-7eb3d3bba826','擬古  其一三','田錫','宋','宋诗','song-poetry','','[]','余聞靈鳳膠，可以續繼弦。',132,'全唐诗/poet.song.2000.json','["余聞靈鳳膠，可以續繼弦。", "又聞返魂香，招魂以其煙。", "因念三季時，人爲世態遷。", "遷之不自覺，純信成險艱。", "中含妬與忌，外即怡溫顔。", "覆人如覆舟，先示其甘言。", "中夜蹈虎尾，霧海生波瀾。", "投彼機會時，傾亡果忽然。", "願得靈鳳膠，續之於仁賢。", "願得返魂香，返其淳化源。", "免令古樂府，高歌行路難。"]'),
('9e2eef9c-9010-4e78-93cd-026916f94998','擬古  其一四','田錫','宋','宋诗','song-poetry','','[]','廣陵秋節半，旗鼓迓靈濤。',107,'全唐诗/poet.song.2000.json','["廣陵秋節半，旗鼓迓靈濤。", "鰌沈雲海遠，風激雪山高。", "壯哉水濱人，游爲水中豪。", "弄濤若平地，輕命如鴻毛。", "古稱公無渡，弱渡堪悲號。", "憑深良足畏，知險可先逃。", "甘言毒人藥，巧笑刳腸刀。", "狎玩終罹禍，險甚於滔滔。", "昭然聖誡，勉旃於爾曹。"]'),
('2fb6f492-1fdc-4bf5-aa3d-8c7122e944f1','擬古  其一五','田錫','宋','宋诗','song-poetry','','[]','赫赫英豪士，韓侯令子孫。',132,'全唐诗/poet.song.2000.json','["赫赫英豪士，韓侯令子孫。", "千金募死士，博浪報君冤。", "國耻尚未雪，驥足俄驚奔。", "待搏如猛虎，未耀同朝暾。", "霸略師黄石，大計當鴻門。", "談笑定安危，功業遂隆尊。", "鸞皇不啄粟，麒麟不駕轅。", "將從赤松遊，高謝漢皇恩。", "一旦君臣中，奮宗物論喧。", "片詞爲密勿，四皓如飛翻。", "進退存亡間，以智爲身潘。"]'),
('557b281c-b53b-4b74-970d-79ea51a4d164','擬古  其一六','田錫','宋','宋诗','song-poetry','','[]','嶧陽生孤桐，擢斡八尺高。',168,'全唐诗/poet.song.2000.json','["嶧陽生孤桐，擢斡八尺高。", "風雨萌枝葉，鸞皇棲羽毛。", "天質自含響，衆木非其曹。", "斵爲綠綺琴，古人貞金刀。", "所製有法象，不敢差釐毫。", "重詳舊譜錄，試撫觀均調。", "其聲清以廉，聞者不貪饕。", "其音安以樂，令人消鬰陶。", "彈宮聽於君，君德如軒堯。", "彈商聽於臣，臣道如夔皋。", "不覺起蹈舞，形逸同翔翱。", "願以七寶妝，薦之於天朝。", "玉軫朱絲弦，輝華近赭袍。", "一彈南薰曲，解慍成歌謠。"]'),
('c969c879-ff79-4eed-83be-2514f13d70be','千金答漂母行','田錫','宋','宋诗','song-poetry','','[]','止水明沈沈，鑒貌未鑒心。',48,'全唐诗/poet.song.2000.json','["止水明沈沈，鑒貌未鑒心。", "凡鳳舞蹌蹌，知聲未知音。", "楚王欲圖霸，不識韓淮陰。", "淮陰漂母家，獨得千黄金。"]'),
('6e177d5a-1aa5-48aa-9bd9-cf912d72762d','雉媒','田錫','宋','宋诗','song-poetry','','[]','東風麥壟青，白日桑陰清。',120,'全唐诗/poet.song.2000.json','["東風麥壟青，白日桑陰清。", "一雉欲媒衆，衆雉無猜情。", "五步一飲啄，十步一飛鳴。", "闇中觸駭機，鏃發如流星。", "洞徹羽毛質，低摧錦繡翎。", "却宛若召客，子常非好兵。", "讒言既交搆，禍難即隨生。", "齊王聽遊說，韓信急功名。", "三軍雖罷戍，一命遽遭烹。", "古來不疑地，悔吝堪相驚。"]'),
('c7be1950-29e4-4e89-8899-8d12a6d67b2a','鬻冰詠','田錫','宋','宋诗','song-poetry','','[]','赫日生炎暉，鬻冰言及時。',48,'全唐诗/poet.song.2000.json','["赫日生炎暉，鬻冰言及時。", "邀利有得色，冰消俄若遺。", "兩失俱無猜，雖悔安可追。", "仁惠當務遠，勿使失其宜。"]'),
('91d42cda-ebe4-4017-b29f-ca9f201dcdfc','辯惑篇','田錫','宋','宋诗','song-poetry','','[]','春樹桃與李，美果終得嘗。',84,'全唐诗/poet.song.2000.json','["春樹桃與李，美果終得嘗。", "莫樹枳與棘，芒刺還相傷。", "君子所樹黨，在擇賢與良。", "其黨苟非人，爲禍亦自殃。", "蓄者本鉛刀，用欲如干將。", "豢者本款段，騁欲侔驌驦。", "辨之胡不早，堅冰自履霜。"]'),
('8ed0cbf6-ef16-48e4-80cf-3ed321aba576','江南曲  其一','田錫','宋','宋诗','song-poetry','','[]','金蟬飾綠雲，細靨蕊黄新。',48,'全唐诗/poet.song.2000.json','["金蟬飾綠雲，細靨蕊黄新。", "南浦解清珮，西谿采白蘋。", "密竹映深花，湖山日欲曛。", "春腸知已斷，脈脈兩難親。"]'),
('6b9b0446-5f33-48bd-8d2e-aeda13f58a20','江南曲  其二','田錫','宋','宋诗','song-poetry','','[]','吳艷若芙蓉，乘舟弄湖水。',48,'全唐诗/poet.song.2000.json','["吳艷若芙蓉，乘舟弄湖水。", "照影不知休，雲鬟墜簪珥。", "含笑忽迴頭，見人羞欲死。", "歸去入花谿，棹濺鴛鴦起。"]'),
('f5056eaf-21fb-4525-9bb5-82d894b786cd','江南曲  其三','田錫','宋','宋诗','song-poetry','','[]','金陵王氣消，六朝隳霸業。',48,'全唐诗/poet.song.2000.json','["金陵王氣消，六朝隳霸業。", "白雲千古恨，空江照樓堞。", "虎丘羅蔓草，姑蘇委楓葉。", "懷賢思伍員，靈濤浩難涉。"]'),
('00fa9ea1-a7da-467f-a990-b30bcd5e1164','贈朱玄進士','田錫','宋','宋诗','song-poetry','','[]','憶昔長安道，與君初相識。',156,'全唐诗/poet.song.2000.json','["憶昔長安道，與君初相識。", "密雲滿天來，不見南山色。", "美酒斗十千，一醉情歡然。", "胸中雲夢澤，眼底高陽客。", "狂呼月華人，撫弄雲和瑟。", "揮鞭過渭川，館第相留連。", "朝簾杏花露，暮樓楊柳煙。", "流輝今六稔，交情益相審。", "忽忽披君文，如截機頭錦。", "過本生天涯，散金常破家。", "東方上書志，高欲凌丹霞。", "安能常戚促，雀啄秋田粟。", "海路與天遥，鸞皇好相逐。"]'),
('040a692a-e483-4101-a22c-1518f396cb7d','華清宮詞','田錫','宋','宋诗','song-poetry','','[]','繡嶺葱蘢浮瑞氣，雲樓靄闕明珠翠。',384,'全唐诗/poet.song.2000.json','["繡嶺葱蘢浮瑞氣，雲樓靄闕明珠翠。", "禁城緣嶺連九天，一片笙歌如鼎沸。", "我恐紫麟丹鳳洲，移於近甸資宸遊。", "東將太華爲城雉，北以渭川爲御溝。", "又疑西王開月圃，白雲仙都紫雲府。", "碧瑶新宮初搆成，借與明皇自爲主。", "開元之末天寶初，天下太平方晏如。", "萬幾多暇頻遊宴，青門道上馳鑾輿。", "長樂岐頭霸陵岸，新豐市井驪山畔。", "百里煙波錦繡明，寶馬香車若珠貫。", "宮中湯泉瑟瑟文，潺湲長以蘭麝薰。", "白玉蓮花蹙飛浪，珠堂繡殿溫如春。", "貴妃承恩貌傾國，三千宮女朝霞飾。", "謝家有女名阿蠻，歌舞織柔柳無力。", "頻喚入宮恩寵厚，金粟臂鐶頒賜得。", "秋來嶺上霜月明，光照組練金吾兵。", "槐煙柳露咽宮漏，玉笛一轟巖壑驚。", "春來嶺下春波綠，夜聽琵琶將理曲。", "幽咽輕攏慢撚聲，鸞皇引雛啄珠玉。", "嘗記乘輿避暑時，御衣輕似紅蕖絲。", "翠輦將遊石渠寺，探得姚崇乘小駟。", "往來綠樹影中行，清凉適稱逍遥意。", "荔支顔色燕脂紅，生於南海煙瘴中。", "南海地遥一萬里，使臣日貢華清宮。"]'),
('ac38fef4-3ebf-433e-8385-a3dd09fc1bee','曉鶑','田錫','宋','宋诗','song-poetry','','[]','春宵已闌更點急，煙柳濛濛露花溼。',200,'全唐诗/poet.song.2000.json','["春宵已闌更點急，煙柳濛濛露花溼。", "畫堂深邃樓閣寒，碧紗窗中月華入。", "早鶑百囀催朝陽，簧言綺語何鏗鏘。", "雲飛雨敬夢初破，聞時滿枕梨花香。", "聲宛轉，十三弦高指撥軟。", "宮喉徵舌多改變，圓於珠，細於線。", "韻玲瓏，湘妃調瑟煙靄中。", "珠纓寶玦遽相觸，江風細響修篁叢。", "或纖柔兮同彩縷，繡得輕煙纖微雨。", "或輕麗兮如彩毫，畫成曉景描春朝。", "間關歷落意不盡，花中似索鸞皇饒。", "逡巡曙色浮林際，菊花毛衣金作袂。", "一片蘇張俊辯心，長與春皇巧遊說。"]'),
('f1ccf53b-6a3f-4bb1-a06a-c705ca42f55d','晚雲曲','田錫','宋','宋诗','song-poetry','','[]','高唐晚峰欲生雨，空山啼猿風嘯虎。',32,'全唐诗/poet.song.2000.json','["高唐晚峰欲生雨，空山啼猿風嘯虎。", "春雲數片留南浦，自與鴛鴦共飛舞。"]'),
('45150d62-cec4-4e82-be47-dce60923d42b','御溝','田錫','宋','宋诗','song-poetry','','[]','春半桃花水初下，一溝潤綠元如砑。',64,'全唐诗/poet.song.2000.json','["春半桃花水初下，一溝潤綠元如砑。", "夾道官城數里中，靜稱潺湲明月夜。", "千門萬戶建章宮，金鎖橫門溝闇通。", "三月花飛若零雨，水聲何處咽香紅。"]'),
('d64501e6-5974-4851-9a94-9f3f655fdf84','惜春詞','田錫','宋','宋诗','song-poetry','','[]','春色初從江國來，湖邊楊柳嶺頭梅。',320,'全唐诗/poet.song.2000.json','["春色初從江國來，湖邊楊柳嶺頭梅。", "梅花飛雪柳垂带，遞次相將時節催。", "春力欺寒過江北，深谷黄鸝生羽翼。", "曉月輕煙禁苑啼，南園桃李已成蹊。", "就中何處芳菲好，春波飛絮魏王堤。", "我憶去年暮春月，京洛新妝丹鳳闕。", "天津水綠煙樹深，萬井笙歌牡丹發。", "天子鑾輿駕幸時，嵩峰瑞靄籠郊圻。", "扈從千官與萬騎，翊衛羽休兼佽飛。", "六宮隨駕羅珠翠，諸王從行陪七貴。", "香氣成霞金犢車，嗚珂中節虹龍駟。", "朱橋細柳端門前，畫舫橫塘會節園。", "朝花貴俠珊瑚席，夜燭嬌娥玳惠筵。", "西樓殘月深宮漏，明河半沈垂北斗。", "縱飲貪歡意未闌，紫陌喧喧人已繁。", "玉鈎掛簾開雉尾，曉日赭袍朝至尊。", "方今寓止臨清渭，杜門無與天涯異。", "殊忘詩酒狂蕩心，但悅琴書高古意。", "可惜春芳漸欲歸，五陵煙草方離離。", "迴憶當時洛陽道，歌魂空與殘花飛。"]'),
('53d7fb68-c70f-42e4-9cfc-17628418cb7a','風箏歌','田錫','宋','宋诗','song-poetry','','[]','白蘋洲暖春風生，畫樓檻上銀箏鳴。',256,'全唐诗/poet.song.2000.json','["白蘋洲暖春風生，畫樓檻上銀箏鳴。", "鏗鏘節奏急復慢，空中一部天樂聲。", "三十六宮深窈窕，繡楣藻井光相照。", "十三弦上千般聲，朝靄微吟暮煙嘯。", "夜來親向月中聞，繁音錯節何紛紜。", "碎如鸞鈴與珂珮，巫山隊仗迎湘君。", "晚來金屋愁微雨，風細箏聲不全舉。", "依希嬪妾怕人知，啾啾切切私相語。", "洪纖斷續何所拘，鳳凰著對飛鸞孤。", "梧桐枝邊泊未穩，琅玕島上鳴相呼。", "有時主奏俄中絕，宮商斗頓如刀截。", "杏花露重鴛鴦寒，空見如霜滿庭月。", "有時半日全無風，一一暮天樓閣紅。", "唯聞鳥雀啄弦上，暖珠寒玉何玲瓏。", "清音朝朝與暮暮，誤聲不管周郎顧。", "祗嫌雅鄭交奏時，寶鐸丁冬闇相妬。"]'),
('0016a06d-9472-4f6d-b4f2-6f7d365f82f8','聖方平戎歌','田錫','宋','宋诗','song-poetry','','[]','玉關秋早霜飛速，代馬新羈逞南牧。',384,'全唐诗/poet.song.2000.json','["玉關秋早霜飛速，代馬新羈逞南牧。", "胡人背信闚漢邊，刻箭爲書召戎族。", "漁陽烽火照甘泉，疆吏飛牋至御前。", "睿謀英武何神速，鑾輿自欲平三邊。", "百萬羽林隨駕出，殺氣皇威先破敵。", "賊臣喪陣遽奔逃，漳水波清因駐蹕。", "宮錦戰袍花鬭新，繡韉珠絡金麒麟。", "天顔威武不可犯，垂鞭按轡視羣臣。", "金吾隊仗如鱗萃，環衛旌旗徑千里。", "漢皇曾上單于臺，壯心磊落侔風雷。", "比量英武不足數，聖文神武雙全才。", "勢可驅山塞滄海，紫氣逶迤龍鳳蓋。", "金花簇歛若星羅，寶細乘輿翼雲旆。", "塗山禹帝戮防風，涿鹿蚩尤死戰鋒。", "鋒鋩俱染玄黄血，爭如不陳而成功。", "示暇皇歡有餘意，御筆題詩饒綺思。", "翰林承旨先受宣，西掖詞臣及近侍。", "詔命交酬繼和來，君臣道合何如是。", "和氣感天天地寧，日融瑞景籠八紘。", "風生旗旆翻龍鳳，霜嚴鼓角喧雷霆。", "海神來受軍門職，太上禱兵尊帝德。", "牢籠萬國頓天綱，天綱恢恢恩信廣。", "胡兒潰散何比之，大明升空逃魍魎。", "漳川地闊霜草平，合闈會獵布天兵。"]'),
('13dacb26-f821-4a78-a365-f081165b151a','西樓殘月歌','田錫','宋','宋诗','song-poetry','','[]','西樓置酒賓客歡，西樓酒闌夜亦殘。',32,'全唐诗/poet.song.2000.json','["西樓置酒賓客歡，西樓酒闌夜亦殘。", "汪汪月華如玉盤，酒力不禁明月寒。"]'),
('9a6b9bcb-71e5-405f-8d49-01e16e966877','倚柱吟','田錫','宋','宋诗','song-poetry','','[]','暮春慘慘黄昏雨，零落櫻桃斜掩戶。',96,'全唐诗/poet.song.2000.json','["暮春慘慘黄昏雨，零落櫻桃斜掩戶。", "未張燈火簾幕深，樓閣巢寒聞燕語。", "昔時常說長安好，而今厭走長安道。", "蘇秦辨說長卿才，自笑功名胡不早。", "人悄悄，倚柱時，情脈脈，無人知。", "憐春惜遠情不盡，斜雨兼花闇濕衣。"]'),
('fcdf2d98-a1eb-408a-b311-6dbf6c1a6039','李謩吹笛歌','田錫','宋','宋诗','song-poetry','','[]','洛陽少年稱李謩，衆推橫笛多功夫。',384,'全唐诗/poet.song.2000.json','["洛陽少年稱李謩，衆推橫笛多功夫。", "當時教坊第一部，算得比衣皆不如。", "天津楊柳籠橋綠，朧月澹煙何處宿。", "不怕金吾禁夜嚴，偷得新翻禁中曲。", "曲中次第能記持，盡向喬欄闇譜之。", "性聰心慧歸來習，分明把向月中吹。", "五音嘈囋相攙出，呼宮吸徵尤奇崛。", "誰羨曹綱善琵琶，未說陽陶能觱栗。", "纏聲不斷如連環，重聲忽轉如迴山。", "清新不比落梅曲，飄颻乍象霓裳翻。", "碎節繁音交砉騞，南箕鼓風簫籟窄。", "一斛明珠一索穿，撒落金盤催曲拍。", "錚摐大抵聲雄豪，歷歷出羣宮調高。", "豐隆驚得蛟螭起，雨趁雲隨初嘯嗥。", "每到換頭多頓挫，一聲忽迸疑轟破。", "玲瓏祇許牙枝催，清脆不容他樂和。", "宮城響應聲更輝，夜靜月明諸處聞。", "何人懶憶馬南郡，知予已勝桓將軍。", "明皇上樓初聽得，聽罷沈呤都不測。", "宣令徧詢坊巷中，旋使王人捕入宮。", "李謩悉心以實封，皇慈由是寬其罪。", "後來落魄如散仙，扁舟玩月江湖天。", "繡囊探出金線管，揚眉舐脣徒自憐。", "驚神動鬼吹一曲，指法尤高氣海圓。"]'),
('336e1929-5099-472b-90d6-58a5b3d827c0','峨嵋山歌','田錫','宋','宋诗','song-poetry','','["\u5ce8\u7709\u5c71"]','高高百里一屈盤，八十四盤青雲端。',96,'全唐诗/poet.song.2000.json','["高高百里一屈盤，八十四盤青雲端。", "星辰淋灕瀉瀑布，嵐樓雪寺五月寒。", "殘陽忽黑雨雹飛，霹靂火著枯杉枝。", "登臨慨然小天下，迴時一顧東海涯。", "細看朝陽初出時，火精轉毬百尺圍。", "曈曈曨曨浮在水，峨眉朝雲已如綺。"]'),
('024f8cc5-2ca9-4697-8140-dd294016a173','采蓮曲','田錫','宋','宋诗','song-poetry','','[]','南谿秋水深淪漣，南村美人來采蓮。',128,'全唐诗/poet.song.2000.json','["南谿秋水深淪漣，南村美人來采蓮。", "蓮花灼灼葉田田，芳桂輕橈蘭作船。", "采采紅蓮幾成束，蓮枝交衮相撐綠。", "蓮蕊滿衣金粉撲，蓮子爲盃葉爲足。", "唱歌相並畫舸舷，願得采賢如采蓮。", "樊姬昔時進燕趙，幾人精彩朝霞鮮。", "中有二人賢於己，柔明婉順君王前。", "堪嗤羊侃錦繡妾，艷歌留怨朱絲弦。"]'),
('1786b41a-1d8c-40f4-8945-5e5bf82db919','紫雲曲','田錫','宋','宋诗','song-poetry','','[]','沈沈鸞殿垂珠箔，祥烟瑞氣含樓閣。',192,'全唐诗/poet.song.2000.json','["沈沈鸞殿垂珠箔，祥烟瑞氣含樓閣。", "三十六宮明月中，夜靜無風花自落。", "寶屏珠帳一夢時，靈仙初降趨丹墀。", "煙衣霞綬赤瑛珮，鈞天樂部前參差。", "合奏鏗鏘向金屋，云是仙鄉紫雲曲。", "朱弦遠召舜湘靈，鳳管應呼秦弄玉。", "天漢星流夜既闌，露零珠樹彤庭寒。", "芙蓉枕上夢初覺，猶聞庭際聲珊珊。", "上曉五音十二律，仙曲計持心歷歷。", "金線龍頭紅玉笛，新聲吹得情飄逸。", "應是夔襄樂府魂，翻得雅音聞至尊。", "俾與霓裳羽衣曲，遞相奏向梨花園。"]'),
('758f6569-d632-4041-8077-549efb54b206','春洲謠','田錫','宋','宋诗','song-poetry','','[]','衣鮫綃兮美人，采白蘋兮水濱。',45,'全唐诗/poet.song.2000.json','["衣鮫綃兮美人，采白蘋兮水濱。", "裊翠翹兮爲飾，步羅襪兮生塵。", "兮遠道，萋萋兮芳草，遠山眉兮澹掃。"]'),
('35f1ea68-a75c-4e23-a858-8e1ddf02e071','夜宴詞','田錫','宋','宋诗','song-poetry','','[]','天如瑟瑟盤，恢廓憶萬里。',78,'全唐诗/poet.song.2000.json','["天如瑟瑟盤，恢廓憶萬里。", "古稱天傾西北半在地，夜轉繁星磨海水。", "逡巡轉上星彩高，北半未定光飄飄。", "楚王夜入章華宴，紅綃燭籠滿宮殿。", "美人歌舞雲雨迷，不知寒漏催銀箭。"]'),
('4f026e50-a9f9-4810-844b-73134dc6e4dc','送春','田錫','宋','宋诗','song-poetry','','[]','花菲菲，柳依依，留春不住送春歸。',64,'全唐诗/poet.song.2000.json','["花菲菲，柳依依，留春不住送春歸。", "春歸何處堪圖畫，春盡江南日暮時。", "黄鸝啼多芳草遠，青梅子重楊花飛。", "人生三萬六千日，與君復有明年期。"]'),
('41283602-9f5f-4bc5-ad93-b300ccab59eb','暮雪','田錫','宋','宋诗','song-poetry','','[]','北風慘慘生微雪，微雪片片皆橫飛。',48,'全唐诗/poet.song.2000.json','["北風慘慘生微雪，微雪片片皆橫飛。", "梅花柳絮隨人歸，黄雲千里凝無輝。", "唯念蓬蒿何處客，縕袍不暖饑且贏。"]'),
('1ddcd0f0-7a8d-4983-90c3-b62df73ed7b3','短歌行','田錫','宋','宋诗','song-poetry','','[]','曉月蒼蒼向煙滅，朝陽焰焰明丹闕。',64,'全唐诗/poet.song.2000.json','["曉月蒼蒼向煙滅，朝陽焰焰明丹闕。", "杜鵑催促躑躅開，鶗鴂已鳴芳草歇。", "芳春苦不爲君留，古人勸君秉燭遊。", "願與松喬弄雲月，紫泥仙海鸞皇洲。"]'),
('e8a4b95f-bdd6-4917-aa8e-230fa954b741','贈宋小著','田錫','宋','宋诗','song-poetry','','[]','紫皇御天方視事，將擇靈官補仙吏。',266,'全唐诗/poet.song.2000.json','["紫皇御天方視事，將擇靈官補仙吏。", "金波古殿寒星簾，虹節蜺旌觀就試。", "白晰仙人皆尋衣，衣冠森列蟾蜍墀。", "寶盤初賜紅霞饌，斗魁挹酒空淋漓。", "水精地上宮花折，枝柯渥丹花艷白。", "高於建木老於椿，其名仙桂長含春。", "又有驪龍長萬尺，波濤爲屋淵爲室。", "逆鱗滿頷如鋒鋩，觸之則怒無人當。", "旁有明珠夜月光，宛轉炫耀生靈芒。", "能探驪珠折得桂，方許驂鸞駕鳳皇，方令碧落爲星郎。", "君曾再對珠旒試，君才堪作仙宮吏。", "驪珠粲粲蟾枝香，紫煙華綬黄霓裳。", "風裝雲馭慣升陟，太霄瀚海嘗翱翱。", "願以橫天之鵬爲逸駕，垂天之虹作飛梁。", "馳雷走電以驚策，叱風揮雨前啟行。", "結水精珮雲錦章，隨君一至於仙鄉。"]'),
('02c7c800-7846-4f8e-bb7c-06944cd799c9','琢玉歌','田錫','宋','宋诗','song-poetry','','[]','藍谿中，荆山峰，結靈凝粹生羣玉，飛英蕩彩如長虹。',136,'全唐诗/poet.song.2000.json','["藍谿中，荆山峰，結靈凝粹生羣玉，飛英蕩彩如長虹。", "野人初向深崖得，蹋著雲根風雨黑。", "滿把晶熒雪霜色，特達天姿幾人識。", "治玉之工初琢成，熒熒輝彩鏘鏘聲。", "方瑚圓璉薦宗廟，蒼珮玄圭頒帝庭。", "堯兵曾用丹浦戰，漢斗已碎鴻門營。", "我願琢爲北斗柄，指麾五星齊七政。", "庶使陰陽造化機，四時六氣隨吾令。"]'),
('0c3ad27c-22b5-4aa1-a6ba-d4e8d1f6437d','酬陳處士詠雪歌','田錫','宋','宋诗','song-poetry','','[]','潁川處士情高古，閑卧煙霞向南浦。',275,'全唐诗/poet.song.2000.json','["潁川處士情高古，閑卧煙霞向南浦。", "忘却簞瓢陋巷貧，耽嗜琴書醉歌舞。", "昨日西風生凜冽，江天慘慘陰雲結。", "雲色蒼黄千里同，晚來旋旋飛輕雪。", "寒條黏綴生梨花，梅飄絮蕩相交加。", "危樓粉飾軒窗冷，橫橋玉碾欄干斜。", "高人嘯傲吟情動，醉拾江毫呵曉凍。", "狂才意度若元白，滿牋靈怪如麟鳳。", "因遣橘僮封寄余，門者稱有陳君書。", "殿開詠雪六十字，水晶盤中明月珠。", "字字纍纍可編貫，句句綿綿意不斷。", "恨無瑛瓊奉報酬，勝得美人錦繡段。", "君不聞吾皇在上致太平，地不藏珍天降靈。", "時聞刺吏奏河清，又報諸侯賀景星。", "君心幸有經綸術，休向江湖隠聲迹。", "雲眠雪嘯意雖高，爭似金鑾侍赭袍。", "不民虹綸十二犗，明月爲鉤釣臣鼇。"]'),
('50e0c28b-1de3-4c62-a9e7-d321b39513b7','桐谿行','田錫','宋','宋诗','song-poetry','','["\u592a\u6e56"]','東郊驛樹連理枝，西廟叢篁十丈圍。',92,'全唐诗/poet.song.2000.json','["東郊驛樹連理枝，西廟叢篁十丈圍。", "堪將輕素命人畫，賫爲方物歸京師。", "公署石楠圓似蓋，畫樓北面當廳檜。", "桐谿怪石勝太湖，賤如泥土無人愛。", "天生彌材地且卑，空山老朽人不知。", "人不知，睦州右史作歌詞。"]'),
('3c76e598-9c54-408e-9351-0fdfa117d633','苦寒行','田錫','宋','宋诗','song-poetry','','[]','昨日北風高，霏霏滿天雪。',288,'全唐诗/poet.song.2000.json','["昨日北風高，霏霏滿天雪。", "千里六出花，六日飛不歇。", "深山深一丈，樹木凍欲折。", "平地盈數尺，布肆不成列。", "覆物生輝光，照人清皎潔。", "紫塞羣玉峰，滄溟白銀闕。", "篁竹爲琅玕，松風篩玉悄。", "官吏來參賀，物情亦感悅。", "瘴癘已消除，豐穰及時節。", "長吏因疾恚，請假來一月。", "病眼爲寒昏，風頭因冷發。", "湯藥厭服餌，酒肉悉罷輟。", "夾幕映重簾，爐茵與衾袍。", "祿粟不憂饑，帑俸無乏絕。", "江海主恩深，素餐心激切。", "兒童溫且飽，當風泝凜冽。", "朝索暖寒酒，暮須湯餠設。", "不知有饑寒，燈火夜暖熱。", "越人輕活計，舂稅供膏血。", "及至風雪時，日給多空竭。", "樵蘇與綱捕，負薪冰路滑。", "口噤無言語，股慄衣疏葛。", "藜藿不充饑，凍餓多不活。", "慚惶襦褲恩，徬徨空殞越。"]'),
('845480fd-04e0-4033-b74f-f69ad2a81a10','酬桐廬知縣刁衎歌','田錫','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','詔守江西新定郡，二年撫俗誰相問。',384,'全唐诗/poet.song.2000.json','["詔守江西新定郡，二年撫俗誰相問。", "白浪青山繞郡城，卧理煙霞稱嘉遯。", "帝鄉迢迢天一涯，子牟戀闕人不知。", "慷慨情懷何企慕，宋璟政事杜牧詩。", "六縣萬家人輯睦，魚鹽利人茶貨足。", "公家事簡案牘稀，芳草疏籬映空獄。", "楊柳湖邊觀釣魚，芙蓉池上靜看書。", "優游天爵浩然性，貴如三入承明廬。", "靖節先生來訪我，欣然延入皇堂坐。", "歛襟欲坐先發言，捧出尺書雙袖間。", "七軸好詞同跪授，儒雅禮豐情意厚。", "主人識鑒非延陵，金石何煩榮固陋。", "且置瓊瑶未暇看，高談如綺有餘歡。", "黄鸝百囀天欲暮，客去斜陽已半軒。", "焚香道院無人到，風花拂几收真誥。", "却取文編一一看，南朝體制多淵奧。", "兩軸七字五字詩，珠貫纍纍樂府詞。", "古於禪月畫羅漢，麗於范蠡進西施。", "議論精微窮理窟，賦詠升高能體物。", "一篇序送周子通，飄飄思若翻冥鴻。", "自有滄浪高尚志，因人命筆生詞鋒。", "嘗聞水國清輝殿，曾事吳王侍文宴。", "田園未遂歸去來，嚴子臺邊知一縣。", "古人窮則善一身，達則惠澤如陽春。"]'),
('552140ca-758c-4f1c-855a-758ab24412eb','贈別琅邪評事兼寄兩制舊交','田錫','宋','宋诗','song-poetry','','[]','醴泉少府王評事，秀氣神清好奇異。',348,'全唐诗/poet.song.2000.json','["醴泉少府王評事，秀氣神清好奇異。", "讀書擊劍善彈琴，仲容信是青雲器。", "我從蜀國來咸秦，長安久客多風塵。", "因此移居清渭北，與君在彼初相識。", "相識經今二十年，支離契闊長相憶。", "去年罷直西掖垣，君亦醴泉方解官。", "關中路遥宛丘道，不遠千里來相看。", "我忝淮陽知郡事，郡齋喜聞嘉客至。", "槐花橫時初到來，菊花開時言欲迴。", "主人苦留留不住，爲君采菊登高臺。", "高臺臨古道，北走還京秋已老。", "白日遠長安，西歸出關天已寒。", "神仙作尉道雖在，骨肉爲累心且寬。", "與君俱年五十一，老去時光轉堪惜。", "況今秋暮冬欲殘，七十唯餘十八年。", "未知十八年之間，悲歡得喪與險艱。", "到得七十即爲幸，此外浮生何足言。", "明日正逢重九日，未忍與君張祖席。", "樽前新菊含露滋，茱萸丹實星離離。", "茱萸擷芳菊延壽，壽酒滿滿莫固辭。", "淮陽郡吏若早替，帝鄉即有相見期。", "兩制交朋若相問，爲我勤勤多謝之。"]'),
('ed12eac5-c9a9-4c6a-ad1d-042d7b9a06a8','酬宋湜賈黄中二學士菊花之什兼呈諸廳學士','田錫','宋','宋诗','song-poetry','','[]','靖節先生曾賞菊，東籬有霜花正開。',376,'全唐诗/poet.song.2000.json','["靖節先生曾賞菊，東籬有霜花正開。", "翰林主人共賞菊，北門吟詠有餘才。", "一唱再和才力健，兼金酬以瑛瓊瑰。", "善歌使人繼其志，遠寄淮陽知郡吏。", "淮陽郡中方燕居，跪讀重緘尺素書。", "中有五章章八句，復有三章同一處。", "五章千葉菊花詞，一章副翰學士詩。", "一章酬和季左司。", "人前再讀與三復，人從日邊初到時。", "歛手先問諸學士，駭目乍闚文字奇。", "兩制別來今已久，朝寄苑丘權太守。", "眼底唯嫌簿領繁，耳冷不聞騷雅言。", "重陽錫宴不得與，湛露空思奉至尊。", "忽捧新詩若爲意，聞詩勝得千金賜。", "受知益感恩顧深，吟賞請言清麗致。", "清如玉樹生天風，麗若露花開錦宮。", "水精盤中置明月，絳火珊瑚枝葉紅。", "珍則難酬青玉案，文律詞鋒併化工。", "因事喻懷堪自惜，神化丹青與刀尺。", "丹青暈淡刀尺裁，先春雪中生早梅。", "春饒桃李及時發，牡丹占斷芳菲來。", "芍藥羞人嬌且妬，玫瑰倚欄笑欲語。", "帝里春從何處歸，巫山雨散朝雲飛。", "遺紅墮翠歸天下，不失年年三月期。"]'),
('d2f622e5-e7d6-47b1-9087-1cce00479f87','進瑞雪歌','田錫','宋','宋诗','song-poetry','','[]','聖德昭彰動天地，歲歲豐穰爲上瑞。',386,'全唐诗/poet.song.2000.json','["聖德昭彰動天地，歲歲豐穰爲上瑞。", "明年有閏節氣遲，冬深有雪方及時。", "三農但喜及時雪，天心帝力豈得知。", "臣忝頌條居近輔，勸課農桑理輿賦。", "宛丘之下爲封部，宣布皇恩愧襦褲。", "王澤流而有頌聲，因而拜手獻歌行。", "歌云歲云暮兮日云暮，白雲初向斜陽度。", "斜陽韜掩雲舒布，慘慘陰風生北戶。", "風來带得霏霏花，花輕片片如瓊葩。", "凍黏寒綴紛交加，陌上逡巡鋪玉沙。", "琪樹瑶臺相間出，落梅墮絮初堆積。", "映箔橫沾翡翠紋，拂窗斜度瑠璃隙。", "飄飄千里度龍山，袤丈蕭關與玉關。", "海上銀臺對金闕，水精簾櫳鑒明月。", "萬年枝上夜輝光，上林先似梨花發。", "黎元有望既滿望，手足舞之而蹈之。", "因思去歲在京師，國家將議改元時。", "時雪未呈盈尺瑞，百神奔走應禱祈。", "海風吹起澄江練，織女金刀碎裁剪。", "剪作天花撒翠微，茫茫六合生光輝。", "明月宮中玉臼杵，霜兔擣藥雲母飛。", "風篩乍似琅玕寶，翔鸞飛下啄瑶墀。", "金門廊廡龍尾道，賀雪千官趁朝早。", "吾皇爲喜表豐年，六出飛花不令掃。"]'),
('c2015473-075a-4b74-a3e9-ebb5d48b749a','留別句中正學士','田錫','宋','宋诗','song-poetry','','[]','玉人欲歸留不住，南山出雲作朝雨。',208,'全唐诗/poet.song.2000.json','["玉人欲歸留不住，南山出雲作朝雨。", "雨中却柅使車輪，主人重得延嘉賓。", "嘉賓有詩留別我，句句高奇字字新。", "新若新花凝宿露，高似秋天曉星布。", "奇於雲起成峰巒，鮫人淚珠盈玉盤。", "浪大月照如金線，金線交加珠可貫。", "玦離環合間珠圓，風生玉步聲珊珊。", "珍奇若此爲重賜，齋沐焚香然後看。", "三復吟看既忘倦，命筆和來才思緩。", "桃李難酬瓊玖珍，野老美芹聊贄獻。", "與君俱是錦江人，今幸星軺來過陳。", "鄉情交分忍輕別，少留可待早秋辰。", "秋光月華伴行色，步步隨君歸紫宸。"]'),
('d2401561-1e4c-43c4-9298-3fb0ecf5fdbe','代書呈蘇易簡學士希寵和見寄以便題之于郡齋也','田錫','宋','宋诗','song-poetry','','[]','金殿嘗聞金口言，詞臣官職是神仙。',384,'全唐诗/poet.song.2000.json','["金殿嘗聞金口言，詞臣官職是神仙。", "三年偶忝西垣職，致身似得文章力。", "感激思酬聖主恩，危言所以難緘默。", "出入金門與玉堂，屢因狂直拜封章。", "禦戎救旱無上策，言詞不足動君王。", "改官出職歸郎署，粉圍正秩慚叨據。", "仍命淮陽頒詔條，元正不得與趨朝。", "中書舍人捧寶策，加美徽稱尊帝堯。", "大明殿裏上壽酒，翰林學士先羣寮。", "獨有淮陽知郡吏，爲典郡符蒙借紫。", "閤門引謝正衙辭，撰日忽忽辦行李。", "都門柳色早春天，繁臺寺中排祖筵。", "離盃滿勸不惜醉，醉別上馬魂黯然。", "客心易感須如是，迴思故國三千里。", "子雲相如俱蜀人，我今五十君青春。", "春秋鼎盛正清貴，我年漸似下坡輪。", "下車猶未踰期月，官舍初經禁煙節。", "殘陽乍聽吹角聲，臺榭梨花簇香雪。", "獨酌不歡何所爲，孤懷無緒懷己知。", "十八學士相念否，應笑骨凡格且卑。", "地仙敢言謫仙宦，海槎却有上天時。", "陳州去京地不遠，莫惜音書來慰勉。", "若得工夫可作歌，歌中言語不厭多。", "畢三情旨頗似我，向二宋四及李大。"]'),
('a0bf82aa-0298-4553-bc72-5b20a6316d30','送韓援赴闕','田錫','宋','宋诗','song-poetry','','[]','逢君南浦落花時，送君南浦草離離。',288,'全唐诗/poet.song.2000.json','["逢君南浦落花時，送君南浦草離離。", "離魂自與白雲斷，兩槳去時乘夕暉。", "昔時漢家稱八使，登車便有澄清意。", "吾皇宵旰念黎民，歌詠皇華遣使臣。", "昭文館殿選學士，巡撫使名名號新。", "二人分得淮南道，人自日邊來既早。", "敷宣朝旨達君恩，淮陽父老私有言。", "言逢太平歌且舞，利病達聰皆悉聞。", "我昔南宮與西掖，後來謫宦爲遷客。", "慶澤量移往單州，長淮塗次泊孤舟。", "昌黎工部未相識，一見怡然如舊遊。", "詩酒論交各相許，何如李白杜工部。", "海上往來將月餘，煙波寄詩兼寄書。", "書裏情深若江漢，詩中意重若瓊琚。", "今說歸京忍輕別，別夜波光蕩明月。", "若到朝廷話鄙夫，爲說子牟心戀闕。", "闕下交游憶者誰，翰林蘇畢韓損之。", "憑君與達相思意，夢向金鑾欵北扉。"]'),
('74a0cdd6-76c3-4fab-b7a0-5cb7374916aa','思歸引','田錫','宋','宋诗','song-poetry','','[]','河朔受詔書，移官向湖外。',108,'全唐诗/poet.song.2000.json','["河朔受詔書，移官向湖外。", "初問禁法茶，次問丁身稅。", "稅口微四百，茶利高十倍。", "老死及充軍，縣籍方消退。", "采摘不入官，公家定科罪。", "何以升平時，遺民猶未泰。", "何以在位者，興利不除害。", "我願罷秩歸，天顔請轉對。", "一言如沃心，恩波必霶霈。"]'),
('9b43ce68-125a-4b64-bc75-e2ec5a27fa88','歸去來','田錫','宋','宋诗','song-poetry','','[]','歸去來，詩不云乎，王事一埤遺我兮。',178,'全唐诗/poet.song.2000.json','["歸去來，詩不云乎，王事一埤遺我兮。", "終日孜孜，心力疲勞齒髮衰。", "爾今已年五十二，前去七十幾多時。", "爾性雖拙頗好學，爾才雖短頗好詩。", "文學歌詩之外非樂爲。", "金門玉堂若無分，隨分官職胡不歸。", "苟能遣得婚嫁累，又何苦憂伏臘資。", "爾不聞仲尼曰，飯疏食飲水。", "曲肱而枕之，樂亦在其中，浮雲富貴非爾宜。", "表聖表聖，爾當念茲而在茲，勿使無其實而有其詞。", "爾若捨靈龜而觀朵頤，無乃見爾癡爾癡。"]'),
('c4ab1e81-79d2-4d8f-9f85-12423142a4f9','送僧歸天寧萬年禪院','田錫','宋','宋诗','song-poetry','','[]','帝里來朝謁，林泉却憶歸。',48,'全唐诗/poet.song.2000.json','["帝里來朝謁，林泉却憶歸。", "得詩從史閣，掃石向巖扉。", "雲伴離丹闕，猿窺換紫衣。", "天台壽昌寺，山水有光輝。"]'),
('3858f1aa-cb20-48dd-9a47-f630fb15df5f','望西林寺','田錫','宋','宋诗','song-poetry','','[]','憶昔嘉州歲已周，西林僧舍未曾遊。',32,'全唐诗/poet.song.2000.json','["憶昔嘉州歲已周，西林僧舍未曾遊。", "可憐遥見如圖畫，竹箐南邊露寺樓。"]'),
('836c722b-fd03-4e48-b938-fc02b1343784','句  其一','田錫','宋','宋诗','song-poetry','','[]','下車逢歲歲旱，禱廟望秋成。',37,'全唐诗/poet.song.2000.json','["下車逢歲歲旱，禱廟望秋成。", "火輪轉曈矓，赤日彌高明。", "稻苗已枯死，麥壠不堪耕。"]'),
('2181f48c-83af-479a-b0df-806de87f34a6','句  其二','田錫','宋','宋诗','song-poetry','','[]','自知不是明時用，爛額焦頭力謾多。',16,'全唐诗/poet.song.2000.json','["自知不是明時用，爛額焦頭力謾多。"]'),
('cad7702a-be64-4774-8ce5-10a840f7333b','句  其三','田錫','宋','宋诗','song-poetry','','[]','郭璞書臺古釣灣。',8,'全唐诗/poet.song.2000.json','["郭璞書臺古釣灣。"]'),
('82c586d7-6be5-4e5a-8350-dc965bd90992','句  其四','田錫','宋','宋诗','song-poetry','','[]','高高百里一屈盤，八十四盤青雲端。',16,'全唐诗/poet.song.2000.json','["高高百里一屈盤，八十四盤青雲端。"]'),
('2524f5f9-404d-4e05-82db-0bb94b8cceb1','句  其五','田錫','宋','宋诗','song-poetry','','[]','諸峰居蜀右，夕翠染巴東。',12,'全唐诗/poet.song.2000.json','["諸峰居蜀右，夕翠染巴東。"]'),
('c62ec91a-b384-49a1-9669-2a3602a9e74d','伏睹禁林盛事謹賦一章','賈黄中','宋','宋诗','song-poetry','','[]','璇題飛白御毫新，三體瓊章妙入神。',96,'全唐诗/poet.song.2000.json','["璇題飛白御毫新，三體瓊章妙入神。", "特賜禁林爲盛事，只緣明主重名臣。", "青編輝映輕前古，丹地深嚴隔世塵。", "金籙禎祥非是寶，玉堂名號此方貞。", "恩榮誰比烟霄客，文彩長懸日月輪。", "爲報鼇宮主人道，蓬萊全勝昔時春。"]'),
('ecc707dd-da37-4eab-8bb3-88fc3207e58a','桂林還珠洞','賈黄中','宋','宋诗','song-poetry','','[]','赫赫威聲震百蠻，昔携筐筥溷谿山。',32,'全唐诗/poet.song.2000.json','["赫赫威聲震百蠻，昔携筐筥溷谿山。", "無人爲起文淵問，端的珠還薏苡還。"]'),
('476bd021-3385-4995-8552-19e72b81b479','吟貽宣議大師英上人','賈黄中','宋','宋诗','song-poetry','','[]','金僊子便是師師，高道寧容世綱羈。',64,'全唐诗/poet.song.2000.json','["金僊子便是師師，高道寧容世綱羈。", "浩浩心田龍可擾，飄飄行止鶴應知。", "塵機擺落超三界，古篆沉研冠一時。", "莫怪伊余苦珍重，白蓮花社有心期。"]'),
('27f016c2-5680-412a-bf80-bed14a9b84ac','送新知永州潘宮贊若沖赴任','賈黄中','宋','宋诗','song-poetry','','[]','鴛鷺行中已著名，頌條暫慰遠民情。',64,'全唐诗/poet.song.2000.json','["鴛鷺行中已著名，頌條暫慰遠民情。", "道途行去乘軺貴，鄉里過時畫錦榮。", "鈴閣曉開江月滿，戟枝寒照雪峰明。", "知君游刃多餘暇，莫忘新詩寄鳳城。"]'),
('268b4055-3454-4449-83d3-64ed52d46002','題華林書院','賈黄中','宋','宋诗','song-poetry','','[]','旌陽舊山曲，書室構山前。',48,'全唐诗/poet.song.2000.json','["旌陽舊山曲，書室構山前。", "景物塵埃外，軒窗樹石邊。", "寧惟集儒業，兼恐混神僊。", "百行家門最，宜當世有賢。"]'),
('e92e6a0b-310d-4a9f-b229-b4b75db5187d','釣臺  其一','劉昌言','宋','宋诗','song-poetry','','[]','漢業中微炎祚衰，四海姦豪竊神器。',144,'全唐诗/poet.song.2000.json','["漢業中微炎祚衰，四海姦豪竊神器。", "南陽龍虎方鬭爭，赤伏真人正天位。", "先生高隠來富春，耕耒青山自如意。", "一竿漁釣樂幽深，七里溪光弄蒼翠。", "朝中天子思故人，物色寰中引其類。", "先生獨步衣羊裘，咳唾浮雲輕富貴。", "足加帝腹傍無人，星動天文失躔次。", "卓哉光武真聖君，終使狂奴畢高志。", "雲臺千尺盡功臣，誰肯回顧釣臺地。"]'),
('990b32be-925d-49d4-aff8-bd423e53ade9','釣臺  其二','劉昌言','宋','宋诗','song-poetry','','[]','不會持竿意，由來善一身。',48,'全唐诗/poet.song.2000.json','["不會持竿意，由來善一身。", "何如事天子，就削漢功臣。", "亂木凋雲際，幽禽散水濱。", "空餘臺下月，千載屬漁人。"]'),
('2ddf792b-9d12-4b96-aa92-7c585a577821','上呂相公','劉昌言','宋','宋诗','song-poetry','','[]','重名清望徧華夷，恐是神仙不可知。',64,'全唐诗/poet.song.2000.json','["重名清望徧華夷，恐是神仙不可知。", "一舉首登龍虎榜，十年身到鳳凰池。", "廟堂只是無言者，門館長如未貴時。", "除却洛京居守外，聖朝賢相復書誰。"]'),
('6af42358-faea-4b7a-ba22-7888674a0ee5','句','劉昌言','宋','宋诗','song-poetry','','[]','惟有夜來蝴蝶夢，翩翩飛入刺桐花。',16,'全唐诗/poet.song.2000.json','["惟有夜來蝴蝶夢，翩翩飛入刺桐花。"]'),
('7867ac00-4d8d-417a-8cb7-cefa5088ec27','句','趙宗萬','宋','宋诗','song-poetry','','[]','斗懸金印心難動，屏列春山眼暫開。',16,'全唐诗/poet.song.2000.json','["斗懸金印心難動，屏列春山眼暫開。"]'),
('1fbe5abb-291d-47a9-abf3-a3bd4a246aa8','偈','釋祖印','宋','宋诗','song-poetry','','[]','昔日南泉親斬却，今朝耶舍示玄徒。',32,'全唐诗/poet.song.2000.json','["昔日南泉親斬却，今朝耶舍示玄徒。", "而今賣與諸禪客，文契分明要也無。"]'),
('35543423-64f3-47b2-a8c6-0248816798e8','喜宣義大師英公相訪','陳文顥','宋','宋诗','song-poetry','','[]','三事天衣兩字師，長安風月更誰知。',64,'全唐诗/poet.song.2000.json','["三事天衣兩字師，長安風月更誰知。", "閑騎劣馬尋碑去，醉卧荒廬出寺遲。", "辭贍不容誇犬子，興闌兼許吐魚兒。", "左馮假道來看我，正值嚴冬大雪時。"]'),
('747dc3fe-18b5-454d-8aa9-564b93b2c490','題太平興國寺壁','老妓','宋','宋诗','song-poetry','','[]','曾趁東風看幾巡，冒霜開喚滿城人。',32,'全唐诗/poet.song.2000.json','["曾趁東風看幾巡，冒霜開喚滿城人。", "殘脂剩粉憐猶在，欲向彌陀借小春。"]'),
('b9cb4561-2f7c-401b-ae61-c34a3aa72cbc','過衡山留贈廖融','張觀','宋','宋诗','song-poetry','','["\u8861\u5c71"]','未向漆園爲傲吏，定應明代作徵君。',64,'全唐诗/poet.song.2000.json','["未向漆園爲傲吏，定應明代作徵君。", "家傳奕世無金玉，樂道經年有典墳。", "带雨小舟橫別澗，隔花幽犬吠深雲。", "到頭終爲蒼生起，休戀耕煙楚水濆。"]'),
('7e9eec97-656d-44bc-9fe1-08a6915b57d5','留題古松','錢昱','宋','宋诗','song-poetry','','[]','景致逼神仙，心幽道亦玄。',48,'全唐诗/poet.song.2000.json','["景致逼神仙，心幽道亦玄。", "僧閒來出世，松老不知年。", "放馬眠岩草，移盃酌澗泉。", "浮名如脫得，終住此雲邊。"]'),
('923a90b2-0ef9-4552-9a39-f382b56f49a6','昇山靈巖寺','錢昱','宋','宋诗','song-poetry','','[]','杉松滿寺廊，欄檻倚高岡。',48,'全唐诗/poet.song.2000.json','["杉松滿寺廊，欄檻倚高岡。", "郡郭曉雲漠，禪齋春草長。", "澗青連竹色，山靜带茶香。", "更有名僧在，茅庵住上方。"]'),
('a1504892-aa5d-46de-ab1b-5bb3d16dbdb2','留題巾山明慶塔院','錢昱','宋','宋诗','song-poetry','','[]','數級崔嵬萬木中，最堪影勢似難同。',64,'全唐诗/poet.song.2000.json','["數級崔嵬萬木中，最堪影勢似難同。", "欄桿夜壓江心月，鈴鐸秋摇嶽頂風。", "重疊畫簷遮世界，稀疏清磬徹虛空。", "有時問著禪僧路，笑指丹霄去不窮。"]'),
('0f56babe-2c93-4c3b-86f1-015f92f554a0','致仕後戲贈故人','張齊賢','宋','宋诗','song-poetry','','[]','午橋今得晉公廬，花竹烟雲興有餘。',32,'全唐诗/poet.song.2000.json','["午橋今得晉公廬，花竹烟雲興有餘。", "師亮白頭心已足，四登兩府九尚書。"]'),
('dbabe7ce-6fa1-45f4-beb8-9961f3b8288c','自警詩','張齊賢','宋','宋诗','song-poetry','','[]','慎言渾不畏，忍事又何妨。',48,'全唐诗/poet.song.2000.json','["慎言渾不畏，忍事又何妨。", "國法須遵守，人非莫舉揚。", "無私仍克己，直道更和光。", "此箇如端的，天應降吉祥。"]'),
('3170d251-09ed-4683-ac25-8fb6d30ed8fe','華清宮','張齊賢','宋','宋诗','song-poetry','','[]','當時不是不窮奢，民樂昇平少嘆嗟。',32,'全唐诗/poet.song.2000.json','["當時不是不窮奢，民樂昇平少嘆嗟。", "姚宋未亡妃子在，塵埃那得到中華。"]'),
('3a32b78a-91cd-4e67-9541-e13a3e78445f','豫章胡氏華林書堂','張齊賢','宋','宋诗','song-poetry','','[]','一百年來烟爨同，衣冠江左慕家風。',64,'全唐诗/poet.song.2000.json','["一百年來烟爨同，衣冠江左慕家風。", "兒孫歌舞詩書內，鄉黨優游禮讓中。", "孝弟筠編爭紀錄，門閭天語賜褒崇。", "莫將六闕方朱氏，葉葉蒸嘗奉始終。"]'),
('e1e5f35d-77ad-4ca0-8736-fd259855900a','御書飛白玉堂之署三體宸章併宣禁苑睹茲盛事輒動斐然','張齊賢','宋','宋诗','song-poetry','','[]','寵深仙署降新牌，御筆親題重俊才。',96,'全唐诗/poet.song.2000.json','["寵深仙署降新牌，御筆親題重俊才。", "四字千齡懸日月，兩篇三體琢瓊環。", "登科郄桂皆同樹，入室丘門盡仰回。", "寓直靜封芝檢去，密宣榮對玉泉來。", "職清望峻人稀見，地貴扃嚴畫罕開。", "多幸謬持黄閣柄，烟霄時得遂游陪。"]'),
('c3899228-62f8-40e2-a23c-31882420aef7','答西京留守惠花酒','張齊賢','宋','宋诗','song-poetry','','[]','有花無酒頭慵舉，有酒無花眼倦開。',32,'全唐诗/poet.song.2000.json','["有花無酒頭慵舉，有酒無花眼倦開。", "好是西園無事日，洛陽花酒一齊來。"]'),
('01388bb3-08d9-4b88-bc52-6333a3c19aac','石將軍南征賦贈','張齊賢','宋','宋诗','song-poetry','','[]','五花密布生門出，三令重宣夙將聽。',64,'全唐诗/poet.song.2000.json','["五花密布生門出，三令重宣夙將聽。", "劃地豈能容賊窟，指天不許見妖星。", "醪投漢水期分飲，石削巴丘待勒銘。", "洗盡甲兵安草木，君山依舊望中青。"]'),
('9eacf87c-550d-4efa-bb83-736faafb20ec','贈賀蘭棲真','張齊賢','宋','宋诗','song-poetry','','[]','日耕雲耨雜芝田，洞府遊多隠奉仙。',64,'全唐诗/poet.song.2000.json','["日耕雲耨雜芝田，洞府遊多隠奉仙。", "聳秀萬尋連翠嶠，澄明一派接靈泉。", "鳳書昔降幽居側，鶴駕曾朝瑞日邊。", "四海高名誰可並，赤松黄石好齊眉。"]'),
('6e0f9b30-2fd5-4da3-a274-445d5b000c04','偈','釋警玄','宋','宋诗','song-poetry','','[]','我昔初機學道迷，萬水千山覓見知。',64,'全唐诗/poet.song.2000.json','["我昔初機學道迷，萬水千山覓見知。", "明今辨古終難會，直說無心轉更疑。", "蒙師點出秦時鏡，照見父母未生時。", "如今覺了何所得，夜放烏雞带雪飛。"]'),
('50c1f1bd-5d5c-4299-a4dd-982973043dec','偈','釋警玄','宋','宋诗','song-poetry','','[]','撒手那邊千聖外，祖堂少室長根芽。',32,'全唐诗/poet.song.2000.json','["撒手那邊千聖外，祖堂少室長根芽。", "鷺倚雪巢猶自可，更看白馬入蘆花。"]'),
('575744a0-b7c7-4d38-937f-910ff252909e','偈','釋警玄','宋','宋诗','song-poetry','','[]','夜半鳥雞抱鵠卵，天明起來生老鸛。',58,'全唐诗/poet.song.2000.json','["夜半鳥雞抱鵠卵，天明起來生老鸛。", "鶴毛鷹觜鷺鸞身，却共烏鴉爲侶伴。", "高入煙霄，低飛柳岸。", "向晚歸來子細看，依稀恰似雲中雁。"]'),
('ad1315f1-4f49-47d2-9866-2861cfbc18b7','寄浮山遠禪師','釋警玄','宋','宋诗','song-poetry','','[]','楊廣山頭草，憑君待價焞。',24,'全唐诗/poet.song.2000.json','["楊廣山頭草，憑君待價焞。", "異苗翻茂處，深密固靈根。"]'),
('107780af-d424-48c8-aec1-8bb6f5622038','寄侍郎五曙偈','釋警玄','宋','宋诗','song-poetry','','[]','吾年八十五，修因至於此。',24,'全唐诗/poet.song.2000.json','["吾年八十五，修因至於此。", "問我歸何處，頂相終難睹。"]'),
('d246cc52-b2fd-4ab0-8877-9d8aa5c3cd8c','句  其一','釋警玄','宋','宋诗','song-poetry','','[]','贏鶴老猿啼谷韻，瘦松寒竹鎖青烟。',16,'全唐诗/poet.song.2000.json','["贏鶴老猿啼谷韻，瘦松寒竹鎖青烟。"]'),
('b071d41e-e932-47b6-9324-2e3058905fb2','句  其二','釋警玄','宋','宋诗','song-poetry','','[]','大洋海底紅塵起，須彌頂上水橫流。',16,'全唐诗/poet.song.2000.json','["大洋海底紅塵起，須彌頂上水橫流。"]'),
('771392ea-b556-4534-b5a7-1f7bb3b52102','句  其三','釋警玄','宋','宋诗','song-poetry','','[]','白雲覆青山，青山頂不露。',12,'全唐诗/poet.song.2000.json','["白雲覆青山，青山頂不露。"]'),
('0e1ef6cb-ce75-4f41-9e4c-83cd72474864','句  其四','釋警玄','宋','宋诗','song-poetry','','[]','寶殿無人不侍立，不種梧桐免鳳來。',16,'全唐诗/poet.song.2000.json','["寶殿無人不侍立，不種梧桐免鳳來。"]'),
('84703f24-9209-46ae-a041-d09ff8642551','句  其五','釋警玄','宋','宋诗','song-poetry','','[]','白牛吐雪彩，黑馬上烏雞。',12,'全唐诗/poet.song.2000.json','["白牛吐雪彩，黑馬上烏雞。"]'),
('5dd0df59-7b64-415e-9349-a21915a46092','奉贈宣義大師英公','李若拙','宋','宋诗','song-poetry','','["\u8861\u5c71"]','昔歲高名動九重，衡山別後碧雲空。',64,'全唐诗/poet.song.2000.json','["昔歲高名動九重，衡山別後碧雲空。", "紫袍親受龍墀上，白足頻登虎殿中。", "小篆每輕秦相法，隸書猶鄙晉臣功。", "多才多藝如師少，當世羣賢盡響風。"]'),
('2ea03a6d-3d3b-4745-bbe7-6c7df1ac96c6','句','李若拙','宋','宋诗','song-poetry','','[]','家寄碧湘濱。',6,'全唐诗/poet.song.2000.json','["家寄碧湘濱。"]'),
('9b94f0ac-8ab0-475c-a0f9-b44e2c81ad4e','送僧歸護國寺  其一','王化基','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','振錫詣華京，頻頻答龍靈。',96,'全唐诗/poet.song.2000.json','["振錫詣華京，頻頻答龍靈。", "玉階前見佛，金口內開經。", "論道窮綱賾，深玄極杳冥。", "褒崇恩爛熳，教化語丁寧。", "傳作心中印，鎸爲坐右銘。", "雲飛來北闕，鶴夢去東冥。", "鼓棹辭梁苑，揚帆過洞庭。", "到山開御札，鸞鳳滿巖扃。"]'),
('08029a2b-4dd8-4ac0-b9fb-c9f3b415e6f9','送僧歸護國寺  其二','王化基','宋','宋诗','song-poetry','','[]','巋然傍勢浙江東，不羨金庭第一峰。',64,'全唐诗/poet.song.2000.json','["巋然傍勢浙江東，不羨金庭第一峰。", "法境常清五十里，妙蓮今現幾千重。", "清凉解洗枝頭露，變現能飛鉢底龍。", "平日舊遊今復到，蒼崖邃谷抱長松。"]'),
('17004c5b-e7d9-4471-98c7-3b8adfd0a9aa','句  其一','王化基','宋','宋诗','song-poetry','','[]','美璞未成終是寶，精鋼寧折不爲鉤。',16,'全唐诗/poet.song.2000.json','["美璞未成終是寶，精鋼寧折不爲鉤。"]'),
('1a9055f8-46ea-45a5-a3b9-f1e014127530','句  其二','王化基','宋','宋诗','song-poetry','','[]','文章換桂一枝秀，清白傳家兩弟貧。',16,'全唐诗/poet.song.2000.json','["文章換桂一枝秀，清白傳家兩弟貧。"]'),
('95d6bdef-02b0-4165-afd3-62f7da30e95c','句  其一','陳充','宋','宋诗','song-poetry','','[]','密葉高叢擁萬枝，女仙成隊綠雲隨。',16,'全唐诗/poet.song.2000.json','["密葉高叢擁萬枝，女仙成隊綠雲隨。"]'),
('dbd470ce-eb14-42ee-b0d6-c859adeb2176','句  其二','陳充','宋','宋诗','song-poetry','','[]','掩戶閑欹枕。',6,'全唐诗/poet.song.2000.json','["掩戶閑欹枕。"]'),
('4f9e4e41-3ea2-4e9b-a96a-292e0e9a123c','題關右寺壁','王嗣宗','宋','宋诗','song-poetry','','[]','欲掛衣冠神武門，先尋水竹渭南村。',32,'全唐诗/poet.song.2000.json','["欲掛衣冠神武門，先尋水竹渭南村。", "却將舊斬樓蘭劍，買得黄牛教子孫。"]'),
('ef3bffbb-9fbd-4344-ba9f-2c33c70947ea','句','王嗣宗','宋','宋诗','song-poetry','','[]','惡人須用大枷枷。',8,'全唐诗/poet.song.2000.json','["惡人須用大枷枷。"]'),
('c2c44ee8-aedf-480c-9a03-c2924e7244ba','聞墮薪有省作偈','釋洪壽','宋','宋诗','song-poetry','','[]','撲落非他物，縱橫不是塵。',24,'全唐诗/poet.song.2000.json','["撲落非他物，縱橫不是塵。", "山河及大地，全露法王身。"]'),
('8055bf35-f955-4c29-b706-f20eb9212fd3','喜英公大師相訪','趙昌言','宋','宋诗','song-poetry','','[]','僧中何事最聞名，筆札高奇是夢英。',63,'全唐诗/poet.song.2000.json','["僧中何事最聞名，筆札高奇是夢英。", "十八家書垂墨妙，一千年聖遇文明。", "未將六籍重刊石，已駕三車到化城。", "此日勞師相枉訪，豁然抱慰平生。"]'),
('1d1fdb4e-3ce4-4ad5-85eb-54355153a72a','代意','刁衎','宋','宋诗','song-poetry','','[]','蕙時芳夕九回腸，斂袂東窗待曉光。',64,'全唐诗/poet.song.2000.json','["蕙時芳夕九回腸，斂袂東窗待曉光。", "秦嶺樹高迷隴塞，楚天雲淡隔瀟湘。", "病餘公斡情多詠，秋晚安仁鬢足霜。", "休道鮫人落珠淚，微波還擬託陳王。"]'),
('2b5ca1e7-1ee5-40fd-b7e9-7173875e19ad','漢武','刁衎','宋','宋诗','song-poetry','','[]','高宴柏梁詞可仰，橫汾簫鼓樂難窮。',64,'全唐诗/poet.song.2000.json','["高宴柏梁詞可仰，橫汾簫鼓樂難窮。", "已教丞相開東閣，猶使將軍誤北戎。", "灑淚甘泉還有恨，祈年仙館惜成空。", "誰知辛苦回中道，共盡千齡五柞宮。"]'),
('93892dc1-8440-4654-b4e4-c16d5a596ccd','夢中詩','刁衎','宋','宋诗','song-poetry','','[]','聖朝文物古難過，何事寒門寵遇多。',64,'全唐诗/poet.song.2000.json','["聖朝文物古難過，何事寒門寵遇多。", "父向石渠新拜職，子從金殿又登科。", "須教枚馬暫蹤跡，堪笑巢由隠薜蘿。", "報國報君何所有，一心待欲枕長戈。"]'),
('bdadcfcc-9652-49e1-b75b-8968c1698879','題義門胡氏華林書院','刁衎','宋','宋诗','song-poetry','','[]','沙井地多異，華林景最幽。',96,'全唐诗/poet.song.2000.json','["沙井地多異，華林景最幽。", "溪聲常到枕，山色正含秋。", "樹密苔封徑，庭虛月滿樓。", "清癯光累世，高義集名流。", "孝弟家風貴，兒孫學業優。", "皇恩特表重，朝達咏扁留。", "精溢千鐘祿，榮過萬戶侯。", "宦途慚未息，何日遂經遊。"]'),
('20a6a4fc-3a3d-49dd-8294-7d1f82c94758','杭州望湖樓','李建中','宋','宋诗','song-poetry','','[]','小艇閑撐處，湖天景物微。',48,'全唐诗/poet.song.2000.json','["小艇閑撐處，湖天景物微。", "春波無限綠，白鳥自由飛。", "落日孤汀遠，輕煙古寺稀。", "時携一壺酒，戀到晚凉歸。"]'),
('0e10fafa-a0d4-4792-a030-aeadd7efaac2','題洛陽寺壁','李建中','宋','宋诗','song-poetry','','[]','杉松倒澗雪霜乾，屋壁麝煤風雨寒。',32,'全唐诗/poet.song.2000.json','["杉松倒澗雪霜乾，屋壁麝煤風雨寒。", "我亦平生有書癖，一回入寺一回看。"]'),
('19e80c68-416b-4fce-8aa4-e3bd0e78197e','懷湘南舊游寄起居劉學士','李建中','宋','宋诗','song-poetry','','[]','老情詩思關何處，渾是湘南水岸頭。',64,'全唐诗/poet.song.2000.json','["老情詩思關何處，渾是湘南水岸頭。", "殘白晚雲歸嶽麓，濃香秋菊滿汀洲。", "靜尋綠徑煎茶寺，徧上紅牆賣酒樓。", "西洛分臺素拘檢，繡衣不得等閑遊。"]'),
('fe9b22a7-3b5e-49fc-9771-b6abfff56610','題洛陽觀音院牡丹  其一','李建中','宋','宋诗','song-poetry','','[]','微動風枝生麗態，半開檀口露濃香。',32,'全唐诗/poet.song.2000.json','["微動風枝生麗態，半開檀口露濃香。", "秦時避世宮娥老，舊日顔容舊日妝。"]'),
('c3dca42d-7b09-4216-b9fc-5dc80bce90d5','題洛陽觀音院牡丹  其二','李建中','宋','宋诗','song-poetry','','[]','花譜名將第一論，洛中最是此花繁。',32,'全唐诗/poet.song.2000.json','["花譜名將第一論，洛中最是此花繁。", "不當更道木芍藥，枝上恐傷妃子魂。"]'),
('887c5c41-25d3-4630-93eb-cbde5dc6c351','題菩提寺','李建中','宋','宋诗','song-poetry','','[]','龍門雙闕湧雲煙，雪未飛花雁下前。',32,'全唐诗/poet.song.2000.json','["龍門雙闕湧雲煙，雪未飛花雁下前。", "徹底清流照車馬，分臺御史過伊川。"]'),
('6cbe3955-1769-4316-aaba-d2ea9c56116b','澹山巖','李建中','宋','宋诗','song-poetry','','[]','常思羽衣人，宅此巖崖傍。',192,'全唐诗/poet.song.2000.json','["常思羽衣人，宅此巖崖傍。", "□□通大道，玄關掩中黄。", "古朴宮殿□，偃亞松桂香。", "洞戶漏夕月，木罅生□陽。", "疊齒上層巔，露井連曲房。", "斷壁廣橫幕，矗石排吟□。", "蟄痕燕穴空，乳溜虬鱗張。", "清泉弄春□，靈草經冬芳。", "自笑老倒容，誰□刀圭霜。", "金版佩上籍，玉音歌洞章。", "□□夜森立，絳節朝飛揚。", "咫尺仙路高，喧囂機世忙。", "浮埃走車馬，奔迸多事場。", "真地擁烟霞，根本無爲鄉。", "不到久歎息，一來徒悲傷。", "但聽鏗華鐘，所得心耳凉。"]'),
('83307287-c1e5-4c5d-8802-d978f980ff4f','直宿','李建中','宋','宋诗','song-poetry','','[]','春風夜急銅龍漏，淡月半斜金井闌。',32,'全唐诗/poet.song.2000.json','["春風夜急銅龍漏，淡月半斜金井闌。", "已覺亞枝花露重，宿鶑猶睡怯餘寒。"]'),
('2ec0933e-d9fd-4b03-9981-86fbbf6731de','早朝','李建中','宋','宋诗','song-poetry','','[]','著衣香重海棠風，人在瀛洲御苑東。',32,'全唐诗/poet.song.2000.json','["著衣香重海棠風，人在瀛洲御苑東。", "將對赤墀班未定，井斡樓角且先紅。"]'),
('95211e2f-86c4-404e-bb2b-5f0b5c254347','白鶴山','李建中','宋','宋诗','song-poetry','','[]','玉簫峰下仙君宅，一樹岩花幾百春。',32,'全唐诗/poet.song.2000.json','["玉簫峰下仙君宅，一樹岩花幾百春。", "當日會稽王內史，如何不見竹間人。"]'),
('7b9d2be6-e3dd-4cb6-a6de-efa0f7a702cb','送張無夢歸天台','李建中','宋','宋诗','song-poetry','','[]','紫殿謁宸極，赤城歸舊山。',48,'全唐诗/poet.song.2000.json','["紫殿謁宸極，赤城歸舊山。", "氣清玄鶴下，語淡白雲閒。", "路入翠微外，巖栖瀑布間。", "何當一携手，相與語靈關。"]'),
('2da9566d-fc98-4e66-80f5-94b63d31397c','福聖觀','李建中','宋','宋诗','song-poetry','','[]','永懷閒訪道，斗上上仙居。',48,'全唐诗/poet.song.2000.json','["永懷閒訪道，斗上上仙居。", "瀑水磬聲外，桂花林影疏。", "山名孫綽賦，觀額葛玄書。", "已負秋來約，誅茅興有餘。"]'),
('5e2a0c75-15c0-40c4-bbc1-71d83d6823d4','郡齋偶書寄同院彭城學士兼簡兵部同年采覽','李建中','宋','宋诗','song-poetry','','[]','閒情閒憶事如空，靜讀離騷向郡中。',64,'全唐诗/poet.song.2000.json','["閒情閒憶事如空，靜讀離騷向郡中。", "冠劍老年傷遠別，關訶夜月許相同。", "晚花天氣孤莊雨，流水人間小閣風。", "行樂及時聊强飲，不須嫌作白頭翁。"]'),
('306f693a-ee36-4682-aa6d-425624651563','奉酬楊少監見寄退居遣興之什','李建中','宋','宋诗','song-poetry','','[]','賢哲道相扶，經綸本近侍。',156,'全唐诗/poet.song.2000.json','["賢哲道相扶，經綸本近侍。", "風雲如有會，霄漢寧無志。", "月窟桂抱林，粉闈丹漆地。", "一何華給束，而謂浮名遂。", "堆積圖史書，朝昏鉛槧事。", "登瀛才力劣，對問神魂愧。", "步驟古人蹤，含虛郡子器。", "獻言既無狀，出守連移次。", "持憲懷真剛，退藏生寤寐。", "欲邀丘壑老，靜坐樵魚帥。", "顥氣留丹田，尺宅分品位。", "寥寥洞府境，落落煙霞意。", "金簡題上青，與茲塵土異。"]'),
('f3e7a086-7011-4be4-8434-f8b00ba120e2','春盡偶書七言四韻奉承采覽','李建中','宋','宋诗','song-poetry','','[]','粉闈丹地白頭深，書殿分廊寓直人。',64,'全唐诗/poet.song.2000.json','["粉闈丹地白頭深，書殿分廊寓直人。", "不怕花枝驚老眼，可無詩句送殘春。", "因嗟紅影隨風去，猶爲青叢遶檻頻。", "更把華燈照深夜，一年情味隔音塵。"]'),
('035f2fc4-c577-441e-bf39-b90b798da9c7','題仙都山','李建中','宋','宋诗','song-poetry','','[]','巖巖仙都山，肅肅黄帝宮。',168,'全唐诗/poet.song.2000.json','["巖巖仙都山，肅肅黄帝宮。", "巨石臨廣澤，千仞凌高穹。", "肇當融結初，全得造化功。", "深可蟠厚壤，峭疑接冥鴻。", "雲軿去路存，丹鼎遺跡空。", "抽潤草心碧，敷香蓮葉紅。", "升龍扳矯矯，飛鳳鳴噰噰。", "而我集仙署，嘗比瀛洲雄。", "星移婺女間，鳳駕析木東。", "到覺毛骨爽，坐如羽翼沖。", "萬事皆氛埃，一氣歸鴻濛。", "遐哉上聖道，貌與元化同。", "金簡奠至誠，玉書銘代工。", "功成解冠劍，棲息期此中。"]'),
('aa4dedcc-ff83-49aa-b2f9-08a4e3451f66','寄英公大師','李建中','宋','宋诗','song-poetry','','[]','往歲瀟湘一相見，詩成野逸筆狂顛。',32,'全唐诗/poet.song.2000.json','["往歲瀟湘一相見，詩成野逸筆狂顛。", "近聞歸住長安寺，松老書窗又歲年。"]'),
('22fdb344-2532-41d4-9d4a-99a0d8ab59c5','開垣曲山路成','李建中','宋','宋诗','song-poetry','','[]','爲郡同卧理，民情識我情。',240,'全唐诗/poet.song.2000.json','["爲郡同卧理，民情識我情。", "三秋得公事，一月遶山行。", "砥柱全拋險，黄河日接平。", "周遭到垣曲，尊大近神京。", "借助林鹽潤，增饒國計成。", "虞州訪遺跡，吳坂念長鳴。", "董澤蒲侵綠，巫咸水傍清。", "人懷絳縣老，地嘆夏臺傾。", "下馬聽泉發，登原待月生。", "盤桓讀碑版，扶持立刀兵。", "晚靄聞鐘斷，微陽喜雨晴。", "峭空崖背落，斗截嶺西橫。", "仙恐臨王屋，高疑見析城。", "去車知軌轍，連畝有農耕。", "彩錯翻朝旆，錚鏦擊夜鉦。", "鑿開青石壁，填貯白雲坑。", "舊幕憐才俊，嘉言許道亨。", "何當議險阻，始信說分明。", "不倦共廉使，常存濟物誠。", "計時聊就筆，千古愧題名。"]'),
('39d6e848-f0b0-458a-9b17-7a2f10b81c94','題義門胡氏華林書院','李建中','宋','宋诗','song-poetry','','[]','山繞華林氣象和，此心猶恨未相過。',64,'全唐诗/poet.song.2000.json','["山繞華林氣象和，此心猶恨未相過。", "門閭世表曾顔德，榜帖人登晁董科。", "春暖花開飄几硯，晚歸雲影在松蘿。", "公卿無限新詩什，雅詠悠然地益□。"]'),
('a18b70d1-4312-4be6-861e-0cc44810aabd','句  其一','李建中','宋','宋诗','song-poetry','','[]','山程授館聞鴻夜，水國還家欲雪天。',16,'全唐诗/poet.song.2000.json','["山程授館聞鴻夜，水國還家欲雪天。"]'),
('3bfef3a1-0065-49ae-b4bf-92ba546606af','句  其二','李建中','宋','宋诗','song-poetry','','[]','漲煙春氣重，貯月夜痕深。',12,'全唐诗/poet.song.2000.json','["漲煙春氣重，貯月夜痕深。"]'),
('a4e92b10-c4af-440b-a9cd-f5bd52a23726','句  其三','李建中','宋','宋诗','song-poetry','','[]','故宮芳草在，往事暮江流。',12,'全唐诗/poet.song.2000.json','["故宮芳草在，往事暮江流。"]'),
('fa613dc7-00f4-4e45-9550-684cd1b5889f','句  其四','李建中','宋','宋诗','song-poetry','','[]','頻年水國飫鮭魚。',8,'全唐诗/poet.song.2000.json','["頻年水國飫鮭魚。"]'),
('c7623837-2b1c-4cd6-a330-e1fd8125fc55','句  其五','李建中','宋','宋诗','song-poetry','','[]','睛山雲罨畫，孤嶼水含稜。',12,'全唐诗/poet.song.2000.json','["睛山雲罨畫，孤嶼水含稜。"]'),
('d60d5e8b-edda-4f5e-b658-af7917d9fa15','句  其六','李建中','宋','宋诗','song-poetry','','[]','按部先春鳳林野，寫懷空望鹿門山。',16,'全唐诗/poet.song.2000.json','["按部先春鳳林野，寫懷空望鹿門山。"]'),
('0406e18c-12ec-49fc-b931-68e38ef244ae','文昭園聞提壺有感','何承矩','宋','宋诗','song-poetry','','[]','馬家公子好樓臺，鑿破青山碧沼開。',32,'全唐诗/poet.song.2000.json','["馬家公子好樓臺，鑿破青山碧沼開。", "啼鳥不知人事變，數聲猶傍水邊來。"]'),
('d05219ca-88cb-4462-bdec-0620ff811a1b','尹洛日作','呂蒙正','宋','宋诗','song-poetry','','[]','昔作儒生謁貢闈，今提相印出黄扉。',63,'全唐诗/poet.song.2000.json','["昔作儒生謁貢闈，今提相印出黄扉。", "九重鵷鷺醉中別，萬里煙霄達了歸。", "鄰叟盡垂新鶴髮，故人猶著舊麻衣。", "洛陽謾道多才子，自嘆遭逢我稀。"]'),
('84b1f739-4be8-4beb-8864-62ee7330dc1d','讀書龍門山土室作','呂蒙正','宋','宋诗','song-poetry','','[]','八灘風急浪花飛，手把漁竿傍釣磯。',32,'全唐诗/poet.song.2000.json','["八灘風急浪花飛，手把漁竿傍釣磯。", "自是釣頭香餌別，此心終待得魚歸。"]'),
('600f246b-0475-4986-86b2-02f74ac8c917','行經鴻溝','呂蒙正','宋','宋诗','song-poetry','','[]','溝中流水已成塵，溝畔荒凉起暮雲。',64,'全唐诗/poet.song.2000.json','["溝中流水已成塵，溝畔荒凉起暮雲。", "大抵關河須一統，可能天地更平分。", "烟橫綠野山空在，樹倚高原日漸曛。", "方憑征鞍思往事，數聲風笛馬前聞。"]'),
('9d115446-b09b-438e-9220-11152d0c25ec','題闕里','呂蒙正','宋','宋诗','song-poetry','','[]','南沂西泗繞晴霞，北岱東蒙擁翠華。',64,'全唐诗/poet.song.2000.json','["南沂西泗繞晴霞，北岱東蒙擁翠華。", "萬里冠裳王者會，千年鄒魯聖人家。", "高林蔽日無巢鳥，古碣埋雲半吐花。", "瞻望宮牆空佝僂，敢從滄海問津涯。"]'),
('19e81f71-f0a6-4d76-9d89-4978193891da','岳陽樓望洞庭','呂蒙正','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','八月寒濤濺碧空，片帆悠颺信秋風。',32,'全唐诗/poet.song.2000.json','["八月寒濤濺碧空，片帆悠颺信秋風。", "探珠直待驪龍睡，莫遣迷津浩渺中。"]'),
('08cbf2b1-a636-4aa0-83c9-3afaaa056277','句  其一','呂蒙正','宋','宋诗','song-poetry','','[]','怪得池塘春水滿，夜來風雨起南山。',16,'全唐诗/poet.song.2000.json','["怪得池塘春水滿，夜來風雨起南山。"]'),
('a6dad002-f52e-4238-8aac-4dbac5b9ffcf','句  其二','呂蒙正','宋','宋诗','song-poetry','','[]','挑盡寒燈夢不成。',8,'全唐诗/poet.song.2000.json','["挑盡寒燈夢不成。"]'),
('16866fc6-0369-41c8-b388-7ae2e10f7a41','句  其三','呂蒙正','宋','宋诗','song-poetry','','[]','撥盡寒爐一夜灰。',8,'全唐诗/poet.song.2000.json','["撥盡寒爐一夜灰。"]'),
('cae090f6-5936-48de-ae98-8d8ec90b3d87','鴻溝和呂聖功韻','曾璉','宋','宋诗','song-poetry','','[]','王霸興亡劫幾塵，鴻溝依舊鎖寒雲。',64,'全唐诗/poet.song.2000.json','["王霸興亡劫幾塵，鴻溝依舊鎖寒雲。", "不將帝業追三代，祇把河山割半分。", "故壘已隨流水盡，歸鴉空带夕陽曛。", "西風立馬頻回首，那忍猿聲隔岸聞。"]'),
('0624f7c0-b213-476a-b75f-e21cac8659b1','贈張詠','傅霖','宋','宋诗','song-poetry','','[]','忍把浮名賣却閑，門前流水對青山。',32,'全唐诗/poet.song.2000.json','["忍把浮名賣却閑，門前流水對青山。", "青山不語人無事，門外風花任往還。"]'),
('bf705261-db62-4ac3-8893-08ab1bc8c82f','題壁','傅霖','宋','宋诗','song-poetry','','[]','寒蛬入夜忙催織，戴勝春深苦勸耕。',32,'全唐诗/poet.song.2000.json','["寒蛬入夜忙催織，戴勝春深苦勸耕。", "人若無心濟天下，不知蟲鳥有何情。"]'),
('039bcbb8-1735-4a04-93b4-60d3fb1ede08','句','益州綠事參軍','宋','宋诗','song-poetry','','[]','秋光都似宦情薄，山色不如歸興濃。',16,'全唐诗/poet.song.2000.json','["秋光都似宦情薄，山色不如歸興濃。"]'),
('dd299333-abed-4530-a641-d5c137eb0cb1','和張乖崖','太學生','宋','宋诗','song-poetry','','[]','四窗滅盡讀書燈，窗外唯聞步鐸聲。',32,'全唐诗/poet.song.2000.json','["四窗滅盡讀書燈，窗外唯聞步鐸聲。", "辜負江山好明月，閑來此地趁虛名。"]'),
('6fe30e93-85e7-4fa5-b51b-8dda56dbad86','悼蜀四十韻','張詠','宋','宋诗','song-poetry','','[]','蜀國富且庶，風俗矜浮薄。',288,'全唐诗/poet.song.2000.json','["蜀國富且庶，風俗矜浮薄。", "奢僭極珠貝，狂佚務娛樂。", "虹橋吐飛泉，煙柳閉朱閣。", "燭影逐星沈，歌聲和月落。", "鬭雞破百萬，呼盧縱大噱。", "遊女白玉璫，驕馬黄金絡。", "酒肆夜不扃，花市春慚怍。", "禾稼暮雲連，紈繡淑氣錯。", "熙熙三十年，光景倏如昨。", "天道本害盈，侈極禍必作。", "當時布政者，岡思救民瘼。", "不能宣淳化，移風復儉約。", "情性非方直，多爲聲色著。", "從欲竊虛譽，隨性縱貪攫。", "蠶食生靈肌，作威恣暴虐。", "佞岡天子聽，所利唯剝削。", "一方仇恨興，千里攘臂躍。", "火氣烘寒空，雪彩揮蓮鍔。", "無人能却敵，何暇施擊柝。", "害物黜貨輩，皆爲白刃爍。", "瓦礫積臺榭，荆棘迷城郭。", "里第鎖苔蕪，庭軒喧燕雀。", "斗粟金帛市，束蒭羅綺博。", "悲夫驕奢民，不能飽葵藿。"]'),
('59dc6375-df04-45b6-a8ca-bd9b2e799a39','勸學','張詠','宋','宋诗','song-poetry','','[]','大化不自言，委之在英才。',120,'全唐诗/poet.song.2000.json','["大化不自言，委之在英才。", "玄門非有閉，苦學當自開。", "世上百代名，莫遣寒如灰。", "晨雞固自勉，男子胡爲哉。", "胸中一片地，無使容纖埃。", "海鷗尚可狎，人世何嫌猜。", "勤慎君子職，顔閔如瓊瑰。", "剋薄小人事，斯輩真可哀。", "放蕩功不遂，滿盈身亦災。", "將心須內疚，禍福本無媒。"]'),
('60984b96-bd53-4f8b-b13c-08b7f35d673b','愍農','張詠','宋','宋诗','song-poetry','','[]','悠悠世事稱無窮，千靈萬象生虛空。',162,'全唐诗/poet.song.2000.json','["悠悠世事稱無窮，千靈萬象生虛空。", "活人性命由百穀，還須著意在耕農。", "自有奸民逃禁律，農夫倍費耕田力。", "青巾短褐皮膚乾，不避霜風與毒日。", "暮即耕兮朝即耘，東坻南壠無閑人。", "春秋生成一百倍，天下三分二分貧。", "天意昭昭憐下土，英賢比跡生寰宇。", "懲奸濟美號長材，來救黎元暗中苦。", "我聞愍農之要簡而平，先銷坐食防兼并。", "更禁貪官與豪吏，愍農之道方始行。"]'),
('097fc208-34bc-4a3a-85d4-144c5cdf6696','緝書齋','張詠','宋','宋诗','song-poetry','','[]','綠流北面桃花中，書齋閑鎖塵蒙籠。',164,'全唐诗/poet.song.2000.json','["綠流北面桃花中，書齋閑鎖塵蒙籠。", "紗窗挂戶明月空，階前草深鳴細蟲。", "千書閟久陰生蠹，治世之文欲無緒。", "彫梁語燕不復歸，華池皓鶴先飛去。", "我來憩駕吟青春，呼奴嘯匠連揮斤。", "一日整庭戶，二日芟荆榛。", "薙草留蕙若，掃逕連松筠。", "千花萬木似得意，幽香細韻來相親。", "衆口藉藉道，一以如初新。", "伊余世上耽書客，古今萬事羅胸臆。", "運海摶風當振翼，任是青天更高碧。"]'),
('e3e77282-e57d-415d-ae38-97fbd50c100b','陽春曲','張詠','宋','宋诗','song-poetry','','[]','東風習習吹庭樹，知道春權移日馭。',64,'全唐诗/poet.song.2000.json','["東風習習吹庭樹，知道春權移日馭。", "青紅獨解露春心，凝冷無言避春去。", "大有閒階白日長，清詞麗句祝春皇。", "春皇不肯論功烈，惟有年年君道昌。"]'),
('dc9212d8-efdc-40b0-bfda-5b65998e0383','勸酒惜別','張詠','宋','宋诗','song-poetry','','[]','春日遲遲輾空碧，綠楊紅杏描春色。',182,'全唐诗/poet.song.2000.json','["春日遲遲輾空碧，綠楊紅杏描春色。", "人生年少不再來，莫把青春枉拋擲。", "思之可不令人驚，中有萬恨千愁并。", "今日就花始暢飲，座中行客酸離情。", "我欲爲君舞長劍，劍歌苦悲人苦厭。", "我欲爲君彈瑶琴，淳風死去無回心。", "不如轉海爲飲花爲幄，贏取青春片時樂。", "明朝匹馬嘶春風，洛陽花發臙脂紅。", "車馳馬走狂似沸，家家帳幕臨晴空。", "天子盛明君正少，勿恨功名苦不早。", "富貴有時來，偷閒强歡笑。", "莫與離憂賈生老。"]'),
('e198fe57-d490-47be-a61c-73484c7ae22d','解嘲','張詠','宋','宋诗','song-poetry','','[]','我本高陽徒，平生意氣凌清虛。',200,'全唐诗/poet.song.2000.json','["我本高陽徒，平生意氣凌清虛。", "詞鋒即日未見試，壯年束手來窮途。", "蛟龍豈是池中物，風雨不夾狂不得。", "五都年少莫相猜，鸞鳳雞犬非朋儕。", "志士抱全節，愚下焉復知。", "寧作鸞鳳饑，不爲雞犬肥。", "君不見淮陰漢將未逢時，市人頗解相輕欺。", "又不聞宣尼孜孜救亂治，厄宋圍陳亦何已。", "往者尚有然，余生勿多恥。", "休誇捷給饒聲光，莫以柔滑勝剛方。", "我愛前賢似松柏，肯隨秋草凋寒霜。", "道在康民致堯禹，豈要常徒論可否。", "興來轉脚上青雲，何必贏馿苦相侮。"]'),
('ec44292f-7144-4f82-b63a-9becd2ca91cc','師鳳謠','張詠','宋','宋诗','song-poetry','','[]','我聞丹山之鳳非有八翼四足兮，又何羽毛之稱奇。',90,'全唐诗/poet.song.2000.json','["我聞丹山之鳳非有八翼四足兮，又何羽毛之稱奇。", "蓋仁於不殺，義於知時。", "既信厚於動止，而淳音其用希，是以衆鳥樂而從之。", "吾疾夫世之小人兮，曾不知仁義之所爲。", "幫卷耳蹙頸背而疾走兮，吾鳳之師。"]'),
('1fe029b8-549f-4946-96fd-f6f4acce676e','驚棲曲','張詠','宋','宋诗','song-poetry','','[]','天昏昏，月娟娟，驚棲之烏伊啞而翩翾。',146,'全唐诗/poet.song.2000.json','["天昏昏，月娟娟，驚棲之烏伊啞而翩翾。", "豈非海寒天風惡，扶桑半折枝巢落。", "又非鵰鶚之不仁，鄧林何苦難容身。", "吁嚱哉，雛雛弄翼出蓬蒿，欲就鸞凰高壘巢。", "安巢待何時，平林容低枝。", "低枝苦賤良可越，却厭爭飛笑鵜鴂。", "星稀夜寒啼轉多，恐作枝間斷腸血。", "人生功名難與期，聽之永夜生憂思。", "援琴欲理驚棲曲，調苦聲悲不相續。"]'),
('df9396a4-c72d-457d-9595-df17f1d7acba','贈劉吉','張詠','宋','宋诗','song-poetry','','[]','天地有至私，劉生與英氣。',240,'全唐诗/poet.song.2000.json','["天地有至私，劉生與英氣。", "學必摘其真，文能取諸類。", "叫回堯舜天，聒破周孔耳。", "通寒不我知，要在歡生意。", "居危不苟全，憑艱立忠義。", "歸國有賢名，天子聞之喜。", "倒海塞橫流，掀天建高議。", "冒死雪忠臣，讜言警貴侍。", "四海多壯夫，望風毛骨起。", "如今竟陵城，榷司茶菽利。", "鶴情終是孤，仁性困亦至。", "勞勞憂衆民，咄咄駡貪吏。", "方期與叫閽，此實不可棄。", "如何不自持，稍負纖人累。", "酣歌引酒徒，亂入垂楊市。", "狂來拔劍舞，踏破青苔地。", "羣口咤若奇，我心憂爾碎。", "請料高陽徒，何如東山器。", "請料酒仙人，何如留侯志。", "去矣劉跋江，深心自爲計。"]'),
('faaa9294-67c4-4d61-8591-ab77b7e6b90b','送韓使君赴任越州十一韻','張詠','宋','宋诗','song-poetry','','[]','聖皇憂越人，與之求良牧。',132,'全唐诗/poet.song.2000.json','["聖皇憂越人，與之求良牧。", "矗侯簡帝心，受詔荒東服。", "再拜陳苦詞，臣生非碌碌。", "未得滅匈奴，雖榮亦爲辱。", "戎醜方款盟，宸恩倦兵黷。", "難展窮北威，遂作東南福。", "況有重慎資，足致奸巢覆。", "況有明恕懷，可使夷人伏。", "行歌烟靄空，坐嘯江山綠。", "無憂報政遲，只怕徵還速。", "他日遺遠書，幸勿忘蘭菊。"]'),
('c66e007a-18f6-46e4-88f0-86738690fca1','留別博州推官楊丹','張詠','宋','宋诗','song-poetry','','[]','郊亭欲別時，霜葉翻空日。',120,'全唐诗/poet.song.2000.json','["郊亭欲別時，霜葉翻空日。", "男兒志在乘長風，去便離憂慘顔色。", "鏌鋣煌煌對尊酒，醉舞不成空握手。", "恥唱悠悠易水歌，羞折絲絲關外柳。", "我欲爲君操峻節，研清詞，古來賢聖同驅馳。", "連城白璧不足道，濟時才略爲藩籬。", "一以答惠貺，再欲酬心知。", "從今明月夜，應有遠相思。"]'),
('0ba84c4e-6e7e-460d-aa4c-b81712b812a0','淮西敘別','張詠','宋','宋诗','song-poetry','','[]','天門高兮未我揭，驅馬淮西阻風雪。',114,'全唐诗/poet.song.2000.json','["天門高兮未我揭，驅馬淮西阻風雪。", "高陽狂客夜敲門，清談大笑傾金尊。", "一飲使君樓，騰騰醉未休。", "再約娛賓曲，歌舞喧耳目。", "宛若是子之哲兮，精神多崛奇。", "穆矣簪纓之後兮，動止饒令儀。", "繁花不染君子道，大鵬自有飛鳴時。", "何顧我之彌彌，不可無言而辭。"]'),
('e392d5fc-a6a3-42ee-bf27-b0814e120f35','淮西有答','張詠','宋','宋诗','song-poetry','','[]','天教明道知經綸，只在尊君兼庇民。',72,'全唐诗/poet.song.2000.json','["天教明道知經綸，只在尊君兼庇民。", "鶴板未徵身且賤，輕車素珮遊紅塵。", "飄飄颻颻齊與魯，半醉半醒陳復楚。", "夜倚西風拔劍舞，拔劍舞，擊劍歌，青雲路遥心奈何。"]'),
('7cb63f52-8606-49ae-9468-de78864bcd16','寄晁同年','張詠','宋','宋诗','song-poetry','','[]','昔同白日昇穹碧，還同水國司民籍。',128,'全唐诗/poet.song.2000.json','["昔同白日昇穹碧，還同水國司民籍。", "三年不見頻寄書，兩月相過忘行役。", "桃花江上雪霏霏，黄鶴樓中風力微。", "幽勝逼人魂欲飛，此時不醉無與歸。", "人間美事應有主，別馬蹄霑邊塞土。", "南樓一望心凄迷，昨夜疏簷滴寒雨。", "休誇筆力敺真風，勿憶雲山千萬重。", "但偶西風一行雁，殺青相問莫辭慵。"]'),
('6fc61023-a256-4bb6-b59f-2fff8f046f52','寄程說傅逸人','張詠','宋','宋诗','song-poetry','','[]','綠楊陰映長楸道，桃杏初花紅影小。',64,'全唐诗/poet.song.2000.json','["綠楊陰映長楸道，桃杏初花紅影小。", "手扶大白口談天，得意相歡不知老。", "一從召入金馬門，三載長纓事邊徼。", "幾欲含毫寄別離，悠悠亂思如芳草。"]'),
('e110945a-5521-4292-8996-0ca65c02183c','與進士宋嚴話別','張詠','宋','宋诗','song-poetry','','[]','人之相知須知心，心通道氣情轉深。',136,'全唐诗/poet.song.2000.json','["人之相知須知心，心通道氣情轉深。", "凌山跨陸不道遠，躡屩佩劍來相尋。", "感君見我開口笑，把臂要我談王道。", "幾度微言似愜心，投杯著地推案叫。", "此事置之無復言，且須舉樂催金船。", "人生通塞未可保，莫將閒事縈心田。", "興盡忽告去，挑燈夜如何。", "彈琴起雙舞，拍手聊長歌。", "我輩本無流俗態，不教離恨上眉多。"]'),
('4482b1c0-9c84-4bd4-929e-0248869290fa','贈聶堯','張詠','宋','宋诗','song-poetry','','[]','聶堯懷抱何翹然，遊心聖道三十年。',64,'全唐诗/poet.song.2000.json','["聶堯懷抱何翹然，遊心聖道三十年。", "智泉湍激橫碧海，文山奇崛凌青天。", "神充氣溢眸子好，常談盡是經綸道。", "早求入用活蒼黔，莫向塵中虛自老。"]'),
('e810d23b-5ed9-46c8-a907-76d223d2664a','酬所知','張詠','宋','宋诗','song-poetry','','[]','皇風浩蕩吹天地，天下英髦連鳳起。',32,'全唐诗/poet.song.2000.json','["皇風浩蕩吹天地，天下英髦連鳳起。", "海鵬一飛一萬里，三尺微風何足謂。"]'),
('f42204d7-81c8-47ed-91f2-dc6f50d86783','送張及三人赴舉','張詠','宋','宋诗','song-poetry','','[]','才雄揚子雲，古稱蜀川秀。',48,'全唐诗/poet.song.2000.json','["才雄揚子雲，古稱蜀川秀。", "千載遺英聲，三賢繼其後。", "文章積學成，孝友亦天授。", "遠郡得充庭，期將免固陋。"]'),
('d89f462d-f3c8-4ea6-b10e-63a0418eea38','蕭蘭','張詠','宋','宋诗','song-poetry','','[]','種蕭芳蘭中，蕭生蘭亦瘁。',48,'全唐诗/poet.song.2000.json','["種蕭芳蘭中，蕭生蘭亦瘁。", "它日秋風來，蕭蘭一齊敗。", "自古賢者心，所憂在民泰。", "不復夢周公，中夜獨慷慨。"]'),
('c7f8f44c-72ef-40ca-bb87-de329bb771bb','東門行','張詠','宋','宋诗','song-poetry','','[]','茫茫六合生萬靈，周公孔子留賢名。',64,'全唐诗/poet.song.2000.json','["茫茫六合生萬靈，周公孔子留賢名。", "伊余志尚未著調，秋風拔劍東門行。", "金龜典酒知是誰，逢君使我抬雙眉。", "眼前萬事不足問，要須醉倒高陽池。"]'),
('647d921c-cd88-4779-b408-02acf89e36b1','白駒謠','張詠','宋','宋诗','song-poetry','','[]','白駒如龍兮逶而迤，紅韁未絆兮天之涯。',34,'全唐诗/poet.song.2000.json','["白駒如龍兮逶而迤，紅韁未絆兮天之涯。", "秋風萬里思鄉時，傷離羣兮嘶復悲。"]'),
('22254048-e2b6-4861-8f3e-cb108c86be06','憫旱','張詠','宋','宋诗','song-poetry','','[]','皇天詔龍司下土，穀苗乾死天未雨。',32,'全唐诗/poet.song.2000.json','["皇天詔龍司下土，穀苗乾死天未雨。", "如何不念蒼生苦，村落𣀃𣀃椎旱鼓。"]'),
('e1c4f9c4-95d5-4270-9272-b4915d307c4f','結交','張詠','宋','宋诗','song-poetry','','[]','古人死恨爲交難，交心不移誠可歡。',32,'全唐诗/poet.song.2000.json','["古人死恨爲交難，交心不移誠可歡。", "須知闇水生波瀾，壯夫一欲摧心肝。"]'),
('0a203f0e-f555-4d06-9139-b9c08eb8320c','祛惑','張詠','宋','宋诗','song-poetry','','[]','過與夜光不肯要，捉得泥丸弄到老。',32,'全唐诗/poet.song.2000.json','["過與夜光不肯要，捉得泥丸弄到老。", "因嗟蜀望無胸懷，至今號作思歸鳥。"]'),
('0e2169a6-2f2c-4e40-ab82-60b308a2b0ff','酣飲','張詠','宋','宋诗','song-poetry','','[]','不敢指天象，象中皆有神。',72,'全唐诗/poet.song.2000.json','["不敢指天象，象中皆有神。", "不敢說人事，謾致奸邪嗔。", "豈若內酣飲，兀然陶吾真。", "吾真小不見，吾真大無倫。", "真苟無所適，亦免招悲辛。", "堪笑古人愚，刺轢徒殞身。"]'),
('8c04b9c2-2d14-4694-b0f1-28af5674b2f2','二月二日遊寶曆寺馬上作','張詠','宋','宋诗','song-poetry','','[]','春遊千萬家，美女顔如花。',124,'全唐诗/poet.song.2000.json','["春遊千萬家，美女顔如花。", "三三兩兩映花立，飄颻盡似乘烟霞。", "我身豈比浮遊輩，蜀地重來治凋瘵。", "見人非理即傷嗟，見人歡樂生慈愛。", "花間歌管媚春陽，花外行人欲斷腸。", "更覺花心妒蘭麝，風來繞郭聞輕香。", "昔賢孜孜戒驕蕩，猖狂不是風流樣。", "但使家肥存禮讓，歲歲春光好遊賞。"]'),
('320cbb64-8f65-43a4-b411-596b54694c7d','書園吏申花開榜子','張詠','宋','宋诗','song-poetry','','[]','後園花開紅滿枝，太守倦遊紅不知。',64,'全唐诗/poet.song.2000.json','["後園花開紅滿枝，太守倦遊紅不知。", "看花小吏報花信，太守茫然心忽悲。", "頭上光陰瞥爾過，昨日少年今老大。", "見說花間舞蝶狂，翻飛更著遊蜂和。"]'),
('49d6a11f-4db3-44b1-8fd0-b050f8088920','孟孟詞','張詠','宋','宋诗','song-poetry','','[]','胡中不識春時節，門外春迴花未發。',56,'全唐诗/poet.song.2000.json','["胡中不識春時節，門外春迴花未發。", "奴家聞道漢宮春，遥望南天拜新月。", "拜新月，攢雙眉。", "別部胡茄聲亦悲，低頭自歎胡無知。"]'),
('5cf1e4bc-1053-4128-81be-405373c8ed90','筵上贈小英','張詠','宋','宋诗','song-poetry','','[]','天教傳百花，摶作小英明如花。',182,'全唐诗/poet.song.2000.json','["天教傳百花，摶作小英明如花。", "住近桃花坊北面，門庭掩映如仙家。", "美人宜稱言不得，龍腦熏衣香入骨。", "維揚軟縠如雲英，毫郡輕紗若蟬翼。", "我疑天上婺女星之精，偷入筵中名小英。", "又疑王母侍兒初失意，謫向人間爲飲妓。", "不然何得膚如紅玉初碾成，眼似秋波雙臉橫。", "舞態因風欲飛去，歌聲遏雲長且清。", "有時歌罷下香砌，幾人魂魄遥相驚。", "人看小英心不足，我看小英心本足。", "爲我高歌送一杯，我今贈爾新翻曲。"]'),
('463af62b-8dc8-4590-aa1a-3759a034e699','登崇陽縣北峰亭','張詠','宋','宋诗','song-poetry','','[]','高榭臨公宅，凭軒萬木秋。',48,'全唐诗/poet.song.2000.json','["高榭臨公宅，凭軒萬木秋。", "亂雲橫島嶼，鳴雁下汀州。", "到此欲長醉，何門銷舊愁。", "若爲陶靖節，容易賦歸休。"]'),
('488df7b5-908a-4334-a4d7-6cd4b315389d','登崇陽縣美美亭','張詠','宋','宋诗','song-poetry','','[]','萬象盤迴處，年來此創亭。',120,'全唐诗/poet.song.2000.json','["萬象盤迴處，年來此創亭。", "喧闐當邑地，清絕倚禪扃。", "砌迥波流碧，空凉洞壑青。", "人家晴渡口，漁釣暖沙汀。", "岸竹風成韻，皋禽曉曬翎。", "栽花多是藥，題壁半書經。", "遠客憑銷恨，高僧與勒銘。", "掃苔朝復暮，閑日醉還醒。", "不可窮吟思，將須列畫屏。", "浮虛莫輕賞，美美獨丁寧。"]'),
('f8e5df90-d31d-483d-becd-3b752656e3c9','縣齋秋夕','張詠','宋','宋诗','song-poetry','','[]','才薄難勝任，空銷懶惰情。',48,'全唐诗/poet.song.2000.json','["才薄難勝任，空銷懶惰情。", "公堂羣吏散，苔地亂蛩聲。", "隔歲鄉書絕，新寒酒病生。", "方今聖明代，不敢話辭榮。"]'),
('5bfd42fc-907d-4e7b-98e9-9004d8c0a7e6','登黄鶴樓','張詠','宋','宋诗','song-poetry','','[]','重重軒檻與雲平，一度登臨萬想生。',63,'全唐诗/poet.song.2000.json','["重重軒檻與雲平，一度登臨萬想生。", "黄鶴信稀烟樹老，碧魂亂晚風清。", "何年紫陌紅塵息，終日空江白浪聲。", "莫道安邦是高致，此身終約到蓬瀛。"]'),
('c1ba1db1-8529-4678-a6b1-4df4a177e108','新秦遣懷','張詠','宋','宋诗','song-poetry','','[]','貂褐久從戎，因令筆硯慵。',48,'全唐诗/poet.song.2000.json','["貂褐久從戎，因令筆硯慵。", "梳中見白髮，枕上憶孤峰。", "風動沙昏畫，寒多雪折松。", "此心無與問，長願酒盈鐘。"]'),
('53a53e70-3825-4e99-ba0d-b5db26fdd301','登麟州城樓','張詠','宋','宋诗','song-poetry','','[]','莫問戎庭苦，高欄是夕攀。',48,'全唐诗/poet.song.2000.json','["莫問戎庭苦，高欄是夕攀。", "時清官事少，邊靜戍人閒。", "雉堞臨寒水，穹廬倚亂山。", "皇恩正無外，不擬更移關。"]'),
('807411dd-6280-41ee-91b1-a361937bf1a4','郡齋秋夕','張詠','宋','宋诗','song-poetry','','[]','久負嵩雲約，年來半白頭。',48,'全唐诗/poet.song.2000.json','["久負嵩雲約，年來半白頭。", "風驚落葉夕，雨滴戍城秋。", "調古將誰合，心狂謾自愁。", "遲迴不能寐，重起凭危樓。"]'),
('75db76c7-dca3-42a6-8d9b-1108d5c841f0','鄴中留別平仲','張詠','宋','宋诗','song-poetry','','[]','聞說懷經濟，乘閒過隠廬。',48,'全唐诗/poet.song.2000.json','["聞說懷經濟，乘閒過隠廬。", "話言殊不逆，交分合何如。", "道愧將時背，心非與世疏。", "凄凄重惜別，蟬噪古槐初。"]'),
('74f8e09c-f118-460b-bc29-c2647df46bd9','至道乙未蜀中送人東歸','張詠','宋','宋诗','song-poetry','','[]','綠楊陰裏卓旌旃，一曲離歌獨泫然。',64,'全唐诗/poet.song.2000.json','["綠楊陰裏卓旌旃，一曲離歌獨泫然。", "顧我無才狂似鹿，羨君清節直如弦。", "錦城冠難初平日，帝里春和入謁天。", "好竭忠誠佐真主，莫教尋佞苦妨賢。"]'),
('931a6b12-08f0-4142-bc16-b05cc5b298ae','再任蜀川感懷','張詠','宋','宋诗','song-poetry','','[]','官職過身鬢已衰，傍人應訝退休遲。',64,'全唐诗/poet.song.2000.json','["官職過身鬢已衰，傍人應訝退休遲。", "從來蜀地稱難制，此是君恩豈合違。", "兵火因由難即問，郡城牢落不勝悲。", "無煩苦意思諸葛，只可頒條使衆知。"]'),
('581ffdee-00de-4740-ad7f-c1d2dadc292e','蜀中傷陳恕左丞','張詠','宋','宋诗','song-poetry','','[]','英賢去世世同悲，管葛才能更比誰。',64,'全唐诗/poet.song.2000.json','["英賢去世世同悲，管葛才能更比誰。", "心盡西山離隠後，名喧深殿受恩時。", "謀猷不枉稱人傑，精審真堪作吏師。", "漫就高原向東哭，路長天遠豈能知。"]'),
('dec29528-55a9-4853-b255-ae116c10d15b','寄傅逸人','張詠','宋','宋诗','song-poetry','','[]','鷗鷺憐疏野，朝昏繞戶飛。',48,'全唐诗/poet.song.2000.json','["鷗鷺憐疏野，朝昏繞戶飛。", "有誰知此意，獨立對斜暉。", "落葉堆荒徑，澄泉照白衣。", "聖郡方急善，應好下魚磯。"]'),
('aa6f3b4c-e6f6-4eb2-a1a5-e30f1a03e2d8','每憶家園樂蜀中寄傅逸人  其一','張詠','宋','宋诗','song-poetry','','[]','每憶家園樂，當年枉用心。',48,'全唐诗/poet.song.2000.json','["每憶家園樂，當年枉用心。", "翻身期濟物，明代已腰金。", "守道知無取，防奸似不任。", "休今得休去，誰肯羨爲霖。"]'),
('11ab323c-b9c9-4448-a3f1-0ed6476fdc2c','每憶家園樂蜀中寄傅逸人  其二','張詠','宋','宋诗','song-poetry','','[]','每憶家園樂，名賢共里閭。',48,'全唐诗/poet.song.2000.json','["每憶家園樂，名賢共里閭。", "劇談祛夜瘧，幽夢得鄉書。", "漸長性情懶，隔年音信疏。", "終嫌累高節，不得薦相如。"]'),
('25c63855-8fe0-4619-8e60-cadacd596a0f','送張及之任穀城','張詠','宋','宋诗','song-poetry','','[]','不求灼灼不卑垂，自愛先賢力自爲。',64,'全唐诗/poet.song.2000.json','["不求灼灼不卑垂，自愛先賢力自爲。", "德行舊多鄉曲譽，文章新受聖皇知。", "辭親西國春方好，去路千峰鶴亦隨。", "若到縣封修政術，漢南良牧是元龜。"]'),
('60228ba7-b52e-425b-a799-b6ea0ed167c9','送趙寺丞罷秩遊青城山','張詠','宋','宋诗','song-poetry','','[]','公餘長閉目，只是老心情。',48,'全唐诗/poet.song.2000.json','["公餘長閉目，只是老心情。", "聞道尋山去，連忙出戶迎。", "好峰須到頂，靈跡要知名。", "迴日從容說，余將少解酲。"]'),
('6f93e8fd-015b-4533-859d-fa7082d21758','金陵郡齋述懷','張詠','宋','宋诗','song-poetry','','[]','傍人往往羨清途，野逸情懷亦自扶。',64,'全唐诗/poet.song.2000.json','["傍人往往羨清途，野逸情懷亦自扶。", "官舍四邊多種竹，潮溝一面近生蘆。", "病嫌見客低徊甚，老覺臨官氣味麤。", "不信浮名是身累，有時閒撚白髭鬚。"]'),
('e71ca61b-369a-4400-be7f-22874af5483f','郡齋書情寄仙遊張及','張詠','宋','宋诗','song-poetry','','[]','老去慵仍甚，榮名舊日疏。',48,'全唐诗/poet.song.2000.json','["老去慵仍甚，榮名舊日疏。", "又因經歲病，不答故人書。", "閉閤僧歸後，看山吏散初。", "何因問心跡，之子最相於。"]'),
('fe1bf255-569a-4c37-8ff6-14eb1394a251','淮陽書懷寄朝中親舊','張詠','宋','宋诗','song-poetry','','[]','聖恩重疊念龍鐘，新賜淮陽地望崇。',64,'全唐诗/poet.song.2000.json','["聖恩重疊念龍鐘，新賜淮陽地望崇。", "纔有筋骸堪策杖，更無情緒可憂公。", "日思舊隠歸何計，或問前程笑指空。", "昨日凭高向西望，滿川烟樹雨濛濛。"]'),
('b57b3a1e-ce8b-4e3c-b93a-d16eb5d0a8e1','遊趙氏西園','張詠','宋','宋诗','song-poetry','','[]','蜀中春艷世間殊，比竝陳園恐未如。',64,'全唐诗/poet.song.2000.json','["蜀中春艷世間殊，比竝陳園恐未如。", "數里花光浮暖日，六街塵浄見香車。", "翻空雅樂催歡處，入格新詩上板初。", "方信承平無一事，淮陽閒殺老尚書。"]'),
('6ad02e30-8757-4f84-9c05-81130ed6c2f7','上楊大諫','張詠','宋','宋诗','song-poetry','','[]','東南雲物異，端正産賢人。',96,'全唐诗/poet.song.2000.json','["東南雲物異，端正産賢人。", "才大可高古，名雄始入秦。", "文江橫舫檝，藝圃剗荆榛。", "民事憂偏切，金門老更親。", "天教任孤直，帝亦賞清貧。", "功業榮書史，銓題洽縉紳。", "苦聞辭祿綬，遠擬訪仙真。", "却顧希顔者，遲留塞草春。"]'),
('573a1150-6143-44a6-8445-dc81f6a03e72','寄田錫舍人','張詠','宋','宋诗','song-poetry','','[]','當年心計此心知，忽忽逢人亦自疑。',64,'全唐诗/poet.song.2000.json','["當年心計此心知，忽忽逢人亦自疑。", "枉是憂公生白髮，有何長略謝清時。", "林僧已怪抽身晚，朝侶猶嫌到闕遲。", "多喜通規識幽抱，路遥無處寄相思。"]'),
('da49ea5d-423c-4270-9d41-c100f4a59ca4','寄潭州劉郎中','張詠','宋','宋诗','song-poetry','','[]','宦途聲稱舊便蕃，朝列皆推比竝難。',64,'全唐诗/poet.song.2000.json','["宦途聲稱舊便蕃，朝列皆推比竝難。", "受任已過唐刺史，結銜猶是漢郎官。", "遥知萬井嗟何暮，酷愛諸峰病亦看。", "老大情懷更多感，相思重疊倚危欄。"]'),
('ee1ae5a3-1450-4cb3-ba9d-86d8861f2a9e','寄柏閣宗涓上人','張詠','宋','宋诗','song-poetry','','[]','周衰風雅言爲，詩匠著禪衣。',49,'全唐诗/poet.song.2000.json','["周衰風雅言爲，詩匠著禪衣。", "身世閒雲片，烟霞共鶴歸。", "引泉凉月動，掃徑落花飛。", "自信干時拙，終求對掩扉。"]'),
('64c33cc7-3c07-4002-9efa-71d2c84665bd','寄郝太沖','張詠','宋','宋诗','song-poetry','','[]','閒愁休問意休疑，此事關身合再思。',64,'全唐诗/poet.song.2000.json','["閒愁休問意休疑，此事關身合再思。", "心靜易求長世法，氣狂難與少年時。", "新編到底將何用，舊好如今更有誰。", "猶憶公堂秋會否，繞窗寒竹夜風吹。"]'),
('75b9cbb5-7a50-4d79-bbf9-cd0120c1e16f','送別蘇寺丞','張詠','宋','宋诗','song-poetry','','[]','公身多不定，何路慰飄離。',48,'全唐诗/poet.song.2000.json','["公身多不定，何路慰飄離。", "莫以微言合，苦將幽思悲。", "山程朝醉少，雪屋夜眠遲。", "即問逢春約，芳菲折贈誰。"]'),
('fbd274a9-0519-4b2e-8bc8-81df3cf7860e','送別祝隠士','張詠','宋','宋诗','song-poetry','','[]','龍鐘塵滿衣，特特叩柴扉。',48,'全唐诗/poet.song.2000.json','["龍鐘塵滿衣，特特叩柴扉。", "暫慰經年別，人驚千里歸。", "山川秋末後，風雪雁來稀。", "莫便長休去，明時待發揮。"]'),
('fd7f358b-8dc9-484d-afc0-1ccd871800a7','送馬道人歸天台','張詠','宋','宋诗','song-poetry','','[]','逢山長欲便辭榮，見說天台益自驚。',64,'全唐诗/poet.song.2000.json','["逢山長欲便辭榮，見說天台益自驚。", "絕頂要歸終久住，此時無計伴師行。", "囊携鼎藥身難老，路接仙橋眼更明。", "莫笑宦途滋味薄，五湖曾有片帆輕。"]'),
('b7741701-5496-4ff1-8f49-6b8718ead082','送人北遊','張詠','宋','宋诗','song-poetry','','[]','慈親別幾時，又作北遊期。',48,'全唐诗/poet.song.2000.json','["慈親別幾時，又作北遊期。", "萬馬方征虜，單車欲訪誰。", "遠身孤劍共，幽抱素琴知。", "應渡黄河夕，波濤驚夢思。"]'),
('ce3dd0dd-5ac4-45f7-b6a4-da8abc368684','歸越東舊隠留別秦中知己','張詠','宋','宋诗','song-poetry','','[]','客亭楊柳葉初殘，歌咽秋空慘別顔。',64,'全唐诗/poet.song.2000.json','["客亭楊柳葉初殘，歌咽秋空慘別顔。", "吟愛好峰歸越路，醉衝寒雨出秦關。", "烟蘿庭戶重栖倚，漁浦人家舊往還。", "縱使功名無分得，免教心在怨尤間。"]'),
('49d356d2-22c0-4e56-9fdd-969c882fdb3c','送祝隠者','張詠','宋','宋诗','song-poetry','','[]','當年辭聘幣，高卧魯郊西。',48,'全唐诗/poet.song.2000.json','["當年辭聘幣，高卧魯郊西。", "道與常流別，名將往哲齊。", "細蟲喧四壁，芳草暗前蹊。", "猶有談玄叟，時時一杖藜。"]'),
('49e68f3e-a8ae-4cc5-b3b1-d1211ac0a68d','贈孫曹二生','張詠','宋','宋诗','song-poetry','','[]','西洛繁華外，幽奇二隠同。',72,'全唐诗/poet.song.2000.json','["西洛繁華外，幽奇二隠同。", "喧卑不主耳，賢達許高風。", "宮水當門落，僧園舊徑通。", "看書悲往事，坐石嘯晴空。", "世界搜吟內，山川曠望中。", "憂人過憂己，豈是卧雲翁。"]'),
('4778ced8-2f4b-4c30-9744-8c77518e6909','郊居會傅逸人','張詠','宋','宋诗','song-poetry','','[]','久客倦驚魂，田居乞塹安。',96,'全唐诗/poet.song.2000.json','["久客倦驚魂，田居乞塹安。", "義寧忘力學，貧要奉親歡。", "枕外河聲老，門前野色寬。", "支流狂繞砌，叢葦品當欄。", "書葉招鄰彥，扶筇話肺肝。", "吟懷難契遇，醉語動辛酸。", "隠几歲時變，凭軒雷雨殘。", "致君須有分，會此擲魚竿。"]'),
('86e98855-64bc-497d-9baa-a7e84938c981','再會傳逸人','張詠','宋','宋诗','song-poetry','','[]','分到知心死不輕，幾年曾是愴離情。',64,'全唐诗/poet.song.2000.json','["分到知心死不輕，幾年曾是愴離情。", "微風吹雨雁初下，落葉滿階蟲正鳴。", "時靜苦嫌論劍略，簟凉頻喜轉琴聲。", "從來共約雲泉老，肯向人間占好名。"]'),
('08b4b686-02c0-4fb3-8288-299f10c5d95d','貽傅逸人','張詠','宋','宋诗','song-poetry','','[]','少年名節動人羣，避俗深居積水濆。',64,'全唐诗/poet.song.2000.json','["少年名節動人羣，避俗深居積水濆。", "幾爲典衣留遠客，半來欹枕看閒雲。", "門連酒舍青苔滑，路近沙汀白鳥分。", "誰道無心活黎庶，數篇新製詠南薰。"]'),
('247f1ee6-0bf3-4368-a523-7ecd382657d7','郊居寄朝中知己','張詠','宋','宋诗','song-poetry','','[]','年來流水壞平田，客徑窮愁自可憐。',64,'全唐诗/poet.song.2000.json','["年來流水壞平田，客徑窮愁自可憐。", "汀葦亂摇寒夜雨，沙鷗閒弄夕陽天。", "狂嫌濁酒難成醉，冷笑清詩不直錢。", "碧落故人知我否，幾回相憶上漁船。"]'),
('836a158f-928b-4f84-9384-eff042306194','懷張白逸人','張詠','宋','宋诗','song-poetry','','[]','昔年吟社偶通鄰，常貴高風入格真。',64,'全唐诗/poet.song.2000.json','["昔年吟社偶通鄰，常貴高風入格真。", "名好已期天共歇，性孤翻與世無親。", "梁園醉別花燒眼，楚寺秋歸鶴伴身。", "從此幽懷不能說，五湖烟月二京塵。"]'),
('375a5c0f-c5eb-4fb7-87af-d60ab1533b5b','訪有不遇','張詠','宋','宋诗','song-poetry','','[]','舊徑莓苔合，兒童獨閉門。',48,'全唐诗/poet.song.2000.json','["舊徑莓苔合，兒童獨閉門。", "踏霜歸遠店，凉月照空尊。", "雁響蒹葭浦，風驚橘柚村。", "知音在何處，凝寂欲銷魂。"]'),
('1499a175-7c27-4fae-a926-26b02aa102de','和人惜春','張詠','宋','宋诗','song-poetry','','[]','白日不塹住，催春去忽賒。',48,'全唐诗/poet.song.2000.json','["白日不塹住，催春去忽賒。", "頻須傾綠蟻，未忍掃殘花。", "漸恐凋雙鬢，堪驚遠別家。", "歌臺重一望，烟柳數行斜。"]'),
('63eeb173-585f-4e6a-888f-df9ae5618328','酬宗人殿院見示詩集','張詠','宋','宋诗','song-poetry','','[]','句好如天設，看來字字精。',48,'全唐诗/poet.song.2000.json','["句好如天設，看來字字精。", "功夫能到此，心意可知清。", "已得風雅正，任從時士輕。", "何當較才用，期與二南并。"]'),
('cca04c2f-ae68-48f9-ad00-79acd95f8563','依韻答人九華山圖','張詠','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','每憶眠雲處，當簷列翠屏。',96,'全唐诗/poet.song.2000.json','["每憶眠雲處，當簷列翠屏。", "有時聊極目，盡日坐忘形。", "去此心惟苦，懸圖恨忽醒。", "數峰秋欲活，虛籟夜重聽。", "地鎮三吳遠，天連萬古青。", "幾人曾得道，是草即通靈。", "松鶴閒窺鼎，龕僧闇誦經。", "終須卜長往，迴首謝明庭。"]'),
('8317fa7e-db18-41fe-ae39-f75907cf8b9f','和人登朗州江亭','張詠','宋','宋诗','song-poetry','','[]','城上江亭簇暮烟，城根老樹浸江瀾。',64,'全唐诗/poet.song.2000.json','["城上江亭簇暮烟，城根老樹浸江瀾。", "何人臨靜夜歌罷，獨客凭高秋興寬。", "直下路通諸國遠，偏東山隔半溪寒。", "漁翁似會清吟意，笑逐江鷗過淺灘。"]'),
('fe04786e-7ac8-43de-a770-ecf42422d0b1','答人惠四明山蕉葉扇','張詠','宋','宋诗','song-poetry','','[]','團團休復頌齊紈，蕉葉精新舉世傳。',64,'全唐诗/poet.song.2000.json','["團團休復頌齊紈，蕉葉精新舉世傳。", "更愛四明來處異，可量三伏用時便。", "已無酷暑侵肌骨，肯放青蠅觸几筵。", "因藉仁風慰黎庶，寧知不及古人賢。"]'),
('b0db0fc4-415d-4bc8-b0df-94bda35473e4','旅懷','張詠','宋','宋诗','song-poetry','','[]','移文休誚客衣塵，欲去終慚未了身。',64,'全唐诗/poet.song.2000.json','["移文休誚客衣塵，欲去終慚未了身。", "一夕亂蛩驚別恨，滿階紅葉愴吟神。", "東周住久知音少，白社拋來舊業貧。", "猶喜陶潛繞籬菊，带霜開得數枝新。"]'),
('bd158b0e-6f62-405f-abe2-c2a0b4207bd7','洛中寓居','張詠','宋','宋诗','song-poetry','','[]','風塵籍籍伴窮迷，旋賃高齋洛水西。',64,'全唐诗/poet.song.2000.json','["風塵籍籍伴窮迷，旋賃高齋洛水西。", "綠樹不知遊子恨，夕陽閒引杜鵑啼。", "苔侵舊徑來人絕，花滿南軒翠竹低。", "自笑詩書冷無味，抱琴階下草萋萋。"]'),
('b8ad2ee9-90f1-426a-9fce-404b9e5ac027','公暇偶作','張詠','宋','宋诗','song-poetry','','[]','世情多與道相違，偶忽公閒便息機。',64,'全唐诗/poet.song.2000.json','["世情多與道相違，偶忽公閒便息機。", "貪競已從心下絕，愛憎還覺眼中稀。", "時文鍊漉教歸正，聖易參研盡入微。", "本要資身兼報國，安知四十九年非。"]'),
('da8fc690-54b6-4673-8adb-5c16157d1dd4','舟行感懷','張詠','宋','宋诗','song-poetry','','[]','風帆江上往來頻，漁叟應多笑此身。',64,'全唐诗/poet.song.2000.json','["風帆江上往來頻，漁叟應多笑此身。", "自愧無才酬聖澤，已甘行樂負青春。", "疲贏未復空忘味，綱緒難條欲問津。", "更擬傾盃祝天地，世間不用長奸人。"]'),
('ace4b917-e968-4757-bb64-e7326a88a0ca','舟次辰陽','張詠','宋','宋诗','song-poetry','','[]','昔賢勞苦爲憂官，我自無才欲忘餐。',64,'全唐诗/poet.song.2000.json','["昔賢勞苦爲憂官，我自無才欲忘餐。", "鳴棹幾程灘勢惡，宿亭一夜雨聲寒。", "山連古洞蠻烟合，地落秋畬楚俗歡。", "雖指公餘便東下，好峰猶得捲簾看。"]'),
('8f752239-4b54-422d-aa11-7948f031c5df','遊桃源觀','張詠','宋','宋诗','song-poetry','','[]','一從仙去失仙源，樹老臺荒又幾番。',64,'全唐诗/poet.song.2000.json','["一從仙去失仙源，樹老臺荒又幾番。", "塵世莫嗟無分到，星壇空自有名存。", "竹邊風建秋醒眼，花底泉香夜斷魂。", "多少尋真舊題處，我來重與拂苔痕。"]'),
('00c63606-d373-4c8c-b415-872872ee6d57','舟中晚望桃源山','張詠','宋','宋诗','song-poetry','','[]','仙山初指眼初明，倚棹因妨半日程。',64,'全唐诗/poet.song.2000.json','["仙山初指眼初明，倚棹因妨半日程。", "雲裏未忘尋去路，世間爭合有浮名。", "巖空闇老松千尺，天靜時聞鶴一聲。", "更謝暮霞憐惜別，滿坡紅影照崢嶸。"]'),
('925afdf0-ed3c-487b-9d66-efb6728105b3','幽居','張詠','宋','宋诗','song-poetry','','[]','落花時節掩關初，請絕江城舊酒徒。',64,'全唐诗/poet.song.2000.json','["落花時節掩關初，請絕江城舊酒徒。", "滿屋烟霞春睡足，一溪風雨夜燈孤。", "易中有象閑消息，身外無求免歎吁。", "多謝巖僧頻見訪，欲迴流水又踟躕。"]'),
('9a68a971-1899-48ad-a537-b000dd6fa703','旅懷','張詠','宋','宋诗','song-poetry','','[]','儒術精窮久，風塵鬢欲衰。',48,'全唐诗/poet.song.2000.json','["儒術精窮久，風塵鬢欲衰。", "知音豈易得，搔首獨何爲。", "寓舍思親處，秋原墜葉時。", "樂天吟更苦，笑殺五陵兒。"]'),
('8896ad59-ebd2-4c90-bb03-b232fce023cc','吳宮石四正題曰醉石、曬藥石、翫月臺、朝天壇','張詠','宋','宋诗','song-poetry','','[]','何人移置向何年，牢落空庭見斷頑。',64,'全唐诗/poet.song.2000.json','["何人移置向何年，牢落空庭見斷頑。", "竹外松間滋澹竚，土昏苔染更斕斑。", "貪憐翫月名偏好，莫問朝天信不還。", "閒醉閒吟聊自得，漸無魂夢憶歸山。"]'),
('9e337d77-67b9-4296-9bf4-2788b0014c59','旅中感懷','張詠','宋','宋诗','song-poetry','','[]','人世貪名豈是閒，幾回思算幾凄然。',64,'全唐诗/poet.song.2000.json','["人世貪名豈是閒，幾回思算幾凄然。", "故鄉路遠不得信，寒月夜來還復圓。", "霜趁悲鴻歸楚澤，風移殘燒下秦川。", "莫言酒作銷憂物，更有新詩一兩篇。"]'),
('ad9f19a0-2922-4b4f-b61b-661edc094dba','退居近墅','張詠','宋','宋诗','song-poetry','','[]','選得烟村寄掩扉，拙謀翻似解忘機。',64,'全唐诗/poet.song.2000.json','["選得烟村寄掩扉，拙謀翻似解忘機。", "名場未入老將至，鄉信不來春欲歸。", "窗背晚陰黄鳥語，簟橫幽徑落花飛。", "何由盡會蒼蒼意，時復携筇上翠微。"]'),
('0df9844a-26fe-4986-94c5-4f222d653d96','歸隠嵩陽','張詠','宋','宋诗','song-poetry','','[]','浮世事無限，何須要到頭。',48,'全唐诗/poet.song.2000.json','["浮世事無限，何須要到頭。", "壯心爲客盡，孤跡卧雲休。", "匣劍已全棄，林僧亦少酬。", "從來愁恨意，乞待外人愁。"]'),
('868ab130-8c22-44d1-8b0d-381cded5cf20','本農','張詠','宋','宋诗','song-poetry','','[]','奢競苦不息，生民只有冤。',48,'全唐诗/poet.song.2000.json','["奢競苦不息，生民只有冤。", "誰搜元化窟，鑿斷麗華根。", "使絕侵奪苦，著爲明聖恩。", "何煩重師古，即此是羲軒。"]'),
('6126321e-0c32-4874-b485-5f3974062e1b','喜雨','張詠','宋','宋诗','song-poetry','','[]','救旱功何遠，淋漓晝復昏。',48,'全唐诗/poet.song.2000.json','["救旱功何遠，淋漓晝復昏。", "風雷潛助勢，草木豈知恩。", "積靄消殘影，枯源漲舊痕。", "朗吟渾得意，重起凭前軒。"]'),
('9d1d5dae-b5ad-4d1b-a0ad-36ce17f1ea5b','秋霖','張詠','宋','宋诗','song-poetry','','[]','觸石便溟濛，經旬失遠空。',48,'全唐诗/poet.song.2000.json','["觸石便溟濛，經旬失遠空。", "深疑竹箭浪，兼起蓼花風。", "浄長苔痕綠，寒催木葉紅。", "蒼蒼不可問，惆悵漢陵東。"]'),
('1e9507f6-2af6-402c-8374-8ff923fdca49','庭竹','張詠','宋','宋诗','song-poetry','','[]','挺秀誠堪貴，蕭疏在蘚庭。',48,'全唐诗/poet.song.2000.json','["挺秀誠堪貴，蕭疏在蘚庭。", "小桃遮不得，深雪放教青。", "射影池光冷，聲敲鶴夢醒。", "牽吟莫可極，重寫上前屏。"]'),
('16710b6b-96ca-44f6-8be5-c0575411ec83','朝日蓮','張詠','宋','宋诗','song-poetry','','[]','少得方爲貴，根莖豈異蓮。',96,'全唐诗/poet.song.2000.json','["少得方爲貴，根莖豈異蓮。", "高低全頼水，舒卷自知天。", "已任羣芳妒，難妨後笑偏。", "向明終有待，呈艷不爭先。", "愛重頻移席，徵求苦費錢。", "蘭蓀饒酷烈，桃杏愧奢妍。", "應瑞花中絕，標名世上傳。", "須栽禁池內，用表太平年。"]'),
('87b15710-2368-4a4d-8326-a716a2052c48','弱柳','張詠','宋','宋诗','song-poetry','','[]','枝莖何弱種何緣，著架扶持勢可憐。',64,'全唐诗/poet.song.2000.json','["枝莖何弱種何緣，著架扶持勢可憐。", "但見低垂長衛足，更無疏疏欲參天。", "離情謾指千條線，野興堪驚一點烟。", "最惜柔謙似君子，夜凉重起繞欄邊。"]'),
('295e32bc-382e-47f7-b931-1c7c9fe60089','曲湖種柳','張詠','宋','宋诗','song-poetry','','[]','曲湖連曲接平蕪，前事因循好歎吁。',64,'全唐诗/poet.song.2000.json','["曲湖連曲接平蕪，前事因循好歎吁。", "不見有源堪畎鑿，便來此地費工夫。", "蛙能聚響難停息，蓮本含香舊已無。", "夾岸近教多種柳，少延春色向城隅。"]'),
('52410e60-3b9b-461f-9b77-626f7987ba3e','新移蓼花','張詠','宋','宋诗','song-poetry','','[]','蓼叢疏淡老相宜，移傍清流曲岸西。',64,'全唐诗/poet.song.2000.json','["蓼叢疏淡老相宜，移傍清流曲岸西。", "紅穗已霑巫峽雨，綠痕猶带錦江泥。", "吟狂不覺驚幽鷺，立困翻疑在舊谿。", "官滿便應離此去，可憐心緒更難齊。"]'),
('0b02e97b-3e9d-470f-bd39-d66032c60e0d','秋日登美美亭','張詠','宋','宋诗','song-poetry','','[]','野人官職與心違，何況經年未得歸。',32,'全唐诗/poet.song.2000.json','["野人官職與心違，何況經年未得歸。", "一夕秋風無限思，偶來凭檻到斜暉。"]'),
('7a3faaca-6250-45d5-913a-5396081150de','縣齋感懷二首  其一','張詠','宋','宋诗','song-poetry','','[]','前朝官政似無端，彭澤先生百日還。',32,'全唐诗/poet.song.2000.json','["前朝官政似無端，彭澤先生百日還。", "堪愧崇陽九河客，明時不敢自歸山。"]'),
