('5454b21f-2389-4c52-95f8-4cbb48b51ee3','柳枝詞七首  其五','張詠','宋','宋诗','song-poetry','','[]','海潮聲裏越谿頭，誰種千株夾亂流。',32,'全唐诗/poet.song.2000.json','["海潮聲裏越谿頭，誰種千株夾亂流。", "安是辭榮同范蠡，綠絲和雨繫扁舟。"]'),
('1aeab303-978b-4612-9dd6-66674bbeda5f','柳枝詞七首  其六','張詠','宋','宋诗','song-poetry','','[]','帳偃纓垂已有名，水邊花外更分明。',32,'全唐诗/poet.song.2000.json','["帳偃纓垂已有名，水邊花外更分明。", "前賢可得輕詞句，幾變新聲入鄭聲。"]'),
('e154b586-6a4b-4d55-b21e-aafdd7c14562','柳枝詞七首  其七','張詠','宋','宋诗','song-poetry','','[]','吳王愛重爲遊從，歲歲添栽後苑中。',32,'全唐诗/poet.song.2000.json','["吳王愛重爲遊從，歲歲添栽後苑中。", "家國旋亡臺榭毀，數株臨水尚牽風。"]'),
('690785b8-f3da-4660-9c9e-7b19214a2187','和人牡丹','張詠','宋','宋诗','song-poetry','','[]','桃源分散恨無期，忽意江城見有時。',32,'全唐诗/poet.song.2000.json','["桃源分散恨無期，忽意江城見有時。", "歌繞醉圍拋不得，幾人終夜起題詩。"]'),
('54574bae-3fbd-492f-85be-ec60884a8351','寄傅逸人','張詠','宋','宋诗','song-poetry','','[]','當年失脚下魚磯，苦爲明朝未得歸。',32,'全唐诗/poet.song.2000.json','["當年失脚下魚磯，苦爲明朝未得歸。", "寄語巢由莫相笑，此心不是愛輕肥。"]'),
('ddc66da7-b8d5-406b-97da-5fb696bec4f9','闕下寄傅逸人','張詠','宋','宋诗','song-poetry','','[]','疏疏蘆葦映門牆，更有新秋膾味長。',32,'全唐诗/poet.song.2000.json','["疏疏蘆葦映門牆，更有新秋膾味長。", "何事輕拋來帝里，至今魂夢繞寒塘。"]'),
('c1bc273f-30c5-4e93-8d5e-7bfdfbc987fb','秋日寄友人','張詠','宋','宋诗','song-poetry','','[]','柳條風暖會吟時，林下池邊屐齒移。',32,'全唐诗/poet.song.2000.json','["柳條風暖會吟時，林下池邊屐齒移。", "別後過從更疏懶，暮蟬嘹亂不勝悲。"]'),
('f2dcb0f5-2de0-4ab7-928c-c6abc0292e6c','送別王秘丞','張詠','宋','宋诗','song-poetry','','[]','帝鄉三十年前別，江外相逢鬢已衰。',32,'全唐诗/poet.song.2000.json','["帝鄉三十年前別，江外相逢鬢已衰。", "清論未窮行計速，爲君臨水立多時。"]'),
('6fa123aa-14a9-4ac1-bc08-33dee80ade60','送別李司直','張詠','宋','宋诗','song-poetry','','[]','亭下依微見遠村，亭中離恨若爲論。',32,'全唐诗/poet.song.2000.json','["亭下依微見遠村，亭中離恨若爲論。", "數聲歌罷揚帆去，民吏相看有淚痕。"]'),
('f3770167-91a9-4a42-a3ab-6f400dd4e00e','送魏道士','張詠','宋','宋诗','song-poetry','','[]','江上蕭蕭木葉飛，天台狂客杖藜歸。',32,'全唐诗/poet.song.2000.json','["江上蕭蕭木葉飛，天台狂客杖藜歸。", "莫嫌俗吏勤相顧，曾是嵩陽舊掩扉。"]'),
('886bbb3c-a6ee-4a90-8379-7bb3b11a1f27','答劉道人','張詠','宋','宋诗','song-poetry','','[]','嵩陽峰底洞中天，曾共浮丘對掩關。',32,'全唐诗/poet.song.2000.json','["嵩陽峰底洞中天，曾共浮丘對掩關。", "知道高閒少兼濟，折腰從此到人間。"]'),
('b3f72df4-1da0-44d1-bed7-ab9f32f81280','暮春憶友人','張詠','宋','宋诗','song-poetry','','[]','楊花零落暮春風，醉起南軒夕照紅。',32,'全唐诗/poet.song.2000.json','["楊花零落暮春風，醉起南軒夕照紅。", "閒倚焦桐坐無語，故人相隔海門東。"]'),
('8ffad89d-dc67-412d-824b-77ea959a098b','遣興勉友人','張詠','宋','宋诗','song-poetry','','[]','人生三萬六千日，二萬日中愁苦身。',32,'全唐诗/poet.song.2000.json','["人生三萬六千日，二萬日中愁苦身。", "惟有無心消遣得，有心到了是癡人。"]'),
('d7f0b4ab-1202-4f20-8cfc-19a770e00ca1','謝雲居山人草鞋','張詠','宋','宋诗','song-poetry','','[]','雲居山客草爲鞋，路轉千峰此寄來。',32,'全唐诗/poet.song.2000.json','["雲居山客草爲鞋，路轉千峰此寄來。", "昨日公餘偷步躡，萬端心緒憶天台。"]'),
('da5feeaa-f116-45b6-a428-e703e4cf8186','請人畫嵩山圖','張詠','宋','宋诗','song-poetry','','[]','嵩陽三十六峰寒，向爲明時隠遁難。',32,'全唐诗/poet.song.2000.json','["嵩陽三十六峰寒，向爲明時隠遁難。", "却顧事繁思不及，如何與作畫圖看。"]'),
('b89e8ed8-db4c-4a6e-a97a-92e35c794e14','鷺鸞','張詠','宋','宋诗','song-poetry','','[]','碧蘆風暖健精神，烟澹烟濃片影分。',32,'全唐诗/poet.song.2000.json','["碧蘆風暖健精神，烟澹烟濃片影分。", "天怪覓魚心未足，不教名興鶴同羣。"]'),
('7b5f3def-316d-4457-b0ff-944290e88839','聞鷓鶘','張詠','宋','宋诗','song-poetry','','[]','畫中曾見曲中聞，不是傷情即斷魂。',32,'全唐诗/poet.song.2000.json','["畫中曾見曲中聞，不是傷情即斷魂。", "北客南來心未穩，數聲相應過前村。"]'),
('239b7f11-d1b6-47ff-b138-afa10cadf166','孤舟','張詠','宋','宋诗','song-poetry','','[]','汴水湯湯，維舟中央。',39,'全唐诗/poet.song.2000.json','["汴水湯湯，維舟中央。", "其去也茫茫，其來也茫茫。", "與其濟兮，焉知古之人不同舟而樂康。"]'),
('ec270343-6e1a-49af-ad54-a4929773d3f2','館中新蟬','張詠','宋','宋诗','song-poetry','','[]','脫塵還與比仙遊，露腹何妨近品流。',64,'全唐诗/poet.song.2000.json','["脫塵還與比仙遊，露腹何妨近品流。", "嫩殻半遺紅藥地，細聲偏傍綠楊樓。", "詩家取象吟難盡，畫格偷真意不休。", "正好儒林擬緌紼，憑欄無苦預悲秋。"]'),
('c930bf53-963a-4a38-a2bf-798fdbf753f0','鶴','張詠','宋','宋诗','song-poetry','','[]','共憐潔白本天姿，縱在泥塵性不卑。',64,'全唐诗/poet.song.2000.json','["共憐潔白本天姿，縱在泥塵性不卑。", "況是稻粱厭足日，好尋烟月却歸時。", "跡參詩雅何年盡，名繫仙經四海知。", "應到崑丘指來歷，曾陪鴛鷺浴華池。"]'),
('c619b54d-c835-4d9a-9822-ebe23123d8ef','闕下元夕令領寄大有','張詠','宋','宋诗','song-poetry','','[]','月華瀟洒始徘徊，時起平津雅宴開。',64,'全唐诗/poet.song.2000.json','["月華瀟洒始徘徊，時起平津雅宴開。", "照座玉山皆俊彩，驚人綺句盡仙才。", "秋風未泛鴟夷檝，浮世皆登郢隗臺。", "的被鄰翁深鄙誚，尚迷繁盛不歸來。"]'),
('1a60457b-e0c3-49a1-b8e5-69bb962229b0','竹','張詠','宋','宋诗','song-poetry','','[]','卷簾陰薄漏山色，欹枕韻疑寒雨聲。',32,'全唐诗/poet.song.2000.json','["卷簾陰薄漏山色，欹枕韻疑寒雨聲。", "春晚不知桃李謝，歲寒非避雪霜深。"]'),
('7f683f83-af6d-421e-8d18-3036f52c8af8','發冷水鋪','張詠','宋','宋诗','song-poetry','','[]','冷水東南去路賒，水邊山掩見人家。',32,'全唐诗/poet.song.2000.json','["冷水東南去路賒，水邊山掩見人家。", "無端下馬尋幽處，鷗鷺飛飛出荻花。"]'),
('910dd865-852a-41a8-8657-a56a95feecaf','句  其一','張詠','宋','宋诗','song-poetry','','[]','莫嗟黑鬢從頭白，終見黄河到底清。',16,'全唐诗/poet.song.2000.json','["莫嗟黑鬢從頭白，終見黄河到底清。"]'),
('207f1bfe-8f16-420d-995f-6a35ed472153','句  其二','張詠','宋','宋诗','song-poetry','','[]','滿屋烟霞春睡足，一溪風雨夜燈孤。',16,'全唐诗/poet.song.2000.json','["滿屋烟霞春睡足，一溪風雨夜燈孤。"]'),
('733dd6aa-4461-496c-83fb-c5a68db478cc','存目  其一','張詠','宋','宋诗','song-poetry','','[]','詩題：伍員廟首句：胥也應無憾。',15,'全唐诗/poet.song.2000.json','["詩題：伍員廟首句：胥也應無憾。"]'),
('a8e6a7d8-43f3-4849-a4b5-e167256926e4','存目  其二','張詠','宋','宋诗','song-poetry','','[]','詩題：泰伯廟首句：至德本無名。',15,'全唐诗/poet.song.2000.json','["詩題：泰伯廟首句：至德本無名。"]'),
('6ed02eb9-c0f5-42bf-bae1-194f284a371f','奉和小園獨坐偶賦所懷','李至','宋','宋诗','song-poetry','','[]','歌舞林亭不外求，朝迴多著道衣遊。',64,'全唐诗/poet.song.2000.json','["歌舞林亭不外求，朝迴多著道衣遊。", "薔薇點綴勾欄好，薜荔攀緣怪石幽。", "泥浸落花紅片濕，鳥啼深樹綠陰稠。", "春風去便還經歲，莫負芳菲醉即休。"]'),
('eff64fd4-08ac-48bf-a07d-5efb59d6d022','至啟伏蒙僕射相公以小子近司靶閣罕扣蕪音忽徵庸陋之詞蓋示記憐之旨特貽篇什俯耀行藏捧翫無猒感戴交切謹依高韻奉和聊抒下情','李至','宋','宋诗','song-poetry','','[]','什句無騷雅口難開，豈稱明公唱和才。',65,'全唐诗/poet.song.2000.json','["什句無騷雅口難開，豈稱明公唱和才。", "多病正憐拈筆懶，相思還喜送詩來。", "讀臨危坐拋青史，吟遶幽庭躡綠苔。", "欲琢一聯聊報謝，志疏詞拙自先咍。"]'),
('f212e63a-e5b6-4872-8bcb-f61fca1cb95d','至啟伏以摇落九秋正憐殘菊淒清四韻忽及弊廬僕射相公閒世宏才九流奧主動則代天而理啟迪謨猷靜則味道之腴吟詠情性當休幹之多暇徵騷楚以自娛因臨菊酒之觴猥念芸香之客顧惟蒙鄙曷稱奬私苟慙屬和之非寧表感知之甚輒資一笑用寫寸心','李至','宋','宋诗','song-poetry','','[]','曉趨蓬閣暮還家，坐覽圖書見海涯。',64,'全唐诗/poet.song.2000.json','["曉趨蓬閣暮還家，坐覽圖書見海涯。", "釣有舊谿猶懶說，詩無新律豈堪誇。", "凉風吹葉沿階厚，積雨生苔逐徑斜。", "知宴龍山無暇去，寂寥空遶滿籬花。"]'),
('b1a5375d-2a1e-4bf9-8e2e-c6fc729d01b2','奉和獨賞牡丹','李至','宋','宋诗','song-poetry','','[]','遶臺依榭一叢叢，紫映黄苞白映紅。',64,'全唐诗/poet.song.2000.json','["遶臺依榭一叢叢，紫映黄苞白映紅。", "爛漫只因前夜雨，馨香無奈此時風。", "暖融春色交相妬，繁曬晴陽艷欲烘。", "應恨官高少同賞，罇前不得召鄰翁。"]'),
('41c25c8f-465d-401c-ac84-7d32cb9d0f36','殘春有感  其一','李至','宋','宋诗','song-poetry','','[]','陰陰垂柳轉黄鸝，腸斷殘春欲去時。',63,'全唐诗/poet.song.2000.json','["陰陰垂柳轉黄鸝，腸斷殘春欲去時。", "白雪亂堆飛絮地，紅鬚半在落花枝。", "園林向晚深藏郭，野水新晴入池。", "最是牡丹堪痛惜，風吹雨打漸離枝。"]'),
('edc9dfe1-15b6-4058-86c2-a824c7015cf4','殘春有感  其二','李至','宋','宋诗','song-poetry','','[]','年年九十日春風，風雨多端復在中。',64,'全唐诗/poet.song.2000.json','["年年九十日春風，風雨多端復在中。", "一盞更還辜我綠，亂花知是爲誰細。", "樹頭啼鳥疑相勸，窗下吟生似不通。", "可惜芳晨莫虛過，眼前便作白頭翁。"]'),
('373658b7-0782-45f6-8eb1-800aabccf3e4','喜雨','李至','宋','宋诗','song-poetry','','[]','沈煙漠漠晦平皋，盡日空濛阻出遨。',64,'全唐诗/poet.song.2000.json','["沈煙漠漠晦平皋，盡日空濛阻出遨。", "窗打紙聲聞紅點，檻飄花影見凝膏。", "依稀恨曲添鳴溜，悵望啼粧在小桃。", "何假錦障泥看麥，門前芳草綠於袍。"]'),
('a4898ead-43dc-4626-8810-f98e7597f743','至啟至比嬰風熱殆過浹旬近方稍康未果上謁輒呈短什聊抒下情','李至','宋','宋诗','song-poetry','','[]','漸老筋骸百事慵，退朝無復接鵷鴻。',64,'全唐诗/poet.song.2000.json','["漸老筋骸百事慵，退朝無復接鵷鴻。", "數枝筠粉幽窗外，一炷檀煙靜室中。", "冷滴夢魂桐葉雨，香吹籬落菊花風。", "自慙不及車夫子，時向東山謁謝公。"]'),
('5788effd-38c5-4b5f-9648-f64ec98990d8','寄獻僕射相公','李至','宋','宋诗','song-poetry','','[]','病無憀頼負重陽，虛過東籬爛漫黄。',64,'全唐诗/poet.song.2000.json','["病無憀頼負重陽，虛過東籬爛漫黄。", "把酒不成陶令醉，脫巾空羨孟嘉狂。", "鴻聲歷歷高橫漢，雲影離離薄護霜。", "珍重風流賢相國，此時閑卧奏清商。"]'),
('491d1ecd-2ad7-46ad-8f30-4ce05c22f854','至伏以時雪普霑天顔兌悅特就圖書之府廣延儒墨之流頒內庫之醇醪給大官之珍膳空慙醉飽莫報休明僕射相公與我義高緣情才大遽枉風騷之作過爲庸鄙之榮輒扣凡音仰依來韻敢冀聊窺之幸止爲笑之資','李至','宋','宋诗','song-poetry','','[]','盡日霏霏灑禁闈，蓬山高會各增輝。',64,'全唐诗/poet.song.2000.json','["盡日霏霏灑禁闈，蓬山高會各增輝。", "數行御札鸞凰舞，一幅天歌錦繡飛。", "席上共驚飄粉絮，筆頭爭看落珠璣。", "蘭臺老監雖多病，爲感君恩亦醉歸。"]'),
('6590b893-67c0-4864-8cb0-1569d821ff40','早春寄獻僕射相公','李至','宋','宋诗','song-poetry','','[]','城中塵坌林亭遠，知得春風何日來。',64,'全唐诗/poet.song.2000.json','["城中塵坌林亭遠，知得春風何日來。", "城外地寬松石好，乞聞春色過年迴。", "竹枝宜靜應分洗，果樹嫌繁更擘栽。", "借問曹樽殘幾許，且須留取待花開。"]'),
('ae3e6bd2-8ddb-4a15-ba02-e9cdd69c752b','僕射相公以鶴算漸高鴻恩未答形於章句冠彼詩流蒙見寄之榮感愛忘之甚誠知寡和豈敢無言亦以鄙懷伸於拙筆庶垂一覽聊用發咍','李至','宋','宋诗','song-poetry','','[]','久病心情只自寬，茫茫世事有多般。',64,'全唐诗/poet.song.2000.json','["久病心情只自寬，茫茫世事有多般。", "一窗青史真堪愛，滿馬紅塵未必懽。", "覓句靜拈雞距筆，納凉閑戴鹿胎冠。", "唯慙報主無絲髮，欲話歸山啟口難。"]'),
('95713203-16ae-416f-ba28-b71fd82f6484','伏奉佳句猥寄鄙夫輒寫丹誠仰依高韻','李至','宋','宋诗','song-poetry','','[]','獨慙師長念遺簪，長感知心在寸心。',64,'全唐诗/poet.song.2000.json','["獨慙師長念遺簪，長感知心在寸心。", "要路未離扶遣進，閑曹因病放教吟。", "風鵬雖遠丹霄勢，月兔猶依綠桂陰。", "從此期公惜高鑒，休將白雪換巴音。"]'),
('c3b6d081-7ee2-4f3b-8b54-4bf26a2b6dbb','至啟伏蒙僕射相公獨垂青眼忽枉朱輪仍貽郢客之詠歌過爲無鹽之刻畫有何才取都是愛忘若慙拙思之如抽豈表善言之必應輒次來韻却獻一章','李至','宋','宋诗','song-poetry','','[]','蓬丘官況復何如，養拙資吟久病餘。',64,'全唐诗/poet.song.2000.json','["蓬丘官況復何如，養拙資吟久病餘。", "印簏罕開無案牘，閤門常鎖有圖書。", "山中舊隠閑多憶，世上浮生老更疏。", "何幸明公偏顧我，馬蹄出便到貧居。"]'),
('0178222d-c886-495b-82ce-832dea34fd11','再獻一章聊歌盛美亦次前韻庶達下情蓋採羣情非獨諛說','李至','宋','宋诗','song-poetry','','[]','搢紳公論比何如，萬物熙熙燮理餘。',64,'全唐诗/poet.song.2000.json','["搢紳公論比何如，萬物熙熙燮理餘。", "罷相暫遊端揆地，退朝閑讀聖人書。", "荀公道在馨香遠，謝傳情高世俗疏。", "聞說吹塵還入夢，東山爭得久安居。"]'),
('da0ab372-4b43-493a-b7f2-9c8181e22303','春色漸濃物華相惱又依前韻更得惡詩既導鄙懷且嘲芳景自猶竊哂何況明公敢望臺慈勿尤塵瀆爲幸  其一','李至','宋','宋诗','song-poetry','','[]','感恩言發即漣如，鶴已乘軒十載餘。',64,'全唐诗/poet.song.2000.json','["感恩言發即漣如，鶴已乘軒十載餘。", "抱病尚通金闕籍，避榮猶掌玉皇書。", "目難看字垂垂暗，髮不勝簪漸漸疏。", "安得安邊一長策，少酬明主定狼居。"]'),
('c34a610d-09e7-47e9-b778-1e7d4df711ff','春色漸濃物華相惱又依前韻更得惡詩既導鄙懷且嘲芳景自猶竊哂何況明公敢望臺慈勿尤塵瀆爲幸  其二','李至','宋','宋诗','song-poetry','','[]','春色融怡畫不如，落花狼籍曉風餘。',64,'全唐诗/poet.song.2000.json','["春色融怡畫不如，落花狼籍曉風餘。", "流鶑爲爾難忘酒，遲日教儂又廢書。", "芳草芊芊行欲徧，垂楊嫋嫋折來疏。", "到頭別卜連園地，悔學齊嬰近市居。"]'),
('26b1bb39-38a6-4ea4-9b77-a6b1789d0ccb','再獻五章奉資一笑  其一','李至','宋','宋诗','song-poetry','','[]','福德才名盡不如，三朝榮貴四旬餘。',64,'全唐诗/poet.song.2000.json','["福德才名盡不如，三朝榮貴四旬餘。", "花前尚飲連觥酒，燈下猶看細字書。", "黄閤暫拋金印重，青銅閑照雪髯疏。", "蒼生共指中臺位，除是明公更合居。"]'),
('937252a6-20c2-4dff-b064-15625ba85c3d','再獻五章奉資一笑  其二','李至','宋','宋诗','song-poetry','','[]','勞公相比作相如，才即無餘幸有餘。',64,'全唐诗/poet.song.2000.json','["勞公相比作相如，才即無餘幸有餘。", "但願徧觀蓬閣史，何曾歸著茂陵書。", "已慙諭蜀詞章劣，仍恨遊梁價望疏。", "惟愛一琴猶頗似，卓文君又恥同居。"]'),
('291a9665-525b-4719-85d2-9933e9c3c261','再獻五章奉資一笑  其三','李至','宋','宋诗','song-poetry','','[]','逢春春半合何如，火急謀懽二月餘。',64,'全唐诗/poet.song.2000.json','["逢春春半合何如，火急謀懽二月餘。", "且向花間行載酒，誰能窗下卧看書。", "追攀每恨朱門遠，鄙恡仍憐玉柄疏。", "他日相尋預相報，芳時多不在蓬居。"]'),
('2d2d4b97-a36b-44cd-a908-ae61dfe9392f','再獻五章奉資一笑  其四','李至','宋','宋诗','song-poetry','','[]','而今祕閣古難如，何啻梁元十萬餘。',64,'全唐诗/poet.song.2000.json','["而今祕閣古難如，何啻梁元十萬餘。", "無本盡從三館借，有籤重遣八分書。", "芸香欲辟魚心蠹，汗簡猶嫌吏手疏。", "號作蓬山應不錯，祇緣清浄似仙居。"]'),
('3cb2f3f9-3493-44a6-864e-02d8cf76aea7','再獻五章奉資一笑  其五','李至','宋','宋诗','song-poetry','','[]','小院荒凉亦自如，纔盈五畝又無餘。',64,'全唐诗/poet.song.2000.json','["小院荒凉亦自如，纔盈五畝又無餘。", "檻中脩竹依時種，壁上斜行信手書。", "雨打杏花將爛漫，風吹楊柳漸扶疏。", "誠知濁酒非公飲，頻爲芳辰過陋居。"]'),
('371e61f7-011f-4663-b6a0-4db65491452f','昨日奉謁還家馬上偶成長句亦次前韻用述鄙懷','李至','宋','宋诗','song-poetry','','[]','澄波橋遠馬班如，往復依稀十里餘。',64,'全唐诗/poet.song.2000.json','["澄波橋遠馬班如，往復依稀十里餘。", "春色遶園千樹柳，清風吹面一堂書。", "已降詩迸驪珠逸，更羨談揮麈尾疏。", "定許貧家卜鄰否，欲收殘俸便尋居。"]'),
('bffec32e-5883-422a-95a2-2078e3617afe','小子祇自夜來風氣又作腫連頤頷熱發心脾無以豁其煩襟徒自樂於酣詠旋書在紙不覺成篇又獲五章皆依前韻達誠而已何足爲詩而惜經苦心忍作棄物入門遽絕既緣知己之獲伸束手終降尚以疲兵而再戰三思無取一笑有餘昔漢室大將軍有長揖之客今我朝大丞相有屬和之生皆一時之美也不亦可乎  其一','李至','宋','宋诗','song-poetry','','[]','四海而今幸晏如，近經周漢亂亡餘。',64,'全唐诗/poet.song.2000.json','["四海而今幸晏如，近經周漢亂亡餘。", "廣抄青史藏新閣，多著黄金訪舊書。", "歲月漸驚容鬢改，膏粱仍恨齒牙疏。", "待公朝暮重調鼎，乞取蓬丘到老居。"]'),
('22bd5304-13af-48c0-9f2e-48c039301fa1','小子祇自夜來風氣又作腫連頤頷熱發心脾無以豁其煩襟徒自樂於酣詠旋書在紙不覺成篇又獲五章皆依前韻達誠而已何足爲詩而惜經苦心忍作棄物入門遽絕既緣知己之獲伸束手終降尚以疲兵而再戰三思無取一笑有餘昔漢室大將軍有長揖之客今我朝大丞相有屬和之生皆一時之美也不亦可乎  其二','李至','宋','宋诗','song-poetry','','[]','自憐何幸少人如，不幸如人亦有餘。',64,'全唐诗/poet.song.2000.json','["自憐何幸少人如，不幸如人亦有餘。", "賤日身安長欠學，榮時眼病却多書。", "含毫終是冥搜拙，展卷仍慙博覽疏。", "最抱平生一般恨，累茵獨享若爲居。"]'),
('fb657914-6eca-4594-bdda-2a005584b699','小子祇自夜來風氣又作腫連頤頷熱發心脾無以豁其煩襟徒自樂於酣詠旋書在紙不覺成篇又獲五章皆依前韻達誠而已何足爲詩而惜經苦心忍作棄物入門遽絕既緣知己之獲伸束手終降尚以疲兵而再戰三思無取一笑有餘昔漢室大將軍有長揖之客今我朝大丞相有屬和之生皆一時之美也不亦可乎  其三','李至','宋','宋诗','song-poetry','','[]','夏口曾遊意豁如，看山尋水二年餘。',64,'全唐诗/poet.song.2000.json','["夏口曾遊意豁如，看山尋水二年餘。", "頭陀碑字殘須補，崔顥詩牌暗又書。", "鸚鵡洲中芳草徧，鷺鸞亭畔野煙疏。", "可憐陶侃當時柳，猶有孫枝遶舊居。"]'),
('b9018a62-82d6-4229-87fd-c4465b077b0f','小子祇自夜來風氣又作腫連頤頷熱發心脾無以豁其煩襟徒自樂於酣詠旋書在紙不覺成篇又獲五章皆依前韻達誠而已何足爲詩而惜經苦心忍作棄物入門遽絕既緣知己之獲伸束手終降尚以疲兵而再戰三思無取一笑有餘昔漢室大將軍有長揖之客今我朝大丞相有屬和之生皆一時之美也不亦可乎  其四','李至','宋','宋诗','song-poetry','','[]','此心未足便何如，官職於君不啻餘。',64,'全唐诗/poet.song.2000.json','["此心未足便何如，官職於君不啻餘。", "輦下十年前進士，省中四品次尚書。", "曾陪國相裨時少，亦掌王言屬思疏。", "終乞分司洛陽去，就泉依竹水南居。"]'),
('2c32639d-0ca9-46ca-be15-6c6729e96da8','小子祇自夜來風氣又作腫連頤頷熱發心脾無以豁其煩襟徒自樂於酣詠旋書在紙不覺成篇又獲五章皆依前韻達誠而已何足爲詩而惜經苦心忍作棄物入門遽絕既緣知己之獲伸束手終降尚以疲兵而再戰三思無取一笑有餘昔漢室大將軍有長揖之客今我朝大丞相有屬和之生皆一時之美也不亦可乎  其五','李至','宋','宋诗','song-poetry','','[]','忽厭菱花太皎如，黳髯新白十莖餘。',64,'全唐诗/poet.song.2000.json','["忽厭菱花太皎如，黳髯新白十莖餘。", "主恩空在丹心感，動籍終無一字書。", "出塞鼓旗猶轉戰，近胡桑柘頗稀疏。", "何因別奮陳湯策，北逐天驕瀚海居。"]'),
('ed7a4212-ca5d-4183-a8d9-06bb649a153c','昨晚又捧五章盡含六義意轉新而韻皆緊才益贍而調彌高始知元白之前賢虛擅車斜之美譽夜來遶徧林樹搜窮肺肝雖巧拙以不侔亦謳吟而自得又依前韻各罄乃懷所貴夫伏老之身心亦岡避不量力之譏誚自茲解甲且議休兵向非起予何以爲樂大雅君子無或見咍 一','李至','宋','宋诗','song-poetry','','[]','無營無欲自如如，寂靜空齋晝寢餘。',64,'全唐诗/poet.song.2000.json','["無營無欲自如如，寂靜空齋晝寢餘。", "渴飲三盃市沽酒，閑看一卷道家書。", "奔趨勢利心元薄，接奉交朋老漸疏。", "終指嵩峰待歸去，白雲深處卜巖居。"]'),
('f7b10062-24ce-4735-866f-2ad3cad90413','昨晚又捧五章盡含六義意轉新而韻皆緊才益贍而調彌高始知元白之前賢虛擅車斜之美譽夜來遶徧林樹搜窮肺肝雖巧拙以不侔亦謳吟而自得又依前韻各罄乃懷所貴夫伏老之身心亦岡避不量力之譏誚自茲解甲且議休兵向非起予何以爲樂大雅君子無或見咍 二','李至','宋','宋诗','song-poetry','','[]','吾宗偉量固難如，萬頃澄波更有餘。',64,'全唐诗/poet.song.2000.json','["吾宗偉量固難如，萬頃澄波更有餘。", "吟徧人寰四時景，讀窮仙館百王書。", "青山綠水牽情切，要路權門著意疏。", "只恐愛閑閑未得，華居須作相君居。"]'),
('dac596bf-02df-4d5d-9528-97b91ec94ca0','昨晚又捧五章盡含六義意轉新而韻皆緊才益贍而調彌高始知元白之前賢虛擅車斜之美譽夜來遶徧林樹搜窮肺肝雖巧拙以不侔亦謳吟而自得又依前韻各罄乃懷所貴夫伏老之身心亦岡避不量力之譏誚自茲解甲且議休兵向非起予何以爲樂大雅君子無或見咍 三','李至','宋','宋诗','song-poetry','','[]','甲第新修盡不如，徧栽花卉地無餘。',64,'全唐诗/poet.song.2000.json','["甲第新修盡不如，徧栽花卉地無餘。", "囊中耻貯千金寶，架上惟藏四部書。", "一炷白檀煙細細，百竿脩竹影疏疏。", "終須副却蒼生望，別築沙堤到盛居。"]'),
('63936332-3af9-4a19-bc6b-928b6c8026c0','昨晚又捧五章盡含六義意轉新而韻皆緊才益贍而調彌高始知元白之前賢虛擅車斜之美譽夜來遶徧林樹搜窮肺肝雖巧拙以不侔亦謳吟而自得又依前韻各罄乃懷所貴夫伏老之身心亦岡避不量力之譏誚自茲解甲且議休兵向非起予何以爲樂大雅君子無或見咍 四','李至','宋','宋诗','song-poetry','','[]','老去襟懷强坦如，故園迢遞戰爭餘。',64,'全唐诗/poet.song.2000.json','["老去襟懷强坦如，故園迢遞戰爭餘。", "休思已往曾經事，但訪從來未見書。", "止水寸心常淡靜，亂蓬雙鬢任蕭疏。", "會當懸却車輿後，少室山前別卜居。"]'),
('8d4e3e80-5dea-4619-a4cf-b268c84a32c6','昨晚又捧五章盡含六義意轉新而韻皆緊才益贍而調彌高始知元白之前賢虛擅車斜之美譽夜來遶徧林樹搜窮肺肝雖巧拙以不侔亦謳吟而自得又依前韻各罄乃懷所貴夫伏老之身心亦岡避不量力之譏誚自茲解甲且議休兵向非起予何以爲樂大雅君子無或見咍 五','李至','宋','宋诗','song-poetry','','[]','自念平生誰得如，一家衣食喜盈餘。',64,'全唐诗/poet.song.2000.json','["自念平生誰得如，一家衣食喜盈餘。", "新開北戶都緣竹，特搆南堂只爲書。", "已歎病來懽笑減，那堪老去往還疏。", "謝他蓬島神仙客，時下三清訪陋居。"]'),
('98c54daa-dd72-48ce-ac23-f7db73dde716','尚欠四章別成十首强抽拙思更續殘篇篇既一而意重氣已衰而詞困願容銜璧自此投戈仰瀆台慈不勝慙懼  其一','李至','宋','宋诗','song-poetry','','[]','潘園謝墅想難如，永日風暄宿雨餘。',23,'全唐诗/poet.song.2000.json','["潘園謝墅想難如，永日風暄宿雨餘。", "啼鳥有情疑勸。"]'),
('2c3ffd1d-c474-4bf1-8ce1-eeeb3a139052','尚欠四章別成十首强抽拙思更續殘篇篇既一而意重氣已衰而詞困願容銜璧自此投戈仰瀆台慈不勝慙懼  其二','李至','宋','宋诗','song-poetry','','[]','喜見春。',4,'全唐诗/poet.song.2000.json','["喜見春。"]'),
('b76bf5cc-b89c-40e3-817f-15d65b8cff76','尚欠四章別成十首强抽拙思更續殘篇篇既一而意重氣已衰而詞困願容銜璧自此投戈仰瀆台慈不勝慙懼  其三','李至','宋','宋诗','song-poetry','','[]','池館漸佳天漸暖，一遊應許奉平津。',16,'全唐诗/poet.song.2000.json','["池館漸佳天漸暖，一遊應許奉平津。"]'),
('9ed0390c-59b6-48ae-8377-64cf899c0bca','奉和對雨閑吟之什','李至','宋','宋诗','song-poetry','','[]','南風吹雨驟還收，五月簾櫳却似秋。',64,'全唐诗/poet.song.2000.json','["南風吹雨驟還收，五月簾櫳却似秋。", "陌上莫嫌行未得，田中應待足方休。", "人垂折角衝寒點，馬浸障泥過漫流。", "遥羨文昌新右相，醉吟時伏一金甌。"]'),
('7e518f54-67d0-4981-a3ad-f7b06f03de15','僕射相公以望重位高識分知足因書台抱遽成雅章清苦振瓊爛如裁錦猥蒙寵示實動榮觀輒述鄙懷仰依高韻','李至','宋','宋诗','song-poetry','','[]','霜毛種種已難簪，聖代歸田又未甘。',64,'全唐诗/poet.song.2000.json','["霜毛種種已難簪，聖代歸田又未甘。", "今日忝塵何啻足，昔年貧賤盡曾諳。", "圖書府裏閑堪愛，騷雅門中樂自躭。", "唯恨病來春枉過，花前辜負舊醺酣。"]'),
('3eb888be-9e20-4afa-a951-64bef3875a10','至啟三伏之中若熱尤甚連假之內度日且長忽辱佳篇若諧高會雖勉爲賡載而未盡所懷輒更放於擊轅庶重陳於摇旆亦既燕居之際聊爲大噱之資','李至','宋','宋诗','song-poetry','','[]','夷門山北是朱門，長有丹心感舊恩。',64,'全唐诗/poet.song.2000.json','["夷門山北是朱門，長有丹心感舊恩。", "魏勃更乖持故箒，曹參猶憶舊芳樽。", "梧桐影裏蟬聲急，菡萏香中雨氣昏。", "應得新詩又盈笥，使來多說在西園。"]'),
('6079afb3-f856-4641-8568-a3bce86d931d','至性靈迂僻學術空虛幸逢好古之君獲在藏書之府惟無功而祿重招髦彥之譏而多病所縈實喜優閑之任居常事簡得以狂吟因成惡詩十章以蓬閣多餘暇冠其篇而爲之目亦樂天何處難忘酒之類也塵黷英鑒幸賜一覽下情不任兢灼之至  其一','李至','宋','宋诗','song-poetry','','[]','蓬閣多餘暇，年來又一年。',48,'全唐诗/poet.song.2000.json','["蓬閣多餘暇，年來又一年。", "所臨雖少事，非據亦坊賢。", "品藻殊無取，文章粗有緣。", "聖君應念此，不使掌東銓。"]'),
('3d009953-21dc-471c-96c3-24d4cacbba11','至性靈迂僻學術空虛幸逢好古之君獲在藏書之府惟無功而祿重招髦彥之譏而多病所縈實喜優閑之任居常事簡得以狂吟因成惡詩十章以蓬閣多餘暇冠其篇而爲之目亦樂天何處難忘酒之類也塵黷英鑒幸賜一覽下情不任兢灼之至  其二','李至','宋','宋诗','song-poetry','','[]','蓬閣多餘暇，情孤與世違。',48,'全唐诗/poet.song.2000.json','["蓬閣多餘暇，情孤與世違。", "老嫌知道晚，閑覺近名非。", "禍福隨操履，窮通在隠微。", "所親應笑我，終日掩柴扉。"]'),
('6932c1e9-3a6b-4e20-bb4e-13fd0c631b71','至性靈迂僻學術空虛幸逢好古之君獲在藏書之府惟無功而祿重招髦彥之譏而多病所縈實喜優閑之任居常事簡得以狂吟因成惡詩十章以蓬閣多餘暇冠其篇而爲之目亦樂天何處難忘酒之類也塵黷英鑒幸賜一覽下情不任兢灼之至  其三','李至','宋','宋诗','song-poetry','','[]','蓬閣多餘暇，君恩豈易酬。',48,'全唐诗/poet.song.2000.json','["蓬閣多餘暇，君恩豈易酬。", "病猶豐祿賜，閑勝在林丘。", "風月僧留宿，松筠鶴共遊。", "素餐終不穩，却擬訪漁舟。"]'),
('a06d0e58-6d15-4cc7-ad87-9df95aa8f077','至性靈迂僻學術空虛幸逢好古之君獲在藏書之府惟無功而祿重招髦彥之譏而多病所縈實喜優閑之任居常事簡得以狂吟因成惡詩十章以蓬閣多餘暇冠其篇而爲之目亦樂天何處難忘酒之類也塵黷英鑒幸賜一覽下情不任兢灼之至  其四','李至','宋','宋诗','song-poetry','','[]','蓬閣多餘暇，優游味可知。',48,'全唐诗/poet.song.2000.json','["蓬閣多餘暇，優游味可知。", "宴酣階擁雪，坐久硯生澌。", "遇話聞新事，因閑檢舊詩。", "已成疏懶性，親友莫相嗤。"]'),
('db06388a-e00f-40fd-97f5-5687c6862e42','至性靈迂僻學術空虛幸逢好古之君獲在藏書之府惟無功而祿重招髦彥之譏而多病所縈實喜優閑之任居常事簡得以狂吟因成惡詩十章以蓬閣多餘暇冠其篇而爲之目亦樂天何處難忘酒之類也塵黷英鑒幸賜一覽下情不任兢灼之至  其五','李至','宋','宋诗','song-poetry','','[]','蓬閣多餘暇，捫心或暗思。',48,'全唐诗/poet.song.2000.json','["蓬閣多餘暇，捫心或暗思。", "學應無足日，髮自有衰時。", "庶事曾經目，浮榮病切肌。", "何當卧雲嶺，方寸貯希夷。"]'),
('8644592f-2440-440c-b00c-e04292241304','至性靈迂僻學術空虛幸逢好古之君獲在藏書之府惟無功而祿重招髦彥之譏而多病所縈實喜優閑之任居常事簡得以狂吟因成惡詩十章以蓬閣多餘暇冠其篇而爲之目亦樂天何處難忘酒之類也塵黷英鑒幸賜一覽下情不任兢灼之至  其六','李至','宋','宋诗','song-poetry','','[]','蓬閣多餘暇，羣編得縱觀。',48,'全唐诗/poet.song.2000.json','["蓬閣多餘暇，羣編得縱觀。", "書精新篆籀，畫古舊衣冠。", "故事南朝遠，胡風北史寒。", "不披三兩卷，永日度應難。"]'),
('5ebf22da-77aa-4de6-b447-d31a6de1e9e5','至性靈迂僻學術空虛幸逢好古之君獲在藏書之府惟無功而祿重招髦彥之譏而多病所縈實喜優閑之任居常事簡得以狂吟因成惡詩十章以蓬閣多餘暇冠其篇而爲之目亦樂天何處難忘酒之類也塵黷英鑒幸賜一覽下情不任兢灼之至  其七','李至','宋','宋诗','song-poetry','','[]','蓬閣多餘暇，簪纓不我拘。',48,'全唐诗/poet.song.2000.json','["蓬閣多餘暇，簪纓不我拘。", "杖遊僧舍數，馬過相門疏。", "竹簡藏蝌蚪，芸香避蠹魚。", "已將成四部，猶乞補殘書。"]'),
('d0f89f94-f8e4-4e69-846f-21f3dae1e967','至性靈迂僻學術空虛幸逢好古之君獲在藏書之府惟無功而祿重招髦彥之譏而多病所縈實喜優閑之任居常事簡得以狂吟因成惡詩十章以蓬閣多餘暇冠其篇而爲之目亦樂天何處難忘酒之類也塵黷英鑒幸賜一覽下情不任兢灼之至  其八','李至','宋','宋诗','song-poetry','','[]','蓬閣多餘暇，天寒懶出門。',48,'全唐诗/poet.song.2000.json','["蓬閣多餘暇，天寒懶出門。", "宴眠書幌靜，夜話地爐溫。", "甌觸烹茶鼎，瓢浮著酒盆。", "翻同未應舉，嵩洛住山村。"]'),
('3a3e291e-d2dd-4d16-9010-7b8c964bc2b9','至性靈迂僻學術空虛幸逢好古之君獲在藏書之府惟無功而祿重招髦彥之譏而多病所縈實喜優閑之任居常事簡得以狂吟因成惡詩十章以蓬閣多餘暇冠其篇而爲之目亦樂天何處難忘酒之類也塵黷英鑒幸賜一覽下情不任兢灼之至  其九','李至','宋','宋诗','song-poetry','','[]','蓬閣多餘暇，幽軒好養蒙。',48,'全唐诗/poet.song.2000.json','["蓬閣多餘暇，幽軒好養蒙。", "圖書閑案幾，水墨故屏風。", "雪壓枯松折，莎藏怪石空。", "退朝無一事，盡日鳥聲中。"]'),
('46eb5e38-cac4-438a-8bdd-c174abe62ee9','至性靈迂僻學術空虛幸逢好古之君獲在藏書之府惟無功而祿重招髦彥之譏而多病所縈實喜優閑之任居常事簡得以狂吟因成惡詩十章以蓬閣多餘暇冠其篇而爲之目亦樂天何處難忘酒之類也塵黷英鑒幸賜一覽下情不任兢灼之至  其一○','李至','宋','宋诗','song-poetry','','[]','蓬閣多餘暇，時遊近郭園。',48,'全唐诗/poet.song.2000.json','["蓬閣多餘暇，時遊近郭園。", "畦蔬新雨嫩，野菊未霜繁。", "牛放殘陽草，人耕斷燒原。", "暮歸城闕遠，鐘鼓已喧喧。"]'),
('442ba9ea-6545-4de8-9bff-32fef8138cf5','至啟至學慙半古才不逮人雖酷好風騷而不成文字一聯一詠或偶得於斐然于再于三距可投於作者然而業已思慮忍所弃捐幸冀矜其不能且念伸於知己而又以吾家何所有冠茲五章非敢望於一觀庶更資於一噱瀆則不告其能逭乎  其一','李至','宋','宋诗','song-poetry','','[]','吾家何所有，景物自憐清。',48,'全唐诗/poet.song.2000.json','["吾家何所有，景物自憐清。", "架上書千卷，庭中竹數莖。", "紙窗明雪勢，茶鼎雜松聲。", "多謝南宮長，裁詩慰野情。"]'),
('b86ab72f-c275-43a7-a205-6c47c3816015','至啟至學慙半古才不逮人雖酷好風騷而不成文字一聯一詠或偶得於斐然于再于三距可投於作者然而業已思慮忍所弃捐幸冀矜其不能且念伸於知己而又以吾家何所有冠茲五章非敢望於一觀庶更資於一噱瀆則不告其能逭乎  其二','李至','宋','宋诗','song-poetry','','[]','吾家何所有，非富亦非貧。',48,'全唐诗/poet.song.2000.json','["吾家何所有，非富亦非貧。", "逐月官供俸，隨時自奉身。", "積薪長滿屋，脫粟亦盈囷。", "信美無他慮，其如竊祿人。"]'),
('099bfe6e-2acf-440d-ab42-7289be535de6','至啟至學慙半古才不逮人雖酷好風騷而不成文字一聯一詠或偶得於斐然于再于三距可投於作者然而業已思慮忍所弃捐幸冀矜其不能且念伸於知己而又以吾家何所有冠茲五章非敢望於一觀庶更資於一噱瀆則不告其能逭乎  其三','李至','宋','宋诗','song-poetry','','[]','吾家何所有，冬月勝袁安。',48,'全唐诗/poet.song.2000.json','["吾家何所有，冬月勝袁安。", "紙帳可床暖，地爐容客寬。", "樹頭風勢大，窗外雪聲乾。", "却念無衣者，何當度此寒。"]'),
('c57e9e21-bf55-4a19-bce4-c9a90e19785b','至啟至學慙半古才不逮人雖酷好風騷而不成文字一聯一詠或偶得於斐然于再于三距可投於作者然而業已思慮忍所弃捐幸冀矜其不能且念伸於知己而又以吾家何所有冠茲五章非敢望於一觀庶更資於一噱瀆則不告其能逭乎  其四','李至','宋','宋诗','song-poetry','','[]','吾家何所有，滿地是蒼苔。',48,'全唐诗/poet.song.2000.json','["吾家何所有，滿地是蒼苔。", "短褐朝迴著，閑門客到開。", "黄精充果實，白薤助羹杯。", "澹薄長娛此，交親莫見咍。"]'),
('547efe7c-8d5f-45d3-bcd5-77e5a39a57d0','至啟至學慙半古才不逮人雖酷好風騷而不成文字一聯一詠或偶得於斐然于再于三距可投於作者然而業已思慮忍所弃捐幸冀矜其不能且念伸於知己而又以吾家何所有冠茲五章非敢望於一觀庶更資於一噱瀆則不告其能逭乎  其五','李至','宋','宋诗','song-poetry','','[]','吾家何所有，別墅在城南。',48,'全唐诗/poet.song.2000.json','["吾家何所有，別墅在城南。", "寒木葉如柿，春溝水似□。", "樹深鳴乳犢，室暗養新蠶。", "溫飫每來此，主人無限慚。"]'),
('19ce9227-bf9c-4c0c-8f73-07e5d13b891b','至啟休沐之中靜專一室病不復飲無以慰懷性且寡合若何爲樂但窗閒弄筆信意亂書無所從意無所得自如而已豈曰詩乎不覺又成五章章之首句皆云朱門多好景蓋紀田第園林之勝美明公游豫之適昔張處士獻牛奇章詩尤鱠炙人口其警句有带盤紅鼴鼠袍砑紫犀牛之盛然而清議者不以爲累公之德何哉賦閑讌而歌富貴也小子是作焉敢望回然亦駑駘之希驥爾  其一','李至','宋','宋诗','song-poetry','','[]','朱門多好景，清共佛鄰牆。',48,'全唐诗/poet.song.2000.json','["朱門多好景，清共佛鄰牆。", "風遞何僧磬，煙聞那院香。", "水聲流靜夜，塔影卧斜陽。", "秖是宮城遠，趨朝較數坊。"]'),
('9a8e0c4e-aa10-4a1c-99ce-6e583a2919a8','至啟休沐之中靜專一室病不復飲無以慰懷性且寡合若何爲樂但窗閒弄筆信意亂書無所從意無所得自如而已豈曰詩乎不覺又成五章章之首句皆云朱門多好景蓋紀田第園林之勝美明公游豫之適昔張處士獻牛奇章詩尤鱠炙人口其警句有带盤紅鼴鼠袍砑紫犀牛之盛然而清議者不以爲累公之德何哉賦閑讌而歌富貴也小子是作焉敢望回然亦駑駘之希驥爾  其二','李至','宋','宋诗','song-poetry','','[]','朱門好景多，全宅在園林。',48,'全唐诗/poet.song.2000.json','["朱門好景多，全宅在園林。", "席上攀紅艷，階前蹋綠陰。", "牡丹疑國色，孔雀是家禽。", "珍重主人意，開樽日易沈。"]'),
('a529f333-15fb-4a1f-97b1-a7f10a65112e','至啟休沐之中靜專一室病不復飲無以慰懷性且寡合若何爲樂但窗閒弄筆信意亂書無所從意無所得自如而已豈曰詩乎不覺又成五章章之首句皆云朱門多好景蓋紀田第園林之勝美明公游豫之適昔張處士獻牛奇章詩尤鱠炙人口其警句有带盤紅鼴鼠袍砑紫犀牛之盛然而清議者不以爲累公之德何哉賦閑讌而歌富貴也小子是作焉敢望回然亦駑駘之希驥爾  其三','李至','宋','宋诗','song-poetry','','[]','朱門好景多，五月亦清凉。',48,'全唐诗/poet.song.2000.json','["朱門好景多，五月亦清凉。", "地勝長膏潤，泉甘劇蔗漿。", "樹深無日到，逕僻有莎荒。", "但恐裴腫令，虛誇綠野堂。"]'),
('00b71d7f-b92d-48a3-aeac-2344e6b3512b','至啟休沐之中靜專一室病不復飲無以慰懷性且寡合若何爲樂但窗閒弄筆信意亂書無所從意無所得自如而已豈曰詩乎不覺又成五章章之首句皆云朱門多好景蓋紀田第園林之勝美明公游豫之適昔張處士獻牛奇章詩尤鱠炙人口其警句有带盤紅鼴鼠袍砑紫犀牛之盛然而清議者不以爲累公之德何哉賦閑讌而歌富貴也小子是作焉敢望回然亦駑駘之希驥爾  其四','李至','宋','宋诗','song-poetry','','[]','朱門好景多，況復九秋中。',48,'全唐诗/poet.song.2000.json','["朱門好景多，況復九秋中。", "積雨凉生簟，凝霜夜著桐。", "槐陰堆敗葉，菊蘂被幽叢。", "閑對籃輿客，翛然此興同。"]'),
('a1b2bffb-6c80-4422-b41b-2dbaedd648a9','至啟休沐之中靜專一室病不復飲無以慰懷性且寡合若何爲樂但窗閒弄筆信意亂書無所從意無所得自如而已豈曰詩乎不覺又成五章章之首句皆云朱門多好景蓋紀田第園林之勝美明公游豫之適昔張處士獻牛奇章詩尤鱠炙人口其警句有带盤紅鼴鼠袍砑紫犀牛之盛然而清議者不以爲累公之德何哉賦閑讌而歌富貴也小子是作焉敢望回然亦駑駘之希驥爾  其五','李至','宋','宋诗','song-poetry','','[]','朱門好景多，寒月動情憀。',48,'全唐诗/poet.song.2000.json','["朱門好景多，寒月動情憀。", "爐炭蹲紅獸，裘花鬭紫貂。", "管弦多盞困，風雪玉銜驕。", "誰似天人福，皆從積善招。"]'),
('62993d73-8c8f-4e6e-af41-1dc98a30e7d1','庭中千葉玫瑰今春盛發爛然可愛因賦一章寄上僕射相公','李至','宋','宋诗','song-poetry','','[]','小檻鎖玫瑰，羣芳次第催。',168,'全唐诗/poet.song.2000.json','["小檻鎖玫瑰，羣芳次第催。", "刺多疑有妬，艷絕却無媒。", "露灑啼粧在，風牽舞態迴。", "層苞不暇吐，數日未能開。", "爛勝燕脂顆，殷於烈焰堆。", "濃將丹筆染，碎把絳綃裁。", "漠漠香如芷，青于葉似苔。", "夭難勝暖日，靜不惹纖埃。", "遠對褰書幌，傍觀置酒盃。", "朵稀心暗記，根淺手親培。", "雉控眠偷摘，僧逢醉覓栽。", "盡嘲終彷彿，擬折又徘徊。", "麗奪傾城色，吟歸間世才。", "多情百花主，聞必有詩來。"]'),
('02dde2a9-7178-48b9-8018-141e2cc4415a','至啟伏蒙寵惠寶相花數朵爛然可觀發鈿合之中纔驚絕艷睹彩牋之上又辱佳篇感歎既盈詠歌斯作輒依高韻拜獻拙詩一首','李至','宋','宋诗','song-poetry','','[]','萬里移來種，成都到上都。',48,'全唐诗/poet.song.2000.json','["萬里移來種，成都到上都。", "貴人猶乍有，貧舍固然無。", "掩斂難勝艷，鮮妍欲奪朱。", "此花輕折贈，可表受知殊。"]'),
('f1061ce9-0b88-4713-abfd-cd242dca3037','節假之中風氣又作僅將伏枕固難登門更獻五章代伸一謁疲兵再戰已取敗於空弮下客請行尚費詞於露穎徒堪大噱豈足徧酬雖投刃皆虛岡睹全牛之狀然援毫而就亦勞倚馬之才但冀覽之斯爲幸矣  其一','李至','宋','宋诗','song-poetry','','[]','出門何所適，馬亦認余情。',48,'全唐诗/poet.song.2000.json','["出門何所適，馬亦認余情。", "轉曲纔東去，嘶風便北行。", "樹高牆外見，犬熟道邊迎。", "可處多相對，南軒景最清。"]'),
('49f1de61-2178-4322-b86c-d3e1e5f7ee88','節假之中風氣又作僅將伏枕固難登門更獻五章代伸一謁疲兵再戰已取敗於空弮下客請行尚費詞於露穎徒堪大噱豈足徧酬雖投刃皆虛岡睹全牛之狀然援毫而就亦勞倚馬之才但冀覽之斯爲幸矣  其二','李至','宋','宋诗','song-poetry','','[]','出門何所適，祕閣倚宮牆。',48,'全唐诗/poet.song.2000.json','["出門何所適，祕閣倚宮牆。", "風遞禁中樂，日聞天外香。", "移屏畫鶴立，開帙蠹魚藏。", "不覺新詩債，朝來又一箱。"]'),
('dc103ec4-77b0-4257-bb85-7de12d6308c0','節假之中風氣又作僅將伏枕固難登門更獻五章代伸一謁疲兵再戰已取敗於空弮下客請行尚費詞於露穎徒堪大噱豈足徧酬雖投刃皆虛岡睹全牛之狀然援毫而就亦勞倚馬之才但冀覽之斯爲幸矣  其三','李至','宋','宋诗','song-poetry','','[]','出門何所適，他處跡皆疏。',48,'全唐诗/poet.song.2000.json','["出門何所適，他處跡皆疏。", "不是陪端揆，多應訪老徐。", "文章今大手，道德古名儒。", "何必逢荀令，馨香自有餘。"]'),
('1d74d794-8b20-49d7-85db-06ff12958955','節假之中風氣又作僅將伏枕固難登門更獻五章代伸一謁疲兵再戰已取敗於空弮下客請行尚費詞於露穎徒堪大噱豈足徧酬雖投刃皆虛岡睹全牛之狀然援毫而就亦勞倚馬之才但冀覽之斯爲幸矣  其四','李至','宋','宋诗','song-poetry','','[]','出門何所適，遇興即留連。',48,'全唐诗/poet.song.2000.json','["出門何所適，遇興即留連。", "野寺微茫雪，漁家冷淡煙。", "地爐寒擁坐，癭枕醉欹眠。", "帝顧應相笑，吾心自泰然。"]'),
('a39a92a1-3af3-49b7-b1cc-428bcd840765','節假之中風氣又作僅將伏枕固難登門更獻五章代伸一謁疲兵再戰已取敗於空弮下客請行尚費詞於露穎徒堪大噱豈足徧酬雖投刃皆虛岡睹全牛之狀然援毫而就亦勞倚馬之才但冀覽之斯爲幸矣  其五','李至','宋','宋诗','song-poetry','','[]','出門何所適，門外雪如花。',48,'全唐诗/poet.song.2000.json','["出門何所適，門外雪如花。", "不是居蘭省，應須在酒家。", "爐灰香爆栗，庭葉碎烹茶。", "欲訪山陰戴，孤舟去路賒。"]'),
('49cac43a-dce9-4aa6-997c-1278728de293','奉和對海紅花見寄之什','李至','宋','宋诗','song-poetry','','[]','春風仙杏枝，條忽吹成果。',120,'全唐诗/poet.song.2000.json','["春風仙杏枝，條忽吹成果。", "墓雨牡丹苞，凄凉飄去我。", "獨有海紅花，一叢千萬朵。", "深似猩血染，香於麝臍破。", "繁壓玉欄霞，紅燒翠鬟火。", "俗呼錦被堆，又有何不可。", "僕射多才情，新停濟川舸。", "閑遶復相思，醉袖花邊嚲。", "吟成數十字，安安明珠顆。", "魚目輒還公，莫笑輕酬麽。"]'),
('9891824f-fded-465a-83d3-caaea6f02157','那日獲詣芳園竊見新栽叢竹蕭然可愛不能無詩輒獻五章望垂台顧  其一','李至','宋','宋诗','song-poetry','','[]','園中比比是花欄，史欠修篁十數竿。',64,'全唐诗/poet.song.2000.json','["園中比比是花欄，史欠修篁十數竿。", "時見此君憐淅瀝，春來何處得檀欒。", "黄初換葉應深惜，綠未成陰已好看。", "看取北窗風更冷，不須炎月用冰盤。"]'),
('0dac3ce6-8841-4c06-9ed0-231e16221ee6','那日獲詣芳園竊見新栽叢竹蕭然可愛不能無詩輒獻五章望垂台顧  其二','李至','宋','宋诗','song-poetry','','[]','子猷曾有風流語，一日不能無此君。',64,'全唐诗/poet.song.2000.json','["子猷曾有風流語，一日不能無此君。", "相國近添蕭灑興，數莖應怪乍離羣。", "寬圍朱檻朱猶濕，密占青苔青自分。", "若見仙翁莫輕許，携將飛入葛陂雲。"]'),
('4c29e512-9266-4d33-b051-cd680713c598','那日獲詣芳園竊見新栽叢竹蕭然可愛不能無詩輒獻五章望垂台顧  其三','李至','宋','宋诗','song-poetry','','[]','疏籬簇簇湘江畔，翠美森森淇水邊。',64,'全唐诗/poet.song.2000.json','["疏籬簇簇湘江畔，翠美森森淇水邊。", "爭似移歸深院裏，真同畫向後堂前。", "粉筠應惜裁龍笛，霜鍤還驚斷馬鞭。", "不是多情誰解愛，手栽吟遶溉新泉。"]'),
('f577875e-8632-49a5-ac8e-06f33fef8b66','那日獲詣芳園竊見新栽叢竹蕭然可愛不能無詩輒獻五章望垂台顧  其四','李至','宋','宋诗','song-poetry','','[]','節節皆勻葉葉疏，相門翻似子猷居。',64,'全唐诗/poet.song.2000.json','["節節皆勻葉葉疏，相門翻似子猷居。", "狂根或带移時土，紅草應勞種後鋤。", "醒酒韻寒初愜意，出牆梢健已凌虛。", "不須更用他泉溉，霖雨纔收必有餘。"]'),
('458521eb-6eae-41a2-9ad4-b1fa0c777ddb','那日獲詣芳園竊見新栽叢竹蕭然可愛不能無詩輒獻五章望垂台顧  其五','李至','宋','宋诗','song-poetry','','[]','欲取琅玕斸翠苔，北扉特爲爾新開。',64,'全唐诗/poet.song.2000.json','["欲取琅玕斸翠苔，北扉特爲爾新開。", "手題詩句從僧覓，親卓筇枝揀地栽。", "紅粉遶叢遺細朵，綠醪偷影入金盃。", "莫憂裁作漁竿用，已向磻谿下釣來。"]'),
('b5fd44b0-5f24-4f61-96ed-44ed08e79d24','所苦之中無以遣悶更題新竹別獻五章幸賜披覽  其一','李至','宋','宋诗','song-poetry','','[]','牡丹灼灼看何厭，芍藥夭夭種已多。',65,'全唐诗/poet.song.2000.json','["牡丹灼灼看何厭，芍藥夭夭種已多。", "却要閒紅兼閒紫，不辭侵逕復又莎。", "舊根今歲移纔活，新笋前春新出便過。", "猶欠小桃花兩樹，夾叢爭艷壓枝柯。"]'),
('703a254e-c626-4aa1-bbe5-c96a75926b73','所苦之中無以遣悶更題新竹別獻五章幸賜披覽  其二','李至','宋','宋诗','song-poetry','','[]','不似溪邊本自芳，且須將護少同防。',64,'全唐诗/poet.song.2000.json','["不似溪邊本自芳，且須將護少同防。", "兒童縱未騎爲馬，鄰舍潜應引過牆。", "乾籜墜莎何用掃，嫩根撐砌莫嫌妨。", "就中此地尤難得，惱殺東都白侍郎。"]'),
('22ceebe0-7749-4925-8f59-0014f870b22a','所苦之中無以遣悶更題新竹別獻五章幸賜披覽  其三','李至','宋','宋诗','song-poetry','','[]','蓽爲扉闔槿爲藩，不似公家地盡寬。',64,'全唐诗/poet.song.2000.json','["蓽爲扉闔槿爲藩，不似公家地盡寬。", "階下纔容數片席，窗前也種十餘竿。", "蝸牛舍畔幽叢小，行馬門中翠影寒。", "應似鷦鷯與鵬鳥，一枝層漢各心安。"]'),
('5d3b7edc-c4cb-4708-906d-055f9d6e434c','所苦之中無以遣悶更題新竹別獻五章幸賜披覽  其四','李至','宋','宋诗','song-poetry','','[]','請公屈指數朱門，誰肯孜孜愛此君。',64,'全唐诗/poet.song.2000.json','["請公屈指數朱門，誰肯孜孜愛此君。", "小檻縱多栽紫艷，閑庭且要曳紅裙。", "三冬翠色終難犯，五月秋聲早已聞。", "不是風流賢宰相，何人移爾入花羣。"]'),
('c2296f7a-9f54-4ece-ad7e-5aed7c715311','所苦之中無以遣悶更題新竹別獻五章幸賜披覽  其五','李至','宋','宋诗','song-poetry','','[]','疏叢宜少不宜多，多後盤根不奈何。',64,'全唐诗/poet.song.2000.json','["疏叢宜少不宜多，多後盤根不奈何。", "出檻新枝罥冠冕，上階狂笋礙笙歌。", "傍翹野鶴人難畫，對酌罇醪日易過。", "若更引泉兼雅稱，門前咫尺是長波。"]'),
('f39d1c80-6df1-40e9-b840-7fb1c9b57c55','依韻奉和來篇','李至','宋','宋诗','song-poetry','','[]','紅塵赤日欲相燃，頼向蓬丘少事牽。',64,'全唐诗/poet.song.2000.json','["紅塵赤日欲相燃，頼向蓬丘少事牽。", "明月動摇紈扇室，亂雲重疊火□天。", "幽屏看雪思寒景，小簟橫風戀畫眠。", "安得心源凉似水，虎溪遥羨老僧禪。"]'),
('53261513-6b2e-44bc-9c8f-372b0d0463b8','依韻奉和來篇','李至','宋','宋诗','song-poetry','','[]','閑書閑畫滿芸香，卧讀行看固是常。',64,'全唐诗/poet.song.2000.json','["閑書閑畫滿芸香，卧讀行看固是常。", "天爲苦吟終借□，帝憐多病不教忙。", "泥封法醖醅猶嫩，茶煮頒冰味更長。", "一榻清風兼好獻，可能來此就儂嘗。"]'),
('bdfb0ede-679c-4639-a9ac-705feb3a2184','夏日直祕閣','李至','宋','宋诗','song-poetry','','[]','蓬閣清虛稱野情，華陽巾穩葛衣輕。',64,'全唐诗/poet.song.2000.json','["蓬閣清虛稱野情，華陽巾穩葛衣輕。", "垂簾不見喧囂事，盡日唯聞禽鳥聲。", "小檜影中鋪硯席，短槐陰下著茶鐺。", "却愁窮巷晚歸去，塵土滿街衝熱行。"]'),
('d9bc49a4-0f2a-4c64-a5c2-bc2c8134571f','暑夜偶作','李至','宋','宋诗','song-poetry','','[]','竹氣荷香夜轉清，趁凉移簟遶空庭。',64,'全唐诗/poet.song.2000.json','["竹氣荷香夜轉清，趁凉移簟遶空庭。", "坊門有月幾多樹，池水無風三四星。", "何處一蟬猶切切，此時殘漏尚丁丁。", "可憐好夢誰驚覺，正戀五湖吹酒醒。"]'),
('26e22664-d6a9-44e7-a3ea-a1155e71bc51','至啟至數日前久疏投刺略遂登門方媿非才過叨奇遇豈謂愛忘之眷遽貽和寡之詞儻取庸音何伸鄙抱謹課一章兼次高韻','李至','宋','宋诗','song-poetry','','[]','相留不稱主人心，多病虛勞酒滿斟。',64,'全唐诗/poet.song.2000.json','["相留不稱主人心，多病虛勞酒滿斟。", "廳事便臨芳草逕，庖厨只就綠槐陰。", "玫瑰出檻參差拆，薜荔依牆積漸深。", "却恨無情是朝日，暫陪懽笑已西沈。"]'),
('47ba5082-6335-47de-a884-6403c04ceda0','偶述鄙懷奉呈僕射相公','李至','宋','宋诗','song-poetry','','[]','從來迂僻寡朋儔，今日優恩豈自酬。',64,'全唐诗/poet.song.2000.json','["從來迂僻寡朋儔，今日優恩豈自酬。", "抱病也容居粉署，好吟仍使在蓬丘。", "利名場裏心尤拙，少俊叢中鬢獨秋。", "早晚東山拂衣去，願携鳩杖從公遊。"]'),
('8fc1ed1e-d6aa-4647-8b83-9de045bb216c','僕射相公思縟春榮詞含古雅忽成絕唱以導高情仍率短才俾次前韻安敢藏拙聊奉諭言','李至','宋','宋诗','song-poetry','','[]','行穿花竹戶庭幽，只下堂階便且遊。',64,'全唐诗/poet.song.2000.json','["行穿花竹戶庭幽，只下堂階便且遊。", "紅蕊向人含艷態，黄鸞代客說春愁。", "遶牀文史堪怡悅，滿席笙歌好獻酬。", "未必此時閒適趣，不如前日鳳池頭。"]'),
('0136496c-932d-4125-bf43-9b7ca6982505','奉和牡丹盛開之什','李至','宋','宋诗','song-poetry','','[]','主人多思惜芬度，醉遶吟攀自是常。',64,'全唐诗/poet.song.2000.json','["主人多思惜芬度，醉遶吟攀自是常。", "爛欲燒叢渾是焰，穠來薰物甚於香。", "妬偎羅綺迷春眼，狂聒笙歌費酒腸。", "久病勞公誤相問，不同前作粉闈郎。"]'),
('13a377c9-f4a5-493f-9591-760d9f1c5561','至啟伏蒙台慈以南至之後見寄佳篇豈曰奉酬輒次高韻','李至','宋','宋诗','song-poetry','','[]','流年冉冉不曾停，合向勞生養道情。',64,'全唐诗/poet.song.2000.json','["流年冉冉不曾停，合向勞生養道情。", "萬物已憐成復象，一陽還見動勾萌。", "南躔日轉階前影，北陸風吹樹杪聲。", "看即東宮布時令，綠楊堤上有閑行。"]'),
('0585a0a5-b952-4f25-a265-bb1e9f042f46','至啟伏以僕射相公丁一賢之運鐘四輸之才黄金照社以炳靈素練升天而入夢當就盈之良月過載誕之佳辰儻慙下俚之拙詞曷表中心之善祝輒形微詠願續遐齡','李至','宋','宋诗','song-poetry','','[]','遥想佳辰宴畫堂，清歌一曲遶雕梁。',64,'全唐诗/poet.song.2000.json','["遥想佳辰宴畫堂，清歌一曲遶雕梁。", "歲星降後蒼生福，元化調來聖祚昌。", "塵外松身千載老，海中椿樹萬年芳。", "閑曹隨分多拘束，不得躬親捧壽觴。"]'),
('378ae5e1-e212-4a3c-937c-a8aa234ac6b4','伏蒙承旨學士特贈寵招慙非嘉客陪列仙于丹地觀盛事於玉堂御題禁署之名勢娛飛動聖制大風之作鏗若宮商一時併耀于蓬瀛三體互成于真草昔太宗之優待學士日預論思明皇之寵尚集賢時聞臨幸以今況昔異代同榮至謬亞冢卿獲司中祕啗牛心而不稱陪塵尾以何□□銜樂聖之杯且乏如賓之賦嗟嘆不足歌詠輒興雖勞燥吻之冥搜終類擊轅之陋唱仰塵高鑒聊抒下情','李至','宋','宋诗','song-poetry','','[]','昔陪羣彥在鼇山，今日重來越玳筵。',96,'全唐诗/poet.song.2000.json','["昔陪羣彥在鼇山，今日重來越玳筵。", "纔向玉堂觀聖札，又離瑶席睹宸篇。", "二南絕唱人驚駭，三體神蹤鳳折旋。", "坐久庭柯移午影，飲酣宮吹遞香烟。", "吟求視草牋分寫，醉假通中枕暫眠。", "俗客不知仙禁近，高歌共樂太平年。"]'),
('52350d6c-d26f-44dc-acc0-2a4b7346d790','桃花犬歌呈修史錢侍郎','李至','宋','宋诗','song-poetry','','[]','宮中有犬桃花名，絳繒圍頸懸金鈴。',192,'全唐诗/poet.song.2000.json','["宮中有犬桃花名，絳繒圍頸懸金鈴。", "先皇爲愛馴且異，指顧之間知上意。", "珠簾未卷扇未開，桃花援尾常先至。", "夜靜不離香砌眠，朝饑祇傍御床餧。", "彩雲路熟不勞牽，瑶草風微有時吠。", "無何軒后鑄鼎成，忽遺弓劍棄寰瀛。", "迢迢松闕伊川上，遠逐龍輴十數程。", "兩眥漣漣似垂淚，骨見毛寒頓顦悴。", "萬人見者倍傷心，微物感恩猶若是。", "韓盧備獵何足嘉，西旅充庭豈爲瑞。", "聞君奉詔修實錄，一字爲褒應不曲。", "白魚赤雁且勿書，願君書此懲浮俗。"]'),
('d1dc3c72-df1d-45d4-bf89-83499c927abf','題義門胡氏華林書院','李至','宋','宋诗','song-poetry','','[]','牆頭翠色雲分嶺，井底泉聲瀑落崖。',64,'全唐诗/poet.song.2000.json','["牆頭翠色雲分嶺，井底泉聲瀑落崖。", "講席日聞談俎豆，書厨時見整竿牌。", "野猿有果頻窺檻，山鳥無人忽下階。", "好是魯儒爭就學，不辭千里過江淮。"]'),
('dc328a7a-6dd6-4ac1-9c24-10d378d55e6b','袁姬哀辭','柳開','宋','宋诗','song-poetry','','[]','彼美袁姬兮，柔芳懿懿。',187,'全唐诗/poet.song.2000.json','["彼美袁姬兮，柔芳懿懿。", "瑶沈蕣瘁兮，追惟弗洎。", "陰質弱卑兮，資陽望貴。", "壽康攸遂兮，夭愆所利。", "北塞南荒兮，偕行萬里。", "寧期不修兮，溘然而逝。", "奔服勤劬兮，喪爾母子。", "恫毒我懷兮，摧傷骨髓。", "高旻孔仁兮，皇適予委。", "明知有生兮，亦必有死。", "無如奈何兮，情思岡已。", "倏焉胡往兮，音容莫寄。", "餘玩遺香兮，忍孰爲視。", "桂山嶄嶄兮，翠攢若指。", "曷能可忘兮，我心於此。", "西流之日兮，東流之水。", "瞬息一去兮，終天遠矣。"]'),
('d7814f4b-6f8b-401f-9f00-6cf7cfc0826b','贈夢英詩','柳開','宋','宋诗','song-poetry','','[]','晝光夜魄陰陽祖，五緯天立五行父。',200,'全唐诗/poet.song.2000.json','["晝光夜魄陰陽祖，五緯天立五行父。", "萬靈蕃昌根此樹，剛柔各鬭清濁聚。", "形類紛然填下土，精英閒見羣寧侶。", "雄劇唯神時可主，功格無先明競睹。", "捨羊犬猪用彪虎，氣包茫昧廓區宇。", "刓髮披緇心有取，蛻免羈跼脫潜去。", "身投西佛學東魯，塵視諸徒飈遠舉。", "狂呼飽醉賤今古，公室侯庭迎走戶。", "如攀喬柯腰俯僂，搜經抉誥將完補。", "聲號大荒鏗簨簴，筆詬斯冰卑爾汝。", "戟枝曳陣孰禦侮，二十游秦老還楚。", "蛟蟠枯泓驥追鼠，停舟湘濆吾興語。", "歸返終南恨睽阻。"]'),
('27f38b5b-7b38-45b4-bce5-9931c133ef89','諷虞嬪詩','柳開','宋','宋诗','song-poetry','','[]','惟堯則天舜弗復，誕妃岡極恩亭育。',152,'全唐诗/poet.song.2000.json','["惟堯則天舜弗復，誕妃岡極恩亭育。", "遏密無聞血盈目，南巡胡爲淚染竹。", "父輕夫重當何淑，沅湘岸筠烟莓覆。", "凝紋疊斑殷郁郁，猿緣鼯號鉤輈宿。", "朋悽助惋聲幾哭，賸疑下尤禹湮瀆。", "功充民戴荷百祿，重暉並耀難停轂。", "元居不寧逝如逐，悲啼負冤生莫卜。", "卒顛沈瀾遠昌族，謳訟肇私歸永福，柔陰慘尅咎深速。", "前睇九山排矗矗，到今雲顔愁可掬。"]'),
('d40ad54e-2904-4160-8d4d-87bcac558516','贈諸進士詩','柳開','宋','宋诗','song-poetry','','[]','今年舉進士，必誰登高第。',192,'全唐诗/poet.song.2000.json','["今年舉進士，必誰登高第。", "孫傳及孫僅，外復有丁謂。", "到京見陳訪，好尚同韓洎。", "館中諸仙郎，綸閤賢三字。", "翰林四主人，列辟羣英粹。", "厝騰走大名，淜轟天邑沸。", "怒浪航斯濟，駿蹄御良轡。", "緣險徑梯空，餓腸勞填味。", "我何爲欣歡，名身苦將悴。", "北塞絕戎勳，南荒政遭墜。", "焦焦家殫窮，口衆食增累。", "雛豝餘十輩，業學莫能器。", "髮白壯心衰，不覺老之至。", "跼縮步九衢，羞畏同腐婢。", "仰瞻爾數子，吾道終焉寄。", "無爲忽于予，斯文幸專繼。"]'),
('394e55a5-81ec-44c5-9f21-e551a9eedc17','與姪柳瀛','柳開','宋','宋诗','song-poetry','','[]','皇唐二百八十年，柳氏家門世有賢。',64,'全唐诗/poet.song.2000.json','["皇唐二百八十年，柳氏家門世有賢。", "出衆文章惟子厚，不羣書札獨公權。", "本朝事去同灰燼，聖代吾思紹衫先。", "感歎盡應餘慶在，今來見汝又堪憐。"]'),
('f9794c53-9eec-4722-a7fb-2f568b4786ba','塞上','柳開','宋','宋诗','song-poetry','','["\u8fb9\u585e", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5199\u4eba", "\u5b8b\u8bd7"]','鳴髇直上一千尺，天靜無風聲更乾。',32,'全唐诗/poet.song.2000.json','["鳴髇直上一千尺，天靜無風聲更乾。", "碧眼胡兒三百騎，盡提金勒向雲看。"]'),
('6c528bdf-d407-4947-ad95-8a733c4c0037','磐石','柳開','宋','宋诗','song-poetry','','[]','古寺聳山椒，公堂去不遥。',48,'全唐诗/poet.song.2000.json','["古寺聳山椒，公堂去不遥。", "尋僧忘俗慮，盤道出塵囂。", "疏箔捲煙霧，明時望泬漻。", "漁翁江上立，指我在雲霄。"]'),
('6dae06b4-3d44-47df-a19d-88ac1accc365','楚南偉觀樓','柳開','宋','宋诗','song-poetry','','[]','洗盡蠻烟幾案空，登臨直見楚山雄。',64,'全唐诗/poet.song.2000.json','["洗盡蠻烟幾案空，登臨直見楚山雄。", "坐當鴻鵠高飛處，身在乾坤灝氣中。", "木落有情瞻北闕，霜輕無夢入西風。", "凭蘭自是蓬瀛客，獨對瀟湘與未窮。"]'),
('7c3e31a0-5cfc-4bd6-8976-73a17c9345e1','句  其一','柳開','宋','宋诗','song-poetry','','[]','空門今日見張華。',8,'全唐诗/poet.song.2000.json','["空門今日見張華。"]'),
('581dcfd5-9985-47a0-b57f-832e2921843d','句  其二','柳開','宋','宋诗','song-poetry','','[]','九重城闕新天子，萬卷詩書老舍人。',16,'全唐诗/poet.song.2000.json','["九重城闕新天子，萬卷詩書老舍人。"]'),
('1a2456f1-6b74-4b0b-b5d0-915c0456a3fc','送人謁柳開','釋正緣','宋','宋诗','song-poetry','','[]','柳牆高於花，怒飛方可至。',24,'全唐诗/poet.song.2000.json','["柳牆高於花，怒飛方可至。", "奇哉游夏徒，吐辭作雄翅。"]'),
('c08043c2-3fec-4eec-bdfb-23d607bdbb76','送僧歸天寧萬年禪院','吳淑','宋','宋诗','song-poetry','','[]','偶携筇杖辭青嶂，便賜蘭牙染紫衣。',64,'全唐诗/poet.song.2000.json','["偶携筇杖辭青嶂，便賜蘭牙染紫衣。", "城闕暫隨明月至，江湖還共白雲歸。", "樓中夕照山川秀，盤裏春蔬筍蕨肥。", "我爲浮名閒未得，他時蓮社願相依。"]'),
('f75f04b9-104a-42e4-8f88-f30bf97563a9','題義門胡氏華林書院','吳淑','宋','宋诗','song-poetry','','[]','高隠仙山下，依山携草堂。',192,'全唐诗/poet.song.2000.json','["高隠仙山下，依山携草堂。", "窮年樂石水，切意玩縑緗。", "竹徑來嵇阮，魚梁集惠莊。", "論文探致極，尋古襲遺芳。", "沉意詩書苑，游心翰墨場。", "海鵬潜羽翼，露豹郁文章。", "俠洽千門慶，聯翩却桂香。", "活和資勝景，變化得神方。", "虛檻臨寒水，平皋占夕陽。", "溪雲蒸柱礎，嵐氣潤衣裳。", "露葉飄書幌，風花落酒觴。", "往還乘月喜，酬唱爲春忙。", "宗族傳雍睦，門閭被寵光。", "高情誰可及，積善不能量。", "顧我何爲者，多年別故鄉。", "他時歸計遂，依附葺雲房。"]'),
('854e9bf0-94d8-4e8b-8eb9-315571a7902f','句  其一','吳淑','宋','宋诗','song-poetry','','[]','浴殿夜凉初閣筆，渚宮秋晚得懸車。',16,'全唐诗/poet.song.2000.json','["浴殿夜凉初閣筆，渚宮秋晚得懸車。"]'),
('62554763-afc3-4254-8284-354576c0e26a','句  其二','吳淑','宋','宋诗','song-poetry','','[]','曉羹沉玉杵，寒鮓疊金綿。',12,'全唐诗/poet.song.2000.json','["曉羹沉玉杵，寒鮓疊金綿。"]'),
('9703b1b6-9985-40d2-933e-4ed7661c9687','伏睹禁林新成盛事輒思歌詠不避荒蕪上李學士','李沆','宋','宋诗','song-poetry','','[]','禁庭多士列華簪，嚴樂輝光冠古今。',97,'全唐诗/poet.song.2000.json','["禁庭多士列華簪，嚴樂輝光冠古今。", "御筆騰驤題玉署，宸章照耀詠辭林。", "虛堂掛後傳千載，翠琰刊成直萬金。", "振復文明知聖作，尊崇儒術見天心。", "增修一院煙霞麗主，曲宴羣英雨露深。", "自我昌朝爲盛事，鼇山清峻重難尋。"]'),
('e05cd9a5-fe75-4fe1-bc5a-0204be1349a0','貢院鎖宿聞呂員外使高麗贈徐騎省','李沆','宋','宋诗','song-poetry','','[]','聖化今無外，片途莫憚賒。',48,'全唐诗/poet.song.2000.json','["聖化今無外，片途莫憚賒。", "揚帆箕子國，駐節管寧家。", "去伴千年鶴，歸逢八月槎。", "離情恨華省，持此待疏麻。"]'),
('6535ea43-ac8c-4624-a9ce-8533db8c9da4','題六和塔','李沆','宋','宋诗','song-poetry','','[]','經從塔下幾春秋，每恨無因到上頭。',32,'全唐诗/poet.song.2000.json','["經從塔下幾春秋，每恨無因到上頭。", "今日始知高處險，不如歸卧舊林丘。"]'),
('149f49e8-aa35-4d76-97e2-d9d7bb62d98d','禁林讌會之什','呂祐之','宋','宋诗','song-poetry','','[]','高會蓬瀛振德音，崇賢同慶湛恩深。',96,'全唐诗/poet.song.2000.json','["高會蓬瀛振德音，崇賢同慶湛恩深。", "瑞融雲露飛宸翰，榮下煙霄飾禁林。", "鳳藻瓖奇清擊石，龍文模琢麗雕金。", "辭臣喜適逢時願，睿眷殊敦好士心。", "華照北門張組繡，秘逾東序敵球琳。", "玉堂宴罷尤知幸，御牓天章豈易尋。"]'),
('97f43800-4e63-45db-83a6-75ebce07e51c','題議門胡氏華林書院','呂祐之','宋','宋诗','song-poetry','','[]','幾朝旌表映門閭，更賞林園入畫圖。',64,'全唐诗/poet.song.2000.json','["幾朝旌表映門閭，更賞林園入畫圖。", "廷詔總宜名讓水，樹巢多恐是慈烏。", "花迎客館清香遠，竹繞書堂氣節殊。", "我直紫垣無路到，亂雲芳草隔洪都。"]'),
('62212346-d9ae-408a-aba3-1ce79c0bf719','望京樓','曾致堯','宋','宋诗','song-poetry','','[]','望京樓上望，望久思踟躕。',48,'全唐诗/poet.song.2000.json','["望京樓上望，望久思踟躕。", "境土連江徼，人家匝海隅。", "隔山川隠映，近郭水縈紆。", "雨過風腥檻，潮來岸浸蘆。"]'),
('15975a84-b450-4669-a4f5-daa073a9150d','東林寺','曾致堯','宋','宋诗','song-poetry','','[]','江南楊柳春，日暖地無塵。',48,'全唐诗/poet.song.2000.json','["江南楊柳春，日暖地無塵。", "渡口驚新雨，夜來生白蘋。", "晴沙鳴乳雁，芳草醉遊人。", "向晚前山路，誰家賽水神。"]'),
('cee6cf24-75ea-4b41-8518-361a7826c43d','崇覺寺','曾致堯','宋','宋诗','song-poetry','','[]','水深花影地莓苔，春色烘人若不開。',32,'全唐诗/poet.song.2000.json','["水深花影地莓苔，春色烘人若不開。", "走報鴒原無別事，遠將歌管酒壺來。"]'),
('0d8bd81e-103b-4b8f-930c-2103611867ad','題劉居士江樓','曾致堯','宋','宋诗','song-poetry','','[]','劉八江樓雅，詩家不易言。',120,'全唐诗/poet.song.2000.json','["劉八江樓雅，詩家不易言。", "春風花對岸，夜月水當軒。", "簾捲青山入，窗開白浪翻。", "畫來須妙手，夢去亦清魂。", "吟稱雲初滿，登宜雪正繁。", "魚龍慣燈火，鷗鷺識琴樽。", "波動簷摇影，潮回砌露痕。", "勢雄鄰碧落，景好怕黄昏。", "未許凡蹤到，寧教俗態存。", "主人憑檻處，寥廓共誰論。"]'),
('f0d40b82-e14c-4a78-8887-cef25d1ddae2','題軍山徐秀才居','曾致堯','宋','宋诗','song-poetry','','[]','買斷軍峰不計錢，屋前屋後水潺潺。',64,'全唐诗/poet.song.2000.json','["買斷軍峰不計錢，屋前屋後水潺潺。", "青春花發簾帷外，白日雲浮棟宇間。", "金鼎欲成紅氣溢，玉芝初種紫苗慳。", "未知桃熟先生醉，鶴馭何人得往還。"]'),
('e88f8c2c-bef7-4e19-b00f-33adbe91966c','題義門胡氏華林書院','曾致堯','宋','宋诗','song-poetry','','[]','華林書院集羣英，講誦興來里巷榮。',64,'全唐诗/poet.song.2000.json','["華林書院集羣英，講誦興來里巷榮。", "賓友盡爲文苑客，子孫多是帝門生。", "九理下詔親旌義，四相留詩自著名。", "致使舉家在霄漢，更將忠孝答皇朝。"]'),
('eefaacd6-d1f2-4dae-b83d-46015888fd69','句  其一','曾致堯','宋','宋诗','song-poetry','','[]','沙鷺窺吟榻，風蟬入座隅。',12,'全唐诗/poet.song.2000.json','["沙鷺窺吟榻，風蟬入座隅。"]'),
('96aebdbc-f96b-4f85-b6e6-e48099b0791f','句  其二','曾致堯','宋','宋诗','song-poetry','','[]','雲昏迷侯館，樹缺辨江湖。',12,'全唐诗/poet.song.2000.json','["雲昏迷侯館，樹缺辨江湖。"]'),
('0860bc10-cf6f-4968-bea5-7e83e884be06','句  其三','曾致堯','宋','宋诗','song-poetry','','[]','更無塵土當軒起，只有松蘿繞檻生。',16,'全唐诗/poet.song.2000.json','["更無塵土當軒起，只有松蘿繞檻生。"]'),
('32dec204-091d-498e-b3f8-33b7198b0f5d','頌','釋善昭','宋','宋诗','song-poetry','','[]','三玄三要事難分，得意忘言道易親。',32,'全唐诗/poet.song.2000.json','["三玄三要事難分，得意忘言道易親。", "一句明明該萬象，重陽九日菊花新。"]'),
('1029a566-4a69-4601-a3b6-0a00686e6496','偈','釋善昭','宋','宋诗','song-poetry','','[]','胡僧金錫光，爲法到汾陽。',24,'全唐诗/poet.song.2000.json','["胡僧金錫光，爲法到汾陽。", "六人成大器，勸請爲敷揚。"]'),
('47f4f934-5730-4589-8b82-28c57725b9a4','偈','釋善昭','宋','宋诗','song-poetry','','[]','汾陽有三訣，衲曾難辨別。',24,'全唐诗/poet.song.2000.json','["汾陽有三訣，衲曾難辨別。", "更擬問如何，拄杖驀頭揳。"]'),
('3bbd5303-928e-4ac9-9285-391f9a5cfe8d','第一訣','釋善昭','宋','宋诗','song-poetry','','[]','接引無時節，巧語不能詮，雲綻青天月。',18,'全唐诗/poet.song.2000.json','["接引無時節，巧語不能詮，雲綻青天月。"]'),
('8ed61834-7ed2-495d-a2af-a77aa311dc0e','第二訣','釋善昭','宋','宋诗','song-poetry','','[]','舒光辨賢哲，問答利生心，拔却眼中楔。',18,'全唐诗/poet.song.2000.json','["舒光辨賢哲，問答利生心，拔却眼中楔。"]'),
('7c1540aa-5737-4e85-858e-220b39f0f012','第三訣','釋善昭','宋','宋诗','song-poetry','','[]','西國胡人說，濟水過新羅，北地用鑌鐵。',18,'全唐诗/poet.song.2000.json','["西國胡人說，濟水過新羅，北地用鑌鐵。"]'),
('c36af399-854c-4f23-b9bd-a82254c3a6fb','句  其一','釋善昭','宋','宋诗','song-poetry','','[]','萬古碧潭空界月，再三撈摝始應知。',16,'全唐诗/poet.song.2000.json','["萬古碧潭空界月，再三撈摝始應知。"]'),
('2f6bf8ba-0893-40d8-9978-10578d10b1a8','句  其二','釋善昭','宋','宋诗','song-poetry','','[]','陣雲橫海上，拔劍攪龍門。',12,'全唐诗/poet.song.2000.json','["陣雲橫海上，拔劍攪龍門。"]'),
('29b82a75-9667-4097-bb7f-a388169b5e1e','句  其三','釋善昭','宋','宋诗','song-poetry','','[]','三頭六臂擎天地，忿怒那吒撲帝鐘。',16,'全唐诗/poet.song.2000.json','["三頭六臂擎天地，忿怒那吒撲帝鐘。"]'),
('2df58a32-d663-4982-bfc1-db39b1f1d4c0','句  其四','釋善昭','宋','宋诗','song-poetry','','[]','雪埋夜月深三尺，陸地行舟萬里程。',16,'全唐诗/poet.song.2000.json','["雪埋夜月深三尺，陸地行舟萬里程。"]'),
('d2017c6f-e41e-40b8-8286-2e1f1e64bd29','句  其五','釋善昭','宋','宋诗','song-poetry','','[]','三玄開正道，一句破邪宗。',12,'全唐诗/poet.song.2000.json','["三玄開正道，一句破邪宗。"]'),
('c3f51c6c-5084-46ab-806a-8fff0a0e23bb','三玄偈三首  其一','釋智嵩','宋','宋诗','song-poetry','','[]','須用直須用，心意莫定動。',24,'全唐诗/poet.song.2000.json','["須用直須用，心意莫定動。", "三歲師子吼，十方沒狐種。"]'),
('00c46ca2-3002-4a2d-9266-90e3a3e5e5b9','三玄偈三首  其二','釋智嵩','宋','宋诗','song-poetry','','[]','我有真如性，如同幕裏隠。',24,'全唐诗/poet.song.2000.json','["我有真如性，如同幕裏隠。", "批破六門關，願出毗盧印。"]'),
('0c8be9b5-3894-449c-b3b1-e270f550a121','三玄偈三首  其三','釋智嵩','宋','宋诗','song-poetry','','[]','真骨金剛體可誇，六塵一拂求無遮。',32,'全唐诗/poet.song.2000.json','["真骨金剛體可誇，六塵一拂求無遮。", "廓落世界空爲體，體上無爲真到家。"]'),
('1a2bbb68-8caa-4012-9055-89897c4a5a88','臨卒書詩','古成之','宋','宋诗','song-poetry','','[]','物外乾坤誰得到，壺中日月我曾遊。',32,'全唐诗/poet.song.2000.json','["物外乾坤誰得到，壺中日月我曾遊。", "留今留古曾留得，一醉浮生萬事休。"]'),
('80c26567-0b3d-43ba-bac2-9dd4b42efac9','憶羅浮','古成之','宋','宋诗','song-poetry','','[]','憶昔浮最上峰，當年曾得寄仙蹤。',63,'全唐诗/poet.song.2000.json','["憶昔浮最上峰，當年曾得寄仙蹤。", "凭闌月色出滄海，欹枕秋聲入古松。", "採藥靜尋幽澗洗，寄書閑仗白雲封。", "紅塵一下拘名利，不聽山間午夜鐘。"]'),
('ffb78afb-7bd3-4ad0-b2ab-d85d3706c55a','五僊觀二首  其一','古成之','宋','宋诗','song-poetry','','[]','撥破浮塵入紫煙，五羊壇上訪神僊。',64,'全唐诗/poet.song.2000.json','["撥破浮塵入紫煙，五羊壇上訪神僊。", "人間自覺無閑地，城裏誰知有洞天。", "竹葉影繁籠藥圃，桃花香煖映芝田。", "吟餘池畔聊欹枕，風雨蕭蕭吹白蓮。"]'),
('83abc44a-001c-4d0d-a213-cd1e294cac8a','五僊觀二首  其二','古成之','宋','宋诗','song-poetry','','[]','玄元分古觀，南鎮越王城。',120,'全唐诗/poet.song.2000.json','["玄元分古觀，南鎮越王城。", "五石空留瑞，羣仙不記名。", "丹砂雖久煉，雞犬自長生。", "檻簇鰲頭景，門通鶴頸程。", "煙霞隨砌起，花木逐時榮。", "古井涵虛碧，疏鐘入戶清。", "荒蕪憐夜色，寒溜引秋聲。", "丹竈封苔老，芝田積雨平。", "風光齊嶽麓，音信接朱明。", "願將身從此，乘雲到平京。"]'),
('5e39a48b-ce7c-4419-a012-d7cc7ac07c3b','懷石樓','古成之','宋','宋诗','song-poetry','','[]','相思天一邊，知在石樓間。',48,'全唐诗/poet.song.2000.json','["相思天一邊，知在石樓間。", "高卧客稀到，數峰人共閒。", "仙方新更試，易疏舊曾刪。", "好探鰲頭信，時應有鶴還。"]'),
('aac97d6e-76fa-43e0-8060-75790a225176','貪泉','古成之','宋','宋诗','song-poetry','','[]','賢良知足辱，爲爾戒貪名。',48,'全唐诗/poet.song.2000.json','["賢良知足辱，爲爾戒貪名。", "一酌不能惑，千年依舊清。", "深涵秋漢色，冷浸古松聲。", "珍重荒碑在，何人曾淚傾。"]'),
('e5bfc9ab-cdf1-4ecb-aadd-ec6166d62a53','遊天通真身塔','古成之','宋','宋诗','song-poetry','','[]','潔志登高塔，西南對海城。',48,'全唐诗/poet.song.2000.json','["潔志登高塔，西南對海城。", "一真雖有相，萬法本無生。", "梅雨侵窗冷，天風入海清。", "臨回慵更語，祖意自分明。"]'),
('ff2034f3-31a5-43eb-8175-3a7a793b3272','句','古成之','宋','宋诗','song-poetry','','[]','寰中有道逢千載，嶺外觀光祇一人。',16,'全唐诗/poet.song.2000.json','["寰中有道逢千載，嶺外觀光祇一人。"]'),
('465fe70e-05c9-49bf-b6cc-45e35ebf53e4','句','胡旦','宋','宋诗','song-poetry','','[]','明年春色裏，領取一行歸。',12,'全唐诗/poet.song.2000.json','["明年春色裏，領取一行歸。"]'),
('b794d1e2-4896-47b0-b617-670e7f115cb1','干越亭','王洞','宋','宋诗','song-poetry','','[]','越國啟封後，餘地連吳楚。',24,'全唐诗/poet.song.2000.json','["越國啟封後，餘地連吳楚。", "事著因一時，留名遂千古。"]'),
('ef644a84-fa53-4d50-913a-c0753f5dd154','自題月軒','釋德聰','宋','宋诗','song-poetry','','[]','軒前轆轤轉冰盤，軒裏詩成徹骨寒。',32,'全唐诗/poet.song.2000.json','["軒前轆轤轉冰盤，軒裏詩成徹骨寒。", "多少人來看明月，誰知倒被月明看。"]'),
('6b032453-8088-486c-bdcc-64690a4a916b','題燕','陳靖','宋','宋诗','song-poetry','','[]','秋去春來不倦遥，流鶑相伴語交交。',32,'全唐诗/poet.song.2000.json','["秋去春來不倦遥，流鶑相伴語交交。", "兒孫各自飛鳴去，猶揀新泥補舊巢。"]'),
('afdca9f3-3baf-4e5a-9bd6-1c94e5aef572','詠華林書院','陳靖','宋','宋诗','song-poetry','','[]','卓爾西山百里强，累年家有桂枝香。',64,'全唐诗/poet.song.2000.json','["卓爾西山百里强，累年家有桂枝香。", "萬株松竹封三徑，數世兒孫食一堂。", "客舍遠連虛席密，縣衙斜引闕門長。", "就中好是華林墅，別種梧桐養鳳凰。"]'),
('c3d087d1-8ce2-47c7-a82a-12ab2659e39f','句  其一','陳靖','宋','宋诗','song-poetry','','[]','玉堂視草思嚴助，鈴閣談經滯馬融。',16,'全唐诗/poet.song.2000.json','["玉堂視草思嚴助，鈴閣談經滯馬融。"]'),
('5caff158-e42b-4e1d-aa65-8a891f887212','句  其二','陳靖','宋','宋诗','song-poetry','','[]','分符出牧同吾祖，衣錦還鄉自我射。',16,'全唐诗/poet.song.2000.json','["分符出牧同吾祖，衣錦還鄉自我射。"]'),
('1d8b5aa6-2424-40d4-a56a-73ef83adb70b','雨霧剡溪','錢昭度','宋','宋诗','song-poetry','','[]','剡溪風雨霽，航葦重行行。',48,'全唐诗/poet.song.2000.json','["剡溪風雨霽，航葦重行行。", "到處楊柳色，幾家荷葉聲。", "噪蟬金鼎沸，游水玉壺清。", "最喜魚梁伴，歸帆的的輕。"]'),
('a46a02f7-4a22-45bf-a90e-e57b9e96e637','懷會稽','錢昭度','宋','宋诗','song-poetry','','[]','斗牛星外翻成夢，巢鳥枝南略寄身。',32,'全唐诗/poet.song.2000.json','["斗牛星外翻成夢，巢鳥枝南略寄身。", "越國荷花八百里，別來誰是採蓮人。"]'),
('ed4b2ca7-61a2-4c72-b7cb-32f96dfc9057','詠方池','錢昭度','宋','宋诗','song-poetry','','[]','東道主人心匠巧，鑿開方石貯漣漪。',32,'全唐诗/poet.song.2000.json','["東道主人心匠巧，鑿開方石貯漣漪。", "夜深却被寒星映，恰似仙翁一局棋。"]'),
('fec08ba5-756d-4a71-adf9-dc3785b8c218','贈白校書','錢昭度','宋','宋诗','song-poetry','','[]','袖裏青鋒秋水寒，誰疑雙燕是金丸。',32,'全唐诗/poet.song.2000.json','["袖裏青鋒秋水寒，誰疑雙燕是金丸。", "出門風雨如何去，空有霜髭在玉盤。"]'),
('07cd7134-7ee4-4f09-abc9-33754f5ead84','憶具區','錢昭度','宋','宋诗','song-poetry','','[]','平生愛具區，島嶼夾陂湖。',48,'全唐诗/poet.song.2000.json','["平生愛具區，島嶼夾陂湖。", "竹雨籠鸂鶒，花煙濕鷓鶘。", "神仙疑有宅，魚鼇自爲都。", "何事勞長想，機雲本是吳。"]'),
('f9811cd7-1de5-44aa-a6dc-4de6673bf748','野水','錢昭度','宋','宋诗','song-poetry','','[]','野水不如璧，澄心不覺勞。',48,'全唐诗/poet.song.2000.json','["野水不如璧，澄心不覺勞。", "與天無表裏，共月見分毫。", "綠好磨長劍，清宜泛小舠。", "淡交今已矣，惆悵越波濤。"]'),
('f8fffe24-0825-485a-9105-d949a521843f','菊','錢昭度','宋','宋诗','song-poetry','','[]','曾見春花落萬紅，不然隨雨即隨風。',32,'全唐诗/poet.song.2000.json','["曾見春花落萬紅，不然隨雨即隨風。", "如何得到重陽日，浮在陶家酒盞中。"]'),
('4aa13d09-afc1-40c7-b3b8-b91334143eb5','春陰','錢昭度','宋','宋诗','song-poetry','','[]','語燕初飛隴麥青，春雲將雨滯行人。',32,'全唐诗/poet.song.2000.json','["語燕初飛隴麥青，春雲將雨滯行人。", "雲間若有金烏賣，應被豪家占得春。"]'),
('4900e3f1-39ee-4e8b-8698-b94cfca7010e','野墅夏晚','錢昭度','宋','宋诗','song-poetry','','[]','一抹生紅畫杏腮，半園沈綠鎖桐材。',64,'全唐诗/poet.song.2000.json','["一抹生紅畫杏腮，半園沈綠鎖桐材。", "黄蜂衙退海潮上，白蟻戰酣山雨來。", "睡思幾家金带枕，酒香何處玉交杯。", "太陽西落波東去，惆悵無人喚得歸。"]'),
('6a1c2637-5ef6-4910-b592-4be05fe001f7','句  其一','錢昭度','宋','宋诗','song-poetry','','[]','西南片月充腸冷，二八飛泉繞齒寒。',16,'全唐诗/poet.song.2000.json','["西南片月充腸冷，二八飛泉繞齒寒。"]'),
('92933a39-9d0b-45dd-a895-8388cc5689a1','句  其二','錢昭度','宋','宋诗','song-poetry','','[]','磻溪重得呂，維嶽再生申。',12,'全唐诗/poet.song.2000.json','["磻溪重得呂，維嶽再生申。"]'),
('70b0a45d-f8a4-47ec-b8f8-7161175161b5','句  其三','錢昭度','宋','宋诗','song-poetry','','[]','雨被北風吹作雪，水愁東海亦成冰。',16,'全唐诗/poet.song.2000.json','["雨被北風吹作雪，水愁東海亦成冰。"]'),
('b88c85d7-adc5-450a-8f41-a6594171a77a','句  其四','錢昭度','宋','宋诗','song-poetry','','[]','東北風吹大庚嶺，西南日映小寒天。',16,'全唐诗/poet.song.2000.json','["東北風吹大庚嶺，西南日映小寒天。"]'),
('ff98fd3c-d8ac-40ed-b299-4551092b5bbd','句  其五','錢昭度','宋','宋诗','song-poetry','','[]','三年別館風吹入，萬里長沙月照來。',16,'全唐诗/poet.song.2000.json','["三年別館風吹入，萬里長沙月照來。"]'),
('ed375b80-4bb5-4055-b99c-a8f42a775f28','句  其六','錢昭度','宋','宋诗','song-poetry','','[]','人間路到三峰盡，天下秋隨一葉來。',16,'全唐诗/poet.song.2000.json','["人間路到三峰盡，天下秋隨一葉來。"]'),
('c8946631-7dc0-492d-bc34-c4bee9822001','句  其七','錢昭度','宋','宋诗','song-poetry','','[]','西北高樓在，東南王氣銷。',12,'全唐诗/poet.song.2000.json','["西北高樓在，東南王氣銷。"]'),
('f893a161-825c-4846-b21a-3fc90d232993','句  其八','錢昭度','宋','宋诗','song-poetry','','[]','繡帔夢驚中酒處，朱門人語上朝時。',16,'全唐诗/poet.song.2000.json','["繡帔夢驚中酒處，朱門人語上朝時。"]'),
