('657b3214-f0c7-4df6-879d-394c0598b09c','句  其一○','錢昭度','宋','宋诗','song-poetry','','[]','風欲拋高雨壓沉，黄昏前後五更深。',16,'全唐诗/poet.song.2000.json','["風欲拋高雨壓沉，黄昏前後五更深。"]'),
('6d978280-2f35-4ec1-aed7-da321891a0a0','句  其一一','錢昭度','宋','宋诗','song-poetry','','[]','閼氏纔聞易妾名，歸期長似俟河清。',16,'全唐诗/poet.song.2000.json','["閼氏纔聞易妾名，歸期長似俟河清。"]'),
('f1b679e8-4aad-4c5c-b2a2-569438a60a8b','句  其一二','錢昭度','宋','宋诗','song-poetry','','[]','荷揮萬朵玉如意，蟬弄一聲金錯刀。',16,'全唐诗/poet.song.2000.json','["荷揮萬朵玉如意，蟬弄一聲金錯刀。"]'),
('afa3ceca-9f0d-4b27-9435-9ded2d9cff4e','句  其一三','錢昭度','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','長憶錢塘江上望，酒樓人散雨千絲。',16,'全唐诗/poet.song.2000.json','["長憶錢塘江上望，酒樓人散雨千絲。"]'),
('3199d258-0558-43e2-98b9-5c0f8df5cea6','句  其一四','錢昭度','宋','宋诗','song-poetry','','[]','蕎麥花殘小雪飛。',8,'全唐诗/poet.song.2000.json','["蕎麥花殘小雪飛。"]'),
('812a5511-6bd1-45ae-bb23-af2e35fa2923','句  其一五','錢昭度','宋','宋诗','song-poetry','','[]','南人如問雪，向道是楊花。',12,'全唐诗/poet.song.2000.json','["南人如問雪，向道是楊花。"]'),
('60bfd013-4e83-4216-8c7f-759f5df8c28b','句  其一六','錢昭度','宋','宋诗','song-poetry','','[]','伯禹無端教鮮食，水中魚盡不知休。',16,'全唐诗/poet.song.2000.json','["伯禹無端教鮮食，水中魚盡不知休。"]'),
('0c3afa8a-73c5-4044-91a3-6bd58e35deb9','偈','釋曉聰','宋','宋诗','song-poetry','','[]','大地雪漫漫，春風依舊寒。',24,'全唐诗/poet.song.2000.json','["大地雪漫漫，春風依舊寒。", "說禪說道易，成佛成祖難。"]'),
('9f9123ae-2821-470b-a5bf-f8fa239ecf02','偈','釋曉聰','宋','宋诗','song-poetry','','[]','晨鷄報曉靈，粥後便天明。',24,'全唐诗/poet.song.2000.json','["晨鷄報曉靈，粥後便天明。", "燈籠猶瞌睡，露柱却惺惺。"]'),
('552a4ef6-b499-4982-b6f0-41b4adfc94e4','示衆偈','釋曉聰','宋','宋诗','song-poetry','','[]','天晴蓋却屋，乘乾刈却禾。',24,'全唐诗/poet.song.2000.json','["天晴蓋却屋，乘乾刈却禾。", "早輸王稅了，鼓腹唱巴歌。"]'),
('72d99052-a240-4ce8-8383-cd6a8f12e656','法身頌','釋曉聰','宋','宋诗','song-poetry','','[]','參禪學道莫茫茫，問透法身北斗藏。',47,'全唐诗/poet.song.2000.json','["參禪學道莫茫茫，問透法身北斗藏。", "余今老倒羸甚，見人無力得商量。", "唯有攫頭知我意，栽松時復上金剛。"]'),
('fa2194f4-f1fc-42c8-aca7-ec47a64e58ae','題逆旅壁','釋寶黁','宋','宋诗','song-poetry','','[]','滿院秋光濃欲滴，老僧倚仗青松側。',32,'全唐诗/poet.song.2000.json','["滿院秋光濃欲滴，老僧倚仗青松側。", "只怪高聲問不應，瞋余踏破蒼苔色。"]'),
('19c97b9b-0b6a-47ee-aefb-20ca2cfcccdd','春日登大悲閣二首  其一','錢惟治','宋','宋诗','song-poetry','','[]','閣，閣。',70,'全唐诗/poet.song.2000.json','["閣，閣。", "雕鏤，彩錯，簇明霞，攢麗萼。", "玉女窺牖，飛仙捧鐸。", "沉煙燠寶香，媚水涵珠箔。", "千山蓊鬰晴霽，萬井喧填曉郭。", "登臨徒倚傍瓊欄，滿目春光煦寥廓。"]'),
('6c525d21-3a27-4a36-83aa-b52c60201b66','春日登大悲閣二首  其二','錢惟治','宋','宋诗','song-poetry','','[]','閣，閣。',70,'全唐诗/poet.song.2000.json','["閣，閣。", "般斤，郢作。", "木從繩，工必度。", "華飾藻繪，密施榱桷。", "明蟾代寶燈，瑞霧爲珍箔。", "欄危似倚高穿，梯迴疑空碧落。", "有時閒上瞰人寰，自謂禽中騰一鶚。"]'),
('0e854a11-3e82-47d3-99bb-09dd12c5f7b5','春日登大悲閣','錢惟治','宋','宋诗','song-poetry','','[]','春城滿望，曉閣閒登。',40,'全唐诗/poet.song.2000.json','["春城滿望，曉閣閒登。", "塵銷霽景，定出真僧。", "人懷遠思，檻凭危層。", "因圓果證，勝境斯興。"]'),
('2afc8c67-2eb4-4a91-a1a5-82dcf95bdb14','春日登大悲閣','錢惟治','宋','宋诗','song-poetry','','[]','聖主欽崇教，千光顯紺容。',48,'全唐诗/poet.song.2000.json','["聖主欽崇教，千光顯紺容。", "映雲窗倚暖，籠月箔花重。", "浄剎香風遠，危欄碧霧沈。", "勝因良以詠，華閣一斯逢。"]'),
('89e9ce65-1225-46ab-9660-731b9678d667','春日登大悲閣二首  其一','錢惟治','宋','宋诗','song-poetry','','[]','碧天臨迥閣，晴雪點山屏。',24,'全唐诗/poet.song.2000.json','["碧天臨迥閣，晴雪點山屏。", "夕煙侵冷箔，明月歛閑亭。"]'),
('b223ff17-1130-4bae-aa32-56e67b1bf2ac','春日登大悲閣二首  其二','錢惟治','宋','宋诗','song-poetry','','[]','裊霞披迥殿，香霧擁輕簾。',24,'全唐诗/poet.song.2000.json','["裊霞披迥殿，香霧擁輕簾。", "曉花歌靜院，芳樹捧晴簷。"]'),
('f5251022-aefe-4c94-8af3-51e7c398b8b0','寄寇平仲','向敏中','宋','宋诗','song-poetry','','[]','九萬鵬霄振翼時，與君同折月中枝。',32,'全唐诗/poet.song.2000.json','["九萬鵬霄振翼時，與君同折月中枝。", "細思淳化持衡者，得到于今更有誰。"]'),
('687c8e25-e939-4940-9b48-eec7c75da8e3','春暮  其一','向敏中','宋','宋诗','song-poetry','','[]','恨別春歸酒滿杯，殘芳繚繞舊亭臺。',64,'全唐诗/poet.song.2000.json','["恨別春歸酒滿杯，殘芳繚繞舊亭臺。", "不甘淑景隨風變，剛被炎光繼日催。", "弱柳綠濃還易合，夭桃紅盡更難開。", "明年復與君相約，重遣陽和早到來。"]'),
('b5df03d3-8006-481e-b4b0-43129f4d06e1','春暮  其二','向敏中','宋','宋诗','song-poetry','','[]','落紅庭院綠池塘，語燕啼鶑亦可傷。',32,'全唐诗/poet.song.2000.json','["落紅庭院綠池塘，語燕啼鶑亦可傷。", "霽柳吹花春已老，暄槐成幄日初長。"]'),
('62df4dc2-07aa-4c0b-b78a-7e78dbdcea6e','春暮  其三','向敏中','宋','宋诗','song-poetry','','[]','蜂蝶如知春已歸，雨餘鶑亦縷金衣。',32,'全唐诗/poet.song.2000.json','["蜂蝶如知春已歸，雨餘鶑亦縷金衣。", "東風盡把楊花翦，吹作滿城輕雪飛。"]'),
('83c05239-e20e-4290-a39f-c0f09548a905','桃花','向敏中','宋','宋诗','song-poetry','','[]','千朵穠芳倚檻斜，一枝枝綴亂雲霞。',32,'全唐诗/poet.song.2000.json','["千朵穠芳倚檻斜，一枝枝綴亂雲霞。", "憑君莫厭臨風看，占斷春光是此花。"]'),
('2b3518d3-b07f-4c2a-9f72-8210e2d2f499','偶吟遣懷','向敏中','宋','宋诗','song-poetry','','[]','昔爲宰輔居黄閣，今作元戎控夏臺。',64,'全唐诗/poet.song.2000.json','["昔爲宰輔居黄閣，今作元戎控夏臺。", "萬里蒼黔漸受賜，一方清晏有何才。", "紫宸杳杳彌年別，紅旆翩翩映日開。", "將相官榮如我少，不須頻獻手中杯。"]'),
('68728412-834f-4152-a64a-c291d0ea30f3','呈知鄜州何士宗','向敏中','宋','宋诗','song-poetry','','[]','勳將鐘鼓堪銘鏤，業爲皇王致太平。',32,'全唐诗/poet.song.2000.json','["勳將鐘鼓堪銘鏤，業爲皇王致太平。", "貔虎有威開玉帳，犬戎無戰卧金鉦。"]'),
('67cafd27-7324-4bcd-9ac3-7b01b5fa37a9','游浄居寺','向敏中','宋','宋诗','song-poetry','','[]','四面煙嵐合，吟魂到便清。',48,'全唐诗/poet.song.2000.json','["四面煙嵐合，吟魂到便清。", "亂山供遠翠，幽竹送寒聲。", "磬韻聽時歇，雲根望處生。", "塵機閑擺落，潛得笑浮榮。"]'),
('2080d4db-cca9-4fa8-992f-1125b2504caa','峽山飛來寺','向敏中','宋','宋诗','song-poetry','','[]','峽山勝地安禪處，萬仞危橋壓要津。',64,'全唐诗/poet.song.2000.json','["峽山勝地安禪處，萬仞危橋壓要津。", "世上豈知名利路，浪中空笑往來人。", "倚門怪石狂遮面，入座寒雲碎遶身。", "日暮西風懶回首，滿林幽鳥語聲頻。"]'),
('a582968d-3ce8-44c5-b54e-a282bf93fa08','題義門胡氏華林書院','向敏中','宋','宋诗','song-poetry','','[]','岑樓高架郁嵯峨，幾度憑欄發浩歌。',64,'全唐诗/poet.song.2000.json','["岑樓高架郁嵯峨，幾度憑欄發浩歌。", "春樹鳥聲當戶巧，夕陽山色卷帘多。", "花凝玉勒含煙露，酒泛金樽醉綺羅。", "自是梁園知好客，不妨車馬日相過。"]'),
('edff5d6a-8dcb-4c48-a45a-f43868cafd60','延安守歲','向敏中','宋','宋诗','song-poetry','','[]','律管風生消暮景，塞原煙靜絕妖氛。',32,'全唐诗/poet.song.2000.json','["律管風生消暮景，塞原煙靜絕妖氛。", "坐移殘燭光陰變，故舊年華一夜分。"]'),
('9ceea17b-6e2c-4833-9ccd-83c43cc73e47','句','向敏中','宋','宋诗','song-poetry','','[]','四時常有煙棚合，三月猶無菜甲生。',16,'全唐诗/poet.song.2000.json','["四時常有煙棚合，三月猶無菜甲生。"]'),
('b92fc7fc-fd72-497c-b669-e9cb037c7d8f','存目','向敏中','宋','宋诗','song-poetry','','[]','詩題：寄寇平仲首句：玉殿登科四十年。',18,'全唐诗/poet.song.2000.json','["詩題：寄寇平仲首句：玉殿登科四十年。"]'),
('a1b3704b-1d05-45ce-9fc1-90ced5f364b7','題洛陽村寺','張度','宋','宋诗','song-poetry','','[]','金谷花時醉一場，舊遊無日不思量。',32,'全唐诗/poet.song.2000.json','["金谷花時醉一場，舊遊無日不思量。", "誰知萬水千山裏，枉被人傳過洛陽。"]'),
('961d1a4a-2ef3-4960-8807-93f23405c7b1','送陳堯叟赴廣西漕','宋湜','宋','宋诗','song-poetry','','[]','憐君將命拜新恩，送別都門亦斷魂。',64,'全唐诗/poet.song.2000.json','["憐君將命拜新恩，送別都門亦斷魂。", "雨歇桂林秋更暖，瘴連梅嶺日多昏。", "詔頒海徼征徭薄，兵罷蠻州市井繁。", "愧我不才居禁近，前春灑掃待回轅。"]'),
('067e653b-3584-4302-ba57-da88a9e5ca80','贈淳于公歸養','宋湜','宋','宋诗','song-poetry','','[]','宦路厭風塵，高堂役夢頻。',48,'全唐诗/poet.song.2000.json','["宦路厭風塵，高堂役夢頻。", "拜章辭旨切，致政罷光新。", "陶令羞爲吏，潘生喜養親。", "况登朝序貴，半俸豈憂貧。"]'),
('fee05974-130d-4f8b-9588-14ccf78d2370','題義門胡氏華林書院','宋湜','宋','宋诗','song-poetry','','[]','紛紛游客豫章回，俱道華林就學來。',64,'全唐诗/poet.song.2000.json','["紛紛游客豫章回，俱道華林就學來。", "門第昔年旌闕聳，主人長日講筵開。", "化行鄉黨渾無頌，教得兒孫盡有才。", "好是諸生游息處，四時花木繞書臺。"]'),
('f6145753-a2f8-42af-a031-082c88ff339c','禁林讌會之什','呂文仲','宋','宋诗','song-poetry','','[]','青葱溫樹非塵境，鼇岫金鑾近日邊。',96,'全唐诗/poet.song.2000.json','["青葱溫樹非塵境，鼇岫金鑾近日邊。", "石壁天章垂雨露，璇題宸翰動雲烟。", "西垣賈馬徵辭客，東觀蓬瀛集列仙。", "讌喜酡顔飛玉斝，鏗鏘奮藻擘花牋。", "唐虞盛化高千古，葵藿傾心祝萬年。", "自顧薄才誠有媿，不知何以奉羣賢。"]'),
('36d4fda0-7c20-44cd-9091-565426d9740b','題義門胡氏華林書院  其一','呂文仲','宋','宋诗','song-poetry','','[]','世世趨庭列雁行，烟蘿泉石繞書堂。',64,'全唐诗/poet.song.2000.json','["世世趨庭列雁行，烟蘿泉石繞書堂。", "分題月下聯書版，聚宴花前獻壽觴。", "旌表异恩逢聖代，隠居佳致接仙鄉。", "因知孝治垂風化，青史留名道允光。"]'),
('5bbbed5f-ecd0-4f64-af56-3bdff880b562','題義門胡氏華林書院  其二','呂文仲','宋','宋诗','song-poetry','','[]','簪裾幾世住南昌，講學旌閭曄日光。',64,'全唐诗/poet.song.2000.json','["簪裾幾世住南昌，講學旌閭曄日光。", "舊里葛山同井邑，遠方廬阜出門牆。", "康成業自詩書顯，卜世家由孝弟彰。", "二隠昔慚聯懿分，同將姓字列東堂。"]'),
('92b56499-5a87-4f16-ad56-7afa3da0d9f1','題義門胡氏華林書院  其三','呂文仲','宋','宋诗','song-poetry','','[]','君家高誼冠南州，舊輯書堂聚北流。',64,'全唐诗/poet.song.2000.json','["君家高誼冠南州，舊輯書堂聚北流。", "北飯未嘗輕下客，名園不羨覓封侯。", "挂冠令有陶彭澤，訪道人希許遠遊。", "他年濯纓江海去，終期此日挹浮邱。"]'),
('3ab61cf5-ddfa-4b5f-ab6c-c68928990745','長樂集總序','謝泌','宋','宋诗','song-poetry','','[]','潮田種稻重收穀，山路逢人半是僧。',32,'全唐诗/poet.song.2000.json','["潮田種稻重收穀，山路逢人半是僧。", "城裏三山千簇寺，夜間七塔萬枝燈。"]'),
('55a75a76-24e4-45d0-9641-5528a1ed1132','謝客巖','謝泌','宋','宋诗','song-poetry','','[]','舊刻巖前文字在，登臨盡日動悲辛。',32,'全唐诗/poet.song.2000.json','["舊刻巖前文字在，登臨盡日動悲辛。", "子孫千載知多少，只我今來嗣後塵。"]'),
('b683b289-d382-4c34-941a-1c96f0be8071','贈日本僧','王礪','宋','宋诗','song-poetry','','[]','滄波泛瓶錫，幾月到天朝。',48,'全唐诗/poet.song.2000.json','["滄波泛瓶錫，幾月到天朝。", "鄉信日邊斷，歸程海面遥。", "秋泉吟裏落，霜葉定中飄。", "爲愛華風好，扶桑夢自消。"]'),
('22895b20-b478-4135-8267-0d8f3556721b','石盆寺','李含章','宋','宋诗','song-poetry','','[]','巨石何年琢，爲盆勢莫裁。',48,'全唐诗/poet.song.2000.json','["巨石何年琢，爲盆勢莫裁。", "圓疑通澤國，深可並天台。", "法水長時滿，青蓮向日開。", "無人知此喻，寂寞首空迴。"]'),
('d9af1b69-df59-444e-b77a-39131e978240','題武陵護戎林亭','李含章','宋','宋诗','song-poetry','','[]','修笙簇徑出林椒，可與遊人避俗囂。',64,'全唐诗/poet.song.2000.json','["修笙簇徑出林椒，可與遊人避俗囂。", "曲檻隔花安筆硯，小窗延月伴簞瓢。", "紅藤引蔓移山豆，綠葉分葩植水蕉。", "到此每憐清氣別，可堪寒夜雨瀟瀟。"]'),
('7b978b0e-3820-4ad6-aa4c-8e77bfe0ff70','寄題元長老林亭','李含章','宋','宋诗','song-poetry','','[]','聞說幽亭氣象寬，何須基構入雲端。',64,'全唐诗/poet.song.2000.json','["聞說幽亭氣象寬，何須基構入雲端。", "平瞻一郡連山翠，遠矚千門枕水寒。", "風拂石床松子墜，雨籠莎徑栗花乾。", "遥知出定牽吟夜，只欠清猿嘯碧湍。"]'),
('2cccd306-04a6-4a38-9bb5-42a9228fefb0','漁家','李含章','宋','宋诗','song-poetry','','[]','數家茅屋枕魚磯，歲歲生涯在渺瀰。',64,'全唐诗/poet.song.2000.json','["數家茅屋枕魚磯，歲歲生涯在渺瀰。", "雞犬怪人奔竹徑，兒孫逢客倚柴籬。", "壁懸簑笠殘煙雨，門對溪山閱盛衰。", "一曲新歌一船月，夜深來往碧漣漪。"]'),
('79838f75-5f91-4507-917b-5aea2a0b765d','寄內翰王同年','李含章','宋','宋诗','song-poetry','','[]','回翔青瑣已多時，四海歸榮更是誰。',64,'全唐诗/poet.song.2000.json','["回翔青瑣已多時，四海歸榮更是誰。", "通籍禁中參鳳閣，司言天上煥龍墀。", "修文禮樂源何大，振筆雲雷澤益滋。", "若把王褒頌勳業，未如際會遇昌期。"]'),
('bc01cf7a-9d73-478c-805f-81f56ec72c7e','河北行','李含章','宋','宋诗','song-poetry','','[]','爲儒還解著征衣，遠戍沙連白草齊。',64,'全唐诗/poet.song.2000.json','["爲儒還解著征衣，遠戍沙連白草齊。", "雁陣不衝羌笛怨，狼煙微認塞雲底。", "蕎花露溼堆空塹，蓼水泓澄截古堤。", "漸近界河分內外，野禽嘐戛路東西。"]'),
('8a271a91-623f-49b5-bed1-1d3528c8657d','出典宣城三首  其一','李含章','宋','宋诗','song-poetry','','[]','戛雲秋翼健磨天，九萬修程孰可肩。',64,'全唐诗/poet.song.2000.json','["戛雲秋翼健磨天，九萬修程孰可肩。", "五馬幸歸鄉國路，百城初認釣魚船。", "餘霞綺閣方池上，宿靄人家疊嶂前。", "多感聖君垂異寵，力思報效向衰年。"]'),
('ad381d8a-3f09-45c9-b6a6-81bad3d2b62e','出典宣城三首  其二','李含章','宋','宋诗','song-poetry','','[]','蘆花未白蓼初紅，綠水澄藍是處通。',64,'全唐诗/poet.song.2000.json','["蘆花未白蓼初紅，綠水澄藍是處通。", "景色不須今日別，煙光仍與昔時同。", "馬嘶曉月思閑廐，帆掛秋光足便風。", "寄語路人休借問，錦衣歸去一衰翁。"]'),
('4d2000c0-d7ca-430d-9bde-c96d11020d56','出典宣城三首  其三','李含章','宋','宋诗','song-poetry','','[]','分符慙寡術，榮抃出京畿。',48,'全唐诗/poet.song.2000.json','["分符慙寡術，榮抃出京畿。", "況什新秋節，重經舊釣磯。", "江村初雨歇，水國淡煙微。", "一路風光好，還同衣錦歸。"]'),
('5420fd41-0a5a-429b-8de4-cb276d270c43','遊桃源觀','李含章','宋','宋诗','song-poetry','','[]','碧草芊綿十洞春，青蒼寒疊五溪雲。',64,'全唐诗/poet.song.2000.json','["碧草芊綿十洞春，青蒼寒疊五溪雲。", "山縈乳竇層層秀，路隔桃花處處分。", "苔徑竹深迷鶴跡，石壇松古漏星文。", "通宵回想塵寰事，好結茅茨向水濱。"]'),
('235b3777-a662-49fd-846b-3fea1126510a','相國寺晚鐘','李含章','宋','宋诗','song-poetry','','[]','高韻出重城，林梢鶴夢清。',48,'全唐诗/poet.song.2000.json','["高韻出重城，林梢鶴夢清。", "九衢方月曉，四野復霜晴。", "會有神仙聽，能無魍魎驚。", "寒山深洞口，依約片雲橫。"]'),
('5fb28b2c-0e7c-4198-9c5b-04052da8d877','僧家','李含章','宋','宋诗','song-poetry','','[]','不愁白日斜，唯只是僧家。',48,'全唐诗/poet.song.2000.json','["不愁白日斜，唯只是僧家。", "遠徑接芳草，閒庭掩落花。", "木欄棲悲翠，盆水種蒹葭。", "到此常留意，深窗自煮茶。"]'),
('0f215039-b899-47a0-b117-81269575b3ae','題廬山上化成寺','李含章','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','樓臺高聳入中天，壓破寒山數畝煙。',64,'全唐诗/poet.song.2000.json','["樓臺高聳入中天，壓破寒山數畝煙。", "永日松欄幽鳥語，半空巖石老僧禪。", "窗臨樛木排深澗，簷拂長蘿下翠顛。", "野客每來何所得，一聲秋磬似相便。"]'),
('b47cf0ea-ea42-4656-a6b3-8730eec5e99c','滴翠軒','馬亮','宋','宋诗','song-poetry','','[]','高閣登臨暑氣空，綠槐蟬噪咽清風。',32,'全唐诗/poet.song.2000.json','["高閣登臨暑氣空，綠槐蟬噪咽清風。", "我今到此須懷感，多少行人道路中。"]'),
('c87cc339-10ac-47fb-9ceb-f59ff21c1fcf','題紫籜寺','王戩','宋','宋诗','song-poetry','','[]','竹山絕頂古招提，境異相將待國齊。',64,'全唐诗/poet.song.2000.json','["竹山絕頂古招提，境異相將待國齊。", "靈鷲雄吞台嶽小，瑞峰高壓斗牛低。", "雲深石怪宜猿隠，水靜林幽樂鳥啼。", "見說當年封紫籜，只因丹鳳此中棲。"]'),
('bde2ac08-a12e-46a1-9f80-0cfc4cdc8171','句','范令孫','宋','宋诗','song-poetry','','[]','孤雲不爲雨，盡日却歸山。',12,'全唐诗/poet.song.2000.json','["孤雲不爲雨，盡日却歸山。"]'),
('603f5fd1-e463-4fe0-bc59-1eb4675b966d','題元象大師房','陳白','宋','宋诗','song-poetry','','[]','鷺行飛起綠楊岸，漁笛吹殘明月灘。',32,'全唐诗/poet.song.2000.json','["鷺行飛起綠楊岸，漁笛吹殘明月灘。", "一片畫圖收不得，何人終日倚闌干。"]'),
('cc97248c-691c-4fac-8bb4-0e61a59c6215','妙智寺  其一','陳白','宋','宋诗','song-poetry','','[]','台嶺名將方丈齊，當年曾說二僊迷。',32,'全唐诗/poet.song.2000.json','["台嶺名將方丈齊，當年曾說二僊迷。", "無人再得洞中信，空有桃花落剡溪。"]'),
('54cf6c8b-b9bb-4360-a117-6126cd5074c8','妙智寺  其二','陳白','宋','宋诗','song-poetry','','[]','排危步步上天梯，喬木蒼蒼拂紫霓。',64,'全唐诗/poet.song.2000.json','["排危步步上天梯，喬木蒼蒼拂紫霓。", "向日莫催琪樹老，清宵應見玉繩低。", "雲蒸巨壑金虬蟄，月落高巖翠羽栖。", "況復僊翁丹井在，碧霄歧路不須迷。"]'),
('ff39d582-3c02-4921-a820-e9d06b0c7862','妙智寺  其三','陳白','宋','宋诗','song-poetry','','[]','八重峰頂望羣山，百谷東流去不還。',32,'全唐诗/poet.song.2000.json','["八重峰頂望羣山，百谷東流去不還。", "惟有右軍遺跡在，月波時落墨池間。"]'),
('0318451e-032e-46ce-8ee7-895c5ac5d997','題勝光怡道軒','陳白','宋','宋诗','song-poetry','','[]','了了無凝滯，誰人知此心。',48,'全唐诗/poet.song.2000.json','["了了無凝滯，誰人知此心。", "開池待海月，種樹宿沙禽。", "白雪盈青簡，古風生素琴。", "由來大隠者，何必在山林。"]'),
('022b4087-b40a-4a9e-87a3-4da1784adbbc','題義門胡氏華林書院','和㠓','宋','宋诗','song-poetry','','[]','累葉聚居旌孝行，一齋崇講待儒流。',64,'全唐诗/poet.song.2000.json','["累葉聚居旌孝行，一齋崇講待儒流。", "滿堂書史勝金玉，入檻峰巒逼斗牛。", "墨客四來深慕義，本奴千樹等封侯。", "南昌舊令曾羈宦，悔不當初命駕游。"]'),
('9aaed1d1-18fe-4764-827c-d6be3e1522da','清風十韻','薛映','宋','宋诗','song-poetry','','[]','爽氣乘秋至，凉飆蕩暑初。',120,'全唐诗/poet.song.2000.json','["爽氣乘秋至，凉飆蕩暑初。", "泠泠含遠籟，槭槭動輕裙。", "翠幕波無際，修篁韻有餘。", "潛驚塞草綠，乍拂井桐疏。", "素髮悲郎將，霜紈感婕妤。", "窗光流熠耀，簾影亂蟾蜍。", "塵襲青絲騎，香飄紺幰車。", "故宮經馺娑，別館度儲胥。", "薄暮來金埒，凌晨上玉除。", "寧同起窮巷，賸欲賦愁予。"]'),
('fe22db9a-4a44-4cf0-8b1e-3d5bbb938802','戊申年七夕五絕  其一','薛映','宋','宋诗','song-poetry','','[]','月放冰輪傍絳河，相期寶婺夜經過。',32,'全唐诗/poet.song.2000.json','["月放冰輪傍絳河，相期寶婺夜經過。", "嫦娥不惜宮中桂，乞與天香分外多。"]'),
('ddecd359-856a-4205-b96e-dcec526fb85d','戊申年七夕五絕  其二','薛映','宋','宋诗','song-poetry','','[]','碧天如水月如鈎，金露盤高玉殿秋。',32,'全唐诗/poet.song.2000.json','["碧天如水月如鈎，金露盤高玉殿秋。", "青鳥潛來報消息，一時西望九花虯。"]'),
('6ae94407-6ec1-46a6-8044-8fa165126d3a','戊申年七夕五絕  其三','薛映','宋','宋诗','song-poetry','','[]','漢殿初呈楚舞時，月臺風榭鎮相隨。',32,'全唐诗/poet.song.2000.json','["漢殿初呈楚舞時，月臺風榭鎮相隨。", "如何牛女佳期夕，又待鑾輿百子池。"]'),
('614dbadb-3eea-44fe-b107-0adc4cce2e22','戊申年七夕五絕  其四','薛映','宋','宋诗','song-poetry','','[]','月露庭中錦繡筵，神光五色一何鮮。',32,'全唐诗/poet.song.2000.json','["月露庭中錦繡筵，神光五色一何鮮。", "世間工巧如求得，四至卿曹亦偶然。"]'),
('7297da0a-9416-458a-b8be-65bfb587951e','戊申年七夕五絕  其五','薛映','宋','宋诗','song-poetry','','[]','銀河耿耿露漙漙，彩縷金針玉佩環。',32,'全唐诗/poet.song.2000.json','["銀河耿耿露漙漙，彩縷金針玉佩環。", "天媛貪忙爲靈匹，幾時留巧與人間。"]'),
('198feef0-4396-4cb1-91fd-80ace572fb10','送高學士知越','薛映','宋','宋诗','song-poetry','','[]','晉朝名理漢循良，胡粉宮闈紫界牆。',64,'全唐诗/poet.song.2000.json','["晉朝名理漢循良，胡粉宮闈紫界牆。", "得請仍辭史官筆，憶歸重換會稽章。", "閒尋嶽寺茶香細，盛會江樓鱠縷長。", "官是秋曹俱老大，異時同約棹滄浪。"]'),
('f66c7fd1-b771-4018-8dc5-85849ae1a09f','典水亭','薛映','宋','宋诗','song-poetry','','[]','臺盤疏石渠，激流不四面。',48,'全唐诗/poet.song.2000.json','["臺盤疏石渠，激流不四面。", "夏屋有餘清，羽觴隨意轉。", "賓告醉言歸，主稱情未惓。", "雖非禊飲辰，豈謝蘭亭讌。"]'),
('ede0db4a-26fa-447e-be37-476c3de01191','句','薛映','宋','宋诗','song-poetry','','[]','黄鵠晨霞傍樓起，頭陀秋草繞碑荒。',16,'全唐诗/poet.song.2000.json','["黄鵠晨霞傍樓起，頭陀秋草繞碑荒。"]'),
('fef2068d-898f-40a6-bd13-055a72e6fe09','靜中好','晁逈','宋','宋诗','song-poetry','','[]','靜中好，冥心歸宴寂。',22,'全唐诗/poet.song.2000.json','["靜中好，冥心歸宴寂。", "齋己不虛吟，靜是真消息。"]'),
('c59fd3c6-dc59-40b3-8f04-5e6a1d7dcd60','靜深生四妙辭','晁逈','宋','宋诗','song-poetry','','[]','了知入道門，先從靜爲祖。',48,'全唐诗/poet.song.2000.json','["了知入道門，先從靜爲祖。", "靜勝則心安，安久虛靈府。", "虛極發明靈，洞徹無不睹。", "天然法樂多，豈比聞簫鼓。"]'),
('b2ba207d-a97f-4dfc-ba5d-483929954688','有警辭','晁逈','宋','宋诗','song-poetry','','[]','圖上華夷能盡記，未始經行一步地。',32,'全唐诗/poet.song.2000.json','["圖上華夷能盡記，未始經行一步地。", "博聞强識總周知，心不能行亦如是。"]'),
('523638a2-04fa-4052-b284-3029b4b55f07','三悟辭','晁逈','宋','宋诗','song-poetry','','[]','若能覺其夢，且悟浮生如戲弄。',58,'全唐诗/poet.song.2000.json','["若能覺其夢，且悟浮生如戲弄。", "若能智其識，漸悟狂知枉心力。", "若能性其情，大悟歸真即妙明。", "喜得自然三悟法，書之聊以表研精。"]'),
('a628af79-aaf6-40e9-865b-38f09e3fb1a7','書紳二法辭','晁逈','宋','宋诗','song-poetry','','[]','心如常滿杯，所以明知足。',36,'全唐诗/poet.song.2000.json','["心如常滿杯，所以明知足。", "心似不燃火，所以明無欲。", "二法可行持，書紳聊自勗。"]'),
('1f8f0ba5-792a-44df-ad32-802f66d77d5f','超真獨覺辭','晁逈','宋','宋诗','song-poetry','','[]','了達事終虛，往事何殊夢。',60,'全唐诗/poet.song.2000.json','["了達事終虛，往事何殊夢。", "此後事來干，屹如山不動。", "了達事終虛，往事今何在。", "此後事來干，豁若空虛礙。", "獨覺貴高奇，傑出羣迷外。"]'),
('177925de-c6f5-49af-9fba-f22bc2e339ae','知常委順辭','晁逈','宋','宋诗','song-poetry','','[]','紛然往事來，浮雲經大空。',36,'全唐诗/poet.song.2000.json','["紛然往事來，浮雲經大空。", "喧然是非聲，驚飈觸灌叢。", "古今無奈何，魏順於其中。"]'),
('db9c694f-8108-44dd-aae0-af9b97e6a75d','自爲觀照總持辭','晁逈','宋','宋诗','song-poetry','','[]','事往終空，如雲如風。',50,'全唐诗/poet.song.2000.json','["事往終空，如雲如風。", "事來不絕，如日如月攝。", "念神凝，久習而成。", "觸境情起，即時而止。", "不可殫言，自當求理。"]'),
('13901c44-a938-4e08-b48b-0f7f2085d02e','反本觀空無礙辭','晁逈','宋','宋诗','song-poetry','','[]','形是幻，情是夢，寢興視息隨羣動。',32,'全唐诗/poet.song.2000.json','["形是幻，情是夢，寢興視息隨羣動。", "當念元來一切無，豁然頓遣心中空。"]'),
('6d6d9087-d2d6-4d61-8ba1-e3b5059e2c7f','簡求心要書紳辭','晁逈','宋','宋诗','song-poetry','','[]','以靜制動，靜爲躁君。',30,'全唐诗/poet.song.2000.json','["以靜制動，靜爲躁君。", "以虛受有，虛緣葆真。", "詳而後習，可書諸紳。"]'),
('64791ba7-e47b-4adc-86d1-aba62b99b880','倣歸去來辭','晁逈','宋','宋诗','song-poetry','','[]','陶令曾言歸去來，解印還家不迴首。',128,'全唐诗/poet.song.2000.json','["陶令曾言歸去來，解印還家不迴首。", "屏貴都遺身外名，忘憂酷嗜杯中酒。", "白傅曾言歸去來，了知浮世非長久。", "獨步逍遥自得場，飲食寢興隨所偶。", "羅隠曾言歸去來，濩落生涯何所有。", "明日船中竹一竿，要學江湖釣魚手。", "晁叟亦言歸去來，抗表辭榮養衰朽。", "京洛紅塵舊滿衣，總脫臨風都抖擻。"]'),
('88e43831-812a-43ee-8530-2130378c6ee0','雙喻辭','晁逈','宋','宋诗','song-poetry','','[]','人事常酌中，取象如敧器。',60,'全唐诗/poet.song.2000.json','["人事常酌中，取象如敧器。", "器平不敧覆，有同身爽利。", "道心常不繫，取象如慮舟。", "舟閒隨逝止，可比性優游。", "能符雙喻者，何虛復何憂。"]'),
('e56ae5d6-9ea0-4b68-9ed5-159ac6333e5e','智斷身心辭','晁逈','宋','宋诗','song-poetry','','[]','咨咨爾幻身，誰能住世久。',88,'全唐诗/poet.song.2000.json','["咨咨爾幻身，誰能住世久。", "洪纖妍媿，豈長存而不朽。", "咨咨爾幻心，常隨外物誘。", "風生電滅，求其狀而何有。", "豁然達理，忽洞見於天真。", "未能無悶，或沃之以聖酒。", "去鄉遊蕩久不歸，今覺窮途自迴首。"]'),
('a8c93a91-3523-4f3a-af94-14dbafe9d125','集句書紳自用辭','晁逈','宋','宋诗','song-poetry','','[]','蒙以正，德而隠。',48,'全唐诗/poet.song.2000.json','["蒙以正，德而隠。", "專於靜，遯於遯。", "無是無非無所求，無名無迹無諸悶。", "愚自書紳用此言，深心更與何人論。"]'),
('b39b6809-5df3-4fad-896d-c7ba871eeefe','洞心情境定心篇','晁逈','宋','宋诗','song-poetry','','[]','物來誘之而不隨，物來觸之而不動。',48,'全唐诗/poet.song.2000.json','["物來誘之而不隨，物來觸之而不動。", "不隨不動自由心，何須結社詢千衆。", "萬事悠悠過即空，追思豈異春宵夢。"]'),
('960a7eee-f4d1-4460-a119-a0f8d0f7d2a7','與道相知最樂篇','晁逈','宋','宋诗','song-poetry','','[]','人多樂於親新相知，又多悲於生別離。',65,'全唐诗/poet.song.2000.json','["人多樂於親新相知，又多悲於生別離。", "唯能與道相知久，如魚樂水無暌時。", "樂道至樂非常樂，宜真造適潜熙怡。", "逌然在心不在境，安能更與白雲期。"]'),
('f3504181-17c3-4a9d-9eab-a97b897d1096','三法自然歌','晁逈','宋','宋诗','song-poetry','','[]','心本不愆自然戒，何用科條心毀敗。',64,'全唐诗/poet.song.2000.json','["心本不愆自然戒，何用科條心毀敗。", "心本不動自然定，何用勤勞止自兢。", "心本不迷自然慧，何用參尋叩倫類。", "即今知此三自然，奉以周旋無失墜。"]'),
('6be8465b-0c85-4ca7-aebf-431f0534e53a','無有所求歌','晁逈','宋','宋诗','song-poetry','','[]','無所求，擺落人間萬事休。',56,'全唐诗/poet.song.2000.json','["無所求，擺落人間萬事休。", "有所求，安養衰年樂聖猷。", "不願竹木林內隠，不願蓮花社裏收。", "願在清平仁壽域，含華守素得優游。"]'),
('a3e43ad7-26a0-4ded-bc46-7cd68ee400dd','醒默居士歌','晁逈','宋','宋诗','song-poetry','','[]','白氏先生躭醉吟，銜杯灑翰恣歡心。',64,'全唐诗/poet.song.2000.json','["白氏先生躭醉吟，銜杯灑翰恣歡心。", "樽空才盡若爲計，釋悶遣懷功未深。", "愚稱居士名醒默，清思忘言求妙德。", "習此功成道更高，不到詩魔兼酒惑。"]'),
('dda48389-b5ef-4ef8-81ed-76a7266e3151','并用存心微妙訣','晁逈','宋','宋诗','song-poetry','','[]','處世間法，或伸或屈。',50,'全唐诗/poet.song.2000.json','["處世間法，或伸或屈。", "用觀察智，無固無必。", "出世間法，勿違勿失。", "用决定信，惟精惟一。", "曲盡其妙，退藏於密。"]'),
('50f7fcaa-1583-4e4f-bd0c-d97ce5473c95','四方觀練深心訣','晁逈','宋','宋诗','song-poetry','','[]','性之生情，爲夢爲想。',70,'全唐诗/poet.song.2000.json','["性之生情，爲夢爲想。", "性之生緣，如影如響。", "不有古聖，愚將安仰。", "不有妙道，愚將安倣。", "爰得智刃，决開疑綱。", "人不同心，超然獨往。", "明融日新，率由天奬。"]'),
('1f39302b-782c-4701-84ce-040c580ccf24','偈','晁逈','宋','宋诗','song-poetry','','[]','心空如太空，豁然無可觸。',24,'全唐诗/poet.song.2000.json','["心空如太空，豁然無可觸。", "一真法界中，靈照常安住。"]'),
('39773ec0-12e2-4988-bc6d-d0f1492ebabc','自警','晁逈','宋','宋诗','song-poetry','','[]','清澄寂滅海，明浄涅槃天。',24,'全唐诗/poet.song.2000.json','["清澄寂滅海，明浄涅槃天。", "到此方知樂，休躭濁睡眠。"]'),
('a7216d3b-b2c4-4286-ac82-e7125a7652b7','堅凝','晁逈','宋','宋诗','song-poetry','','[]','了知起滅意，决定生死根。',24,'全唐诗/poet.song.2000.json','["了知起滅意，决定生死根。", "不復隨緣轉，是名不動尊。"]'),
('be6e2d6d-b397-468f-9002-81ff9458470f','十魔軍','晁逈','宋','宋诗','song-poetry','','[]','與道彌新世轉疏，老心恢廓學如初。',32,'全唐诗/poet.song.2000.json','["與道彌新世轉疏，老心恢廓學如初。", "妄緣紛擾隨時過，雲物何曾礙碧虛。"]'),
('6d41a5e8-1d59-430a-8b6b-aaf992f116eb','造化因心偈','晁逈','宋','宋诗','song-poetry','','[]','賦象各由心，影響無欺詐。',24,'全唐诗/poet.song.2000.json','["賦象各由心，影響無欺詐。", "元無造化工，羣生自造化。"]'),
('bca39dfd-76d0-48a7-baf8-abb995710969','意不求如  其一','晁逈','宋','宋诗','song-poetry','','[]','牢收長物金三品，密寫虛名墨一行。',32,'全唐诗/poet.song.2000.json','["牢收長物金三品，密寫虛名墨一行。", "失道信緣成苦趣，懵然流轉海茫茫。"]'),
('9346bb73-34e5-49f6-8274-c0ac16ff1697','意不求如  其二','晁逈','宋','宋诗','song-poetry','','[]','風花榮落速，水月浄明深。',24,'全唐诗/poet.song.2000.json','["風花榮落速，水月浄明深。", "物物觀天理，資吾入道心。"]'),
('122d1563-5ae3-48f1-850d-4d1abeee4db0','禪道同功修養訣','晁逈','宋','宋诗','song-poetry','','[]','心息相依，息調心靜。',40,'全唐诗/poet.song.2000.json','["心息相依，息調心靜。", "靜調久久，可成勝定。", "神氣相合，氣和神清。", "清和久久，可致長生。"]'),
('5a5dd333-546f-452c-bc33-418c0b848663','晚年勤道自修詩','晁逈','宋','宋诗','song-poetry','','[]','老來何故惜分陰，如月明虧魄漸侵。',32,'全唐诗/poet.song.2000.json','["老來何故惜分陰，如月明虧魄漸侵。", "進道不遑求廣智，隨時隨處且冥心。"]'),
('5ec0d7a7-c204-4163-8086-aeebf3da1583','心禱六符詩','晁逈','宋','宋诗','song-poetry','','[]','恬和端潔及虛明，六妙均融道法成。',32,'全唐诗/poet.song.2000.json','["恬和端潔及虛明，六妙均融道法成。", "願考此祥皆密契，不求知己浪傳名。"]'),
('31a1e690-675c-4182-b305-1ae94882c1a7','擬古人詩','晁逈','宋','宋诗','song-poetry','','[]','今人學宴坐，不免尋思過。',24,'全唐诗/poet.song.2000.json','["今人學宴坐，不免尋思過。", "欲免尋思過，但知學宴坐。"]'),
('0706107b-1712-43a7-b935-0d779b9bac70','擬龐居士詩','晁逈','宋','宋诗','song-poetry','','[]','人愛貴而富，我愛白而虛。',24,'全唐诗/poet.song.2000.json','["人愛貴而富，我愛白而虛。", "富貴榮辱會，虛白吉祥居。"]'),
('78019ddc-eae8-46fc-86d7-9e99b491147a','擬白樂天詩  其一','晁逈','宋','宋诗','song-poetry','','[]','求位不由己，求道不由天。',48,'全唐诗/poet.song.2000.json','["求位不由己，求道不由天。", "位即無以求，道可使進焉。", "且務由己者，己能盡心源。", "勿問由天者，天高擅化權。"]'),
('997e3def-e511-429e-963e-29fce7387b14','擬白樂天詩  其二','晁逈','宋','宋诗','song-poetry','','[]','順逆不由己，喜怒不由他。',48,'全唐诗/poet.song.2000.json','["順逆不由己，喜怒不由他。", "他即無奈何，己可存太和。", "且務由己者，克己諒誹多。", "勿貴由他者，他心是我魔。"]'),
('01feefd7-6672-495f-9df1-660bcb944442','偈  其一','晁逈','宋','宋诗','song-poetry','','[]','起滅心不停，生化形無數。',24,'全唐诗/poet.song.2000.json','["起滅心不停，生化形無數。", "奇哉大丈夫，自在空中住。"]'),
('d7c7584a-3c6c-4f20-bfe6-66b1d08e2b89','偈  其二','晁逈','宋','宋诗','song-poetry','','[]','一切是非藪，皆從外聽成。',24,'全唐诗/poet.song.2000.json','["一切是非藪，皆從外聽成。", "我是厭聞者，反聽存靈響。"]'),
('656fa08a-4e92-4f01-969f-90e4c00173cd','偈  其三','晁逈','宋','宋诗','song-poetry','','[]','求聽存靈響，冥心合太虛。',24,'全唐诗/poet.song.2000.json','["求聽存靈響，冥心合太虛。", "清融浮想盡，名曰小無餘。"]'),
('9beb9d8b-644c-48ed-a789-ee02b5556184','擬白樂天詩','晁逈','宋','宋诗','song-poetry','','[]','權要亦有苦，苦在當憂責。',24,'全唐诗/poet.song.2000.json','["權要亦有苦，苦在當憂責。", "閑慢亦有樂，樂在無縈迫。"]'),
('83c8e5fd-f09b-468f-9216-0361504e20f9','具足觀修訣','晁逈','宋','宋诗','song-poetry','','[]','三空一不空，悟入勢孤雄。',24,'全唐诗/poet.song.2000.json','["三空一不空，悟入勢孤雄。", "得道加殊稱，超天自在公。"]'),
('040172ba-b0c8-4236-ae78-da9efa398a52','自曉存心訣','晁逈','宋','宋诗','song-poetry','','[]','心息音，混融深。',32,'全唐诗/poet.song.2000.json','["心息音，混融深。", "智先覺，念無侵。", "隨辦及，即溫尋。", "用此法，存於心。"]'),
('3a9ffd6c-febf-42a8-9ef1-d0e60c0ca8fc','擬白樂天遣懷','晁逈','宋','宋诗','song-poetry','','[]','羲和走馭趁年華，不許人間歲月賒。',64,'全唐诗/poet.song.2000.json','["羲和走馭趁年華，不許人間歲月賒。", "春正艷陽春即老，日方停午日還斜。", "時情莫測深如海，世事難齊亂似麻。", "已共身心要約定，古今如此勿驚嗟。"]'),
('f9a248af-e5ea-4e63-b51d-2110f0f02053','擬白樂天期李二十文略王十八質夫不至獨宿仙遊寺','晁逈','宋','宋诗','song-poetry','','[]','角勝勞生不足云，濫傳僧語亦非真。',32,'全唐诗/poet.song.2000.json','["角勝勞生不足云，濫傳僧語亦非真。", "始知解愛禪中樂，萬萬人中無一人。"]'),
('33efcc65-8c5f-4cd3-9a40-1dcc215e4abc','擬白樂天題贈定光上人','晁逈','宋','宋诗','song-poetry','','[]','孟子四十心不動，定光四十心離塵。',64,'全唐诗/poet.song.2000.json','["孟子四十心不動，定光四十心離塵。", "我到明年加一倍，如何此際尚因循。", "已喜自逃名宦綱，猶患長隨造化鈞。", "記得前賢有詩句，祖師元是世間人。"]'),
('a0c4ff6c-d0e6-4de2-8bcf-9625bcf6d4ac','擬白樂天詩','晁逈','宋','宋诗','song-poetry','','[]','心不擇時息，書不擇時觀。',24,'全唐诗/poet.song.2000.json','["心不擇時息，書不擇時觀。", "達理意無礙，豁如天地寬。"]'),
('64b3350f-fa17-42ad-bec7-39e1c0d0acec','詩一首','晁逈','宋','宋诗','song-poetry','','[]','貌愚愚谷邃，道醉醉鄉春。',24,'全唐诗/poet.song.2000.json','["貌愚愚谷邃，道醉醉鄉春。", "愚醉無迷謬，伊予意又新。"]'),
('2e84a52f-b808-4913-b8d1-494543c6398f','擬白樂天詩','晁逈','宋','宋诗','song-poetry','','[]','自學養恬休用智，從他名迹日衰微。',32,'全唐诗/poet.song.2000.json','["自學養恬休用智，從他名迹日衰微。", "我身不欲全高貴，高貴多乘禍敗機。"]'),
('95affe80-8917-4056-aa3e-e0931843685f','願成四勝深心偈','晁逈','宋','宋诗','song-poetry','','[]','豁然悟空，了然見性。',20,'全唐诗/poet.song.2000.json','["豁然悟空，了然見性。", "凝然不動，寂然無思。"]'),
('a79b5a05-6be7-4d56-b327-edb66bfba231','擬白樂天詩','晁逈','宋','宋诗','song-poetry','','[]','多圖果何益，只自勞奔競。',24,'全唐诗/poet.song.2000.json','["多圖果何益，只自勞奔競。", "不如收身心，凝然成靜定。"]'),
('de718192-4307-4178-b2f8-f725132963eb','屬疾','晁逈','宋','宋诗','song-poetry','','[]','精鶩成勤瘁，頤貞俟有瘳。',95,'全唐诗/poet.song.2000.json','["精鶩成勤瘁，頤貞俟有瘳。", "吟生南越思，慈結北憂。", "粲枕甘爲蝶，豐厨厭炙牛。", "玄元知寡欲，平子尚多愁。", "夕鳥侵階啄，宵螢入樹流。", "玉書能靜覽，柱史倦閑投。", "忽賦行雲什，堪聽擊壤謳。", "期君整朝佩，仙置在瀛洲。"]'),
('09081502-49a1-41f6-9d35-fbaa4f005ccd','清風十韻','晁逈','宋','宋诗','song-poetry','','[]','仙御來相慰，解顔良會稀。',120,'全唐诗/poet.song.2000.json','["仙御來相慰，解顔良會稀。", "病蠲宜養素，趣遠欲忘機。", "懲躁能無漸，延齡或可祈。", "影摇珠箔細，聲泛細箏微。", "委恨餘班扇，流歡入楚衣。", "陶潛知夢穩，韓壽畏香飛。", "氣爽蒼龍闕，凉生白虎闈。", "健資雞距筆，偷撼獸鐶扉。", "松下琴心逸，江東鱠縷肥。", "宿懷真隠處，終約與同歸。"]'),
('929c1bd0-69a6-4981-a7d0-0fa7bc4742aa','燕居','晁逈','宋','宋诗','song-poetry','','[]','鍊礦成金得寶珍，鍊情成性合天真。',32,'全唐诗/poet.song.2000.json','["鍊礦成金得寶珍，鍊情成性合天真。", "相逢此理交談者，千百人中無一人。"]'),
('f77ee169-8f16-4eaf-b807-4ad9ccc96aa3','遊虎丘詩','晁逈','宋','宋诗','song-poetry','','[]','餞別閶門復少留，故人邀我浣離愁。',64,'全唐诗/poet.song.2000.json','["餞別閶門復少留，故人邀我浣離愁。", "旋沽美醖乘漁艇，急棹斜陽到虎丘。", "千古劍池呀怪石，一方金地枕清流。", "歸時眷戀情無限，不得從容秉燭遊。"]'),
('efb6efee-2910-4596-94c6-d6c65e7f4019','假山','晁逈','宋','宋诗','song-poetry','','[]','覆簣由心匠，多奇勢逼真。',48,'全唐诗/poet.song.2000.json','["覆簣由心匠，多奇勢逼真。", "盆池幽閒古，拳石翠峰新。", "雲淡爐煙合，松滋樹影鄰。", "不須同謝傅，對此已精神。"]'),
('d17b6849-a4fd-41d5-a31f-d203ef525d8b','送何水部蒙出牧袁州','晁逈','宋','宋诗','song-poetry','','[]','條教屬惟良，乘秋始辦裝。',48,'全唐诗/poet.song.2000.json','["條教屬惟良，乘秋始辦裝。", "朱轓重按部，白首尚爲郎。", "督課民期富，從儒道益光。", "更資談博物，千載楚萍鄉。"]'),
('c1f9893e-9448-47e1-bfa1-a1108e314b3b','詩一首','晁逈','宋','宋诗','song-poetry','','[]','宜城徵美醖，漢水得佳舫。',24,'全唐诗/poet.song.2000.json','["宜城徵美醖，漢水得佳舫。", "登峴思前哲，遊池醉夕陽。"]'),
('f689dab8-37cb-482e-949b-fb8f3b6f1c8c','句  其一','晁逈','宋','宋诗','song-poetry','','[]','安得大金柅，制彼日月輪。',24,'全唐诗/poet.song.2000.json','["安得大金柅，制彼日月輪。", "免同流水車，今人續古人。"]'),
('dafc5fae-6230-4d29-b65b-f49cd9bf2b8d','句  其二','晁逈','宋','宋诗','song-poetry','','[]','介居僧尚雜，警聽鶴猶聾。',12,'全唐诗/poet.song.2000.json','["介居僧尚雜，警聽鶴猶聾。"]'),
('8a9f5d3c-ead5-409f-8655-cfc1e14f171e','句  其三','晁逈','宋','宋诗','song-poetry','','[]','影外影爲三等妄，夢中夢是兩重虛。',16,'全唐诗/poet.song.2000.json','["影外影爲三等妄，夢中夢是兩重虛。"]'),
('2c961a73-ccec-4ec7-afe2-9867bbb7cd8b','句  其四','晁逈','宋','宋诗','song-poetry','','[]','三臺八座九品官，名目不同而已矣。',16,'全唐诗/poet.song.2000.json','["三臺八座九品官，名目不同而已矣。"]'),
('b6326f62-57da-4206-8b90-a381b50b665b','句  其五','晁逈','宋','宋诗','song-poetry','','[]','破暗用明明是用，非明非暗即惺惺。',16,'全唐诗/poet.song.2000.json','["破暗用明明是用，非明非暗即惺惺。"]'),
('012da753-6312-481d-8b67-185125387261','句  其六','晁逈','宋','宋诗','song-poetry','','[]','葉外應無葉，心中更有心。',12,'全唐诗/poet.song.2000.json','["葉外應無葉，心中更有心。"]'),
('81bf18c6-1e3d-46c9-85be-b268fdbafaf1','句  其七','晁逈','宋','宋诗','song-poetry','','[]','色空辨相何妨道，語默由心不礙禪。',16,'全唐诗/poet.song.2000.json','["色空辨相何妨道，語默由心不礙禪。"]'),
('941d741b-889b-491a-8ce2-bd68f719efc5','句  其八','晁逈','宋','宋诗','song-poetry','','[]','橋過涿水心先喜，路入雄州眼更明。',16,'全唐诗/poet.song.2000.json','["橋過涿水心先喜，路入雄州眼更明。"]'),
('0a7ab17e-314b-4a39-8f24-9701d363764c','句  其九','晁逈','宋','宋诗','song-poetry','','[]','昭然不昧處，靈照在胸中。',12,'全唐诗/poet.song.2000.json','["昭然不昧處，靈照在胸中。"]'),
('c5176acc-e538-4b81-a201-0eabd5a1b8e4','句  其一○','晁逈','宋','宋诗','song-poetry','','[]','浮生七十今踰九，已是超羣越世人。',16,'全唐诗/poet.song.2000.json','["浮生七十今踰九，已是超羣越世人。"]'),
('9681d87f-22ef-4d42-82b2-dfeee040744e','句  其一一','晁逈','宋','宋诗','song-poetry','','[]','妄緣擾擾知縈己。',8,'全唐诗/poet.song.2000.json','["妄緣擾擾知縈己。"]'),
('62eb67bc-8014-4162-8d4f-8a2fa3ce7b00','句  其一二','晁逈','宋','宋诗','song-poetry','','[]','宴居寂寂堪修道。',8,'全唐诗/poet.song.2000.json','["宴居寂寂堪修道。"]'),
('03a844f5-deb0-452d-8b0c-a7e55760c482','句  其一三','晁逈','宋','宋诗','song-poetry','','[]','明心了了思超世。',8,'全唐诗/poet.song.2000.json','["明心了了思超世。"]'),
('ddf29506-55ea-49ca-9196-1ff1c73e815f','句  其一四','晁逈','宋','宋诗','song-poetry','','[]','豈知習靜知常子，塵外天聲滿耳根。',16,'全唐诗/poet.song.2000.json','["豈知習靜知常子，塵外天聲滿耳根。"]'),
('451f7cbb-7808-40dc-91d3-282663b5ef9b','句  其一五','晁逈','宋','宋诗','song-poetry','','[]','耳音清亮好，最愛夢醒時。',12,'全唐诗/poet.song.2000.json','["耳音清亮好，最愛夢醒時。"]'),
('13f44dc2-63b4-4e6b-8b61-b7a86dadeca5','句  其一六','晁逈','宋','宋诗','song-poetry','','[]','文昭豈異天垂象，澤布還同雨灑溟。',16,'全唐诗/poet.song.2000.json','["文昭豈異天垂象，澤布還同雨灑溟。"]'),
('d907dbeb-6afa-460a-8702-ab2d731c51af','句  其一七','晁逈','宋','宋诗','song-poetry','','[]','鳳駕都門曉，凉風苑樹秋。',12,'全唐诗/poet.song.2000.json','["鳳駕都門曉，凉風苑樹秋。"]'),
('470db5f8-5585-4ee6-80b0-ec71ca84fe17','句  其一八','晁逈','宋','宋诗','song-poetry','','[]','南郡正求賢太守，西垣須輟舊詞臣。',16,'全唐诗/poet.song.2000.json','["南郡正求賢太守，西垣須輟舊詞臣。"]'),
('14910f16-5ab7-46c1-9f99-d37b4706286f','句  其一九','晁逈','宋','宋诗','song-poetry','','[]','期月政成當事簡，不妨遊燕楚宮春。',16,'全唐诗/poet.song.2000.json','["期月政成當事簡，不妨遊燕楚宮春。"]'),
('3f3a8a7d-9190-4f4c-8bc6-bb10164849e5','句  其二○','晁逈','宋','宋诗','song-poetry','','[]','羅含舍宇存遺址，熊繹封疆控廣津。',16,'全唐诗/poet.song.2000.json','["羅含舍宇存遺址，熊繹封疆控廣津。"]'),
('a0c5c319-d0c0-49ae-b35b-a9553d23f2e2','句  其二一','晁逈','宋','宋诗','song-poetry','','[]','心如蓮花不著水，身似翔鴻不可籠。',16,'全唐诗/poet.song.2000.json','["心如蓮花不著水，身似翔鴻不可籠。"]'),
('a6d1f34c-986d-4d29-8f30-a65a53be5400','句  其二二','晁逈','宋','宋诗','song-poetry','','[]','清興比方心境妙，月明池浄白蓮開。',16,'全唐诗/poet.song.2000.json','["清興比方心境妙，月明池浄白蓮開。"]'),
('5536e880-dc3f-4b81-ab9c-e2bb946fd531','句  其二三','晁逈','宋','宋诗','song-poetry','','[]','善思委順世間法，於本真心而不動。',16,'全唐诗/poet.song.2000.json','["善思委順世間法，於本真心而不動。"]'),
('b3ac0488-9e16-495f-8428-41b79f9b0439','句  其二四','晁逈','宋','宋诗','song-poetry','','[]','芃芃麥壠驚翬起，灼灼桃園舞蝶來。',16,'全唐诗/poet.song.2000.json','["芃芃麥壠驚翬起，灼灼桃園舞蝶來。"]'),
('98ff2e36-fd85-4bc2-b2d3-8c451f48db85','句  其二五','晁逈','宋','宋诗','song-poetry','','[]','可能宴坐即宴坐，待全靜無全靜時。',16,'全唐诗/poet.song.2000.json','["可能宴坐即宴坐，待全靜無全靜時。"]'),
('a239cd1e-8d9d-451f-b2c7-c426bd9088a7','存目','晁逈','宋','宋诗','song-poetry','','[]','詩題：遊文潞公曲水園首句：夭桃穠李艷芳辰。',21,'全唐诗/poet.song.2000.json','["詩題：遊文潞公曲水園首句：夭桃穠李艷芳辰。"]'),
('d26e918b-938b-45c6-a29e-437191220caf','送王長洲禹偁赴闕','潘閬','宋','宋诗','song-poetry','','[]','蒿蘭不並香，涇渭安同流。',48,'全唐诗/poet.song.2000.json','["蒿蘭不並香，涇渭安同流。", "小人有千險，君子生百憂。", "名重聖主徵，道光史策收。", "一鶚秋空飛，鳥雀徒啾啾。"]'),
('f6212627-1474-459d-bfc6-9b9262012ee0','曉泊嶀浦寄剡縣劉貺員外','潘閬','宋','宋诗','song-poetry','','[]','曉汎剡溪水，晚見剡溪山。',48,'全唐诗/poet.song.2000.json','["曉汎剡溪水，晚見剡溪山。", "徘徊駐行櫂，待月思再還。", "漁唱深潭上，鳥棲高樹間。", "應當金石交，念我無暫閒。"]'),
('04b9c42c-1e24-41de-b4d4-9a328442ac10','送孫學士兩浙轉運使兼簡杭州知府張侍郎  其一','潘閬','宋','宋诗','song-poetry','','[]','吳山挂魂碧，浙江入夢清。',48,'全唐诗/poet.song.2000.json','["吳山挂魂碧，浙江入夢清。", "旦暮東南望，徒使華髮生。", "君今運邦計，不得同舟行。", "即聽江倉豐，竚見汴稟盈。"]'),
('4eeaa8d2-b759-4f9c-84ac-75bb111731f1','送孫學士兩浙轉運使兼簡杭州知府張侍郎  其二','潘閬','宋','宋诗','song-poetry','','[]','曉帆疊疊飛，夜櫓連連鳴。',48,'全唐诗/poet.song.2000.json','["曉帆疊疊飛，夜櫓連連鳴。", "貪吏誡守廉，饑民蘇念生。", "岸花有異態，沙鳥無嬌聲。", "錢塘太守賢，好共致昇平。"]'),
('3229b2e6-e8a0-4c24-8dee-39df864dacef','金山寺留題','潘閬','宋','宋诗','song-poetry','','[]','金山碧崔嵬，我泛扁舟來。',96,'全唐诗/poet.song.2000.json','["金山碧崔嵬，我泛扁舟來。", "虛閣登還下，長廊去得迴。", "梵剎絕頂立，僧房八面開。", "波濤起蛟蜃，洞穴生風雷。", "千載有高松，萬古無纖埃。", "葛衣惹秋雲，草履黏蒼苔。", "孤城寒角動，片帆暮鐘催。", "朗吟成此章，欲返猶徘徊。"]'),
('df935825-5fc2-40ce-8958-79caa968e14c','闕下留別孫丁二學士歸舊山','潘閬','宋','宋诗','song-poetry','','[]','名利路萬轍，我來意如何。',48,'全唐诗/poet.song.2000.json','["名利路萬轍，我來意如何。", "紅塵三尺深，中有是非波。", "波翻幾潛沒，來者猶更過。", "歸去感知淚，永灑青松柯。"]'),
('32149f18-3e76-4bbd-a8d2-9a5c879a736c','贈道士王介','潘閬','宋','宋诗','song-poetry','','[]','頭冠星斗光，七十鬢不蒼。',48,'全唐诗/poet.song.2000.json','["頭冠星斗光，七十鬢不蒼。", "篋有化金方，詩無入俗章。", "舉步雲霞輕，出語芝朮香。", "約我游羅浮，絕頂天風凉。"]'),
('894a95a8-fc1d-4135-bfd2-63e8f78ec883','雪夜有感','潘閬','宋','宋诗','song-poetry','','[]','大雪擁蓬戶，寒夢不成歸。',48,'全唐诗/poet.song.2000.json','["大雪擁蓬戶，寒夢不成歸。", "孤坐北窗風，飄落辭家衣。", "向曉酒力減，背壁燈影微。", "誰知游子心，暗逐長空飛。"]'),
('eba7a326-3c73-43e3-bae5-aeab1be35b2e','贈馮德之道士','潘閬','宋','宋诗','song-poetry','','[]','上清消息久不聞，紫鸞丹鳳應離羣。',96,'全唐诗/poet.song.2000.json','["上清消息久不聞，紫鸞丹鳳應離羣。", "羲和縱轡日又曛，九衢旦暮徒紛紛。", "誰識天書數行字，識者便是真僊子。", "直言鉛汞成還丹，鍊之餌之身不死。", "嵩陽道士早來別，纔承天澤辭玉闕。", "紫章深秘莫漏泄，他年華頂爲君說。"]'),
('ce59462a-1f46-40fe-b505-630c02125ee1','憶賈閬仙','潘閬','宋','宋诗','song-poetry','','[]','風雅道何玄，高吟憶閬仙。',48,'全唐诗/poet.song.2000.json','["風雅道何玄，高吟憶閬仙。", "人雖終百歲，君合壽千年。", "骨已西埋蜀，魂應北入燕。", "不知天地內，誰爲讀遺編。"]'),
('02402db9-a6bc-480d-8b7e-56406a19eb90','與人游會潤州金山寺','潘閬','宋','宋诗','song-poetry','','[]','浮生難會此，此寺絕塵埃。',48,'全唐诗/poet.song.2000.json','["浮生難會此，此寺絕塵埃。", "容易寞言去，等閒爭得來。", "江聲寒若吼，山色翠如堆。", "自是忘機者，憑闌不忍迴。"]'),
('ba65a11f-0115-44f2-9a95-fd16fd3d9073','望湖樓上作','潘閬','宋','宋诗','song-poetry','','[]','望湖樓上立，竟日懶思還。',48,'全唐诗/poet.song.2000.json','["望湖樓上立，竟日懶思還。", "聽水分他浦，看雲過別山。", "孤舟依岸靜，獨鳥向人閒。", "迴首重門閉，蛙鳴夕照間。"]'),
('dfdc0a60-7bd3-4172-8c04-f4c4defb5b7c','寓泊浙江寄漢陽孫邁郎中','潘閬','宋','宋诗','song-poetry','','[]','維揚相別後，十載浙江居。',48,'全唐诗/poet.song.2000.json','["維揚相別後，十載浙江居。", "氣概貧猶在，顛狂老漸疏。", "已憑天柱客，曾寄漢陽書。", "近見人來說，才華患有餘。"]'),
('91e5314b-9617-4495-b2aa-ce34a528ac62','錢塘秋夕旅舍感懷','潘閬','宋','宋诗','song-poetry','','[]','永夜不能寐，閒門懶復開。',48,'全唐诗/poet.song.2000.json','["永夜不能寐，閒門懶復開。", "片心生萬緒，孤枕轉千迴。", "敗葉聲如雨，狂風響似雷。", "更堪江上笛，歷歷有餘零。"]');
